UPDATE public.articulos SET titulo = 'Nudo Ocho Enlazado', contenido = '<p>El nudo ocho enlazado o <a href="https://knots3d.com/knots/es_es/35/nudo-ocho-por-chicote" target="_blank" rel="noreferrer noopener">nudo ocho por chicote</a> se utiliza para <a href="https://nuamana.com/nuanew/etiqueta/nudos-para-unir-cuerdas/" target="_blank" rel="noreferrer noopener">unir dos cuerdas</a> se suele considerar un <a href="https://nuamana.com/nuanew/tecnicas/nudos/" target="_blank" rel="noreferrer noopener">nudo</a> seguro y es una forma sencilla de <a href="https://nuamana.com/nuanew/etiqueta/nudos-para-unir-cuerdas/" target="_blank" rel="noreferrer noopener">unir dos cuerdas</a> de diámetro similar. Por lo general, es fácil de desatar.</p>



<h3 class="wp-block-heading"><strong>Elaboración del Nudo Ocho Enlazado</strong></h3>



<p>Este simple <a href="https://nuamana.com/nuanew/tecnicas/nudos/" target="_blank" rel="noreferrer noopener">nudo</a> (también conocido como "nudo Flemish") se ejecuta realizando un <a href="https://nuamana.com/nuanew/nudo-ocho/" target="_blank" rel="noreferrer noopener">nudo en forma de ocho</a> en el extremo del cabo, y después siguiendo con el otro chicote el camino del primero. Es, a pesar de su simplicidad, una de las uniones más fuertes, trabajando igualmente bien con un cabo grueso que con una cuerda fina.</p>



<div class="wp-block-boldblocks-carousel-item-repeater wp-block-boldblocks-custom-parent is-carousel js-carousel-layout" data-carousel-settings="{&quot;speed&quot;:300,&quot;loop&quot;:true,&quot;rewind&quot;:false,&quot;autoplay&quot;:{&quot;delay&quot;:3000,&quot;pauseOnMouseEnter&quot;:true},&quot;direction&quot;:&quot;horizontal&quot;,&quot;effect&quot;:&quot;slide&quot;,&quot;slidesPerView&quot;:{&quot;auto&quot;:false,&quot;value&quot;:&quot;3&quot;},&quot;breakpoints&quot;:{&quot;576&quot;:{&quot;slidesPerView&quot;:1,&quot;spaceBetween&quot;:0},&quot;768&quot;:{&quot;slidesPerView&quot;:{&quot;auto&quot;:false,&quot;value&quot;:&quot;3&quot;},&quot;spaceBetween&quot;:0}},&quot;pagination&quot;:false,&quot;paginationSettings&quot;:{&quot;enable&quot;:false,&quot;size&quot;:&quot;12px&quot;,&quot;spacing&quot;:&quot;10px&quot;,&quot;color&quot;:&quot;&quot;,&quot;inactiveColor&quot;:&quot;&quot;,&quot;opacity&quot;:0.3,&quot;dynamicBullets&quot;:true,&quot;horizontalGap&quot;:&quot;5px&quot;},&quot;navigation&quot;:false,&quot;navigationSettings&quot;:{&quot;enable&quot;:false,&quot;size&quot;:&quot;44px&quot;,&quot;spacing&quot;:&quot;10px&quot;,&quot;color&quot;:&quot;&quot;},&quot;scrollbar&quot;:false,&quot;scrollbarSettings&quot;:{&quot;enable&quot;:false,&quot;trackSize&quot;:&quot;5px&quot;,&quot;draggable&quot;:true,&quot;hide&quot;:false,&quot;snapOnRelease&quot;:true,&quot;trackColor&quot;:&quot;&quot;,&quot;sliderColor&quot;:&quot;&quot;}}"><div class="carousel__inner">
