UPDATE public.articulos SET titulo = 'El Jardinero', contenido = '<p>La dinámica de el Jardinero sirve para fomentar un entorno de confianza a la vez que se anima a ser asertivo y no tenerle miedo a chocar o hacerse daño si hay alguien que nos guía.</p>







<p>Es una actividad que durará dependiendo de la <a href="https://nuamana.com/nuanew/cantidad-participantes/4-participantes/" target="_blank" rel="noreferrer noopener">cantidad de participantes</a>. Para grupos de 15 personas puede tardarse unos 30 minutos.</p>







<h3 class="wp-block-heading">El Jardinero</h3>







<figure class="wp-block-image alignright is-resized"><img src="https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_ElJardinero2.png" alt="El Jardinero diagrama" class="wp-image-4366" style="width:360px"/></figure>







<p>Para esta dinámica los jugadores se deberán colocar formando dos filas, una frente a otra y separadas a dos metros, representando a los árboles de una avenida.</p>







<p>Uno de los participantes empezará la actividad haciendo de <a href="https://psicologiaymente.com/social/dinamicas-confianza" target="_blank" rel="noreferrer noopener">el jardinero</a>. Se situará al extremo de la avenida con los ojos vendados, tendrá que buscar un objeto que se encuentre al otro lado (Silbato).</p>







<p>Este trayecto debe hacerse sin tocar las dos filas de árboles, los cuales pueden decirle al jardinero, antes de que choque contra ellos, que se está acercando o que se está equivocando de dirección.</p>







<p>De forma sucesiva, los árboles se irán convirtiendo en jardineros y se irá repitiendo la tarea una y otra vez hasta que todos la hayan hecho.</p>







', extracto = 'La dinámica de el Jardinero sirve para fomentar un entorno de confianza a la vez que se anima a ser asertivo y no tenerle miedo a chocar o hacerse daño si hay...', metadata = '{"areas": ["afectividad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior", "Interior"], "cantidad": "04 participantes", "duracion": "20 minutos", "unidades": ["compa¿¿a", "tropa", "avanzada", "clan"], "objetivos": ["Fomentar un entorno de confianza"], "materiales": ["Pa¿olin", "Silbato"], "variaciones": "Puede variar las indicaciones que dan los \"árboles\" para que sean determinados sonidos cuando se están acercando.", "recomendaciones": "Procure que el terreno está nivelado y libre de obst¿culos que impidan un caminar seguro de los \"jardineros\".", "justificacion_areas": "Desarrolla el autoconocimiento, la confianza grupal y la empat¿a en las interacciones del juego. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_ElJardinero.png", "objetivos_educativos": [{"id": "2f8359db-221e-4a64-b2df-2b3e7b74a2db", "area": "Afectividad", "texto": "Escucho las opiniones de las dem¿s personas y si no estoy de acuerdo lo digo con respeto.", "unidad": "Compa¿¿a", "como_se_cumple": "Practicando la empat¿a y la asertividad en las relaciones interpersonales de patrulla en El Jardinero."}, {"id": "3621f4ae-1316-4b3e-8682-3e3c9ad381a7", "area": "Afectividad", "texto": "Mantengo mi opini¿n cuando estoy convencida que es correcta.", "unidad": "Compa¿¿a", "como_se_cumple": "Practicando la empat¿a y la asertividad en las relaciones interpersonales de patrulla en El Jardinero."}, {"id": "a4060c60-7ce9-425b-bf2a-76941a689937", "area": "Afectividad", "texto": "Escucho las opiniones de los dem¿s personas y si no estoy de acuerdo lo digo con respeto.", "unidad": "Tropa", "como_se_cumple": "Practicando la empat¿a y la asertividad en las relaciones interpersonales de patrulla en El Jardinero."}, {"id": "4ade9c82-6b0d-4a44-8bc6-2eb47a011ffb", "area": "Afectividad", "texto": "Digo lo que pienso con respeto hacia los dem¿s personas.", "unidad": "Tropa", "como_se_cumple": "Practicando la empat¿a y la asertividad en las relaciones interpersonales de patrulla en El Jardinero."}, {"id": "6c2b5054-70e8-4529-957f-a8abea073918", "area": "Afectividad", "texto": "Expreso mis opiniones libremente, sin descalificar a los dem¿s.", "unidad": "Avanzada", "como_se_cumple": "Estableciendo relaciones afectivas basadas en el respeto mutuo, el autocontrol y el cuidado del otro en El Jardinero."}, {"id": "d0ba748f-313b-4ffe-b2a3-fb21c1f8943f", "area": "Afectividad", "texto": "Practica una conducta asertiva y una actitud afectuosa hacia las dem¿s personas, sin inhibiciones ni agresividad.", "unidad": "Clan", "como_se_cumple": "Estableciendo relaciones afectivas basadas en el respeto mutuo, el autocontrol y el cuidado del otro en El Jardinero."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compa¿¿a", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante El Jardinero."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que act¿o, aunque no siempre está de acuerdo con ellas.", "unidad": "Compa¿¿a", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante El Jardinero."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante El Jardinero."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que act¿o, aunque no siempre está de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante El Jardinero."}, {"id": "f1496221-0da5-4775-b3ba-29e65603cfee", "area": "Sociabilidad", "texto": "Acepto las normas de los diferentes ambientes en que act¿o, sin renunciar a mi derecho de tratar de cambiarlas cuando no me parecen correctas.", "unidad": "Avanzada", "como_se_cumple": "Velando por la seguridad f¿sica y el cumplimiento estricto del reglamento de competencia en El Jardinero."}, {"id": "b5954f1c-4d0d-4bdb-97d8-821583beb77e", "area": "Sociabilidad", "texto": "Cumple las normas que la sociedad se ha dado, evalu¿ndolas con responsabilidad y sin renunciar a cambiarlas.", "unidad": "Clan", "como_se_cumple": "Velando por la seguridad f¿sica y el cumplimiento estricto del reglamento de competencia en El Jardinero."}]}'::jsonb WHERE id = '5c308bc8-970e-4321-ac02-762b44db8a19';

UPDATE public.articulos SET titulo = 'Carrera de Jarras', contenido = '<p>La carrera de jarras es una actividad con un alto componente físico, enfocada en el desgaste de energías y la cooperación al interior del equipo, que busca el <a href="https://nuamana.com/nuanew/objetivos-actividad/aumentar-el-conocimiento-de-las-limitantes-fisicas/" target="_blank" rel="noreferrer noopener">conocimiento de las limitaciones físicas</a> y el desarrollo del criterio.</p>







<p>La carrera de jarras se desarrolla en equipos de tres participantes, los cuales pueden rotar en caso de existir más participantes en una suerte de relevos al interior de los grupos.</p>







<h3 class="wp-block-heading">¿Cómo se hace la Carrera de Jarras?</h3>







<p>Se separan los participantes en grupos de tres, y se determina el área de juego con un punto de salida y una meta.</p>







<p>Al interior de cada grupo uno de los participantes (el más liviano de los tres) será la "<a href="https://es.wikipedia.org/wiki/Botijo" target="_blank" rel="noreferrer noopener">jarra</a>" se sienta en el suelo con las piernas firmemente cruzadas entre sí y cruza los brazos, los brazos serán las "orejas de la jarra".</p>







<p>Las o los otros dos participantes deberán tomar a la "<a href="https://es.wikipedia.org/wiki/Botijo" target="_blank" rel="noreferrer noopener">jarra</a>" uno de cada brazo y levantarlo para trasladarlo desde el punto de inicio a la meta.</p>







<p>A la señal, los participantes de los lados toman la "jarra", la levantan y corren a la meta, en caso de que bajen el participante pueden volver a levantarlo y continuar hacia la meta.</p>







