UPDATE public.articulos SET titulo = 'Cuerpo a Tierra', contenido = '<p>El cuerpo a tierra es un <a href="https://nuamana.com/nuanew/actividades/juegos/" target="_blank" rel="noreferrer noopener">juego</a> que consta de una carrera en equipo, donde existe un punto en el que participa todo el equipo, es un juego que se utiliza principalmente de desfogue de energías o como complemento para darle dinamismo a otra actividad.</p>



<p>Al menos dos equipos formados en filas o hileras hacia atrás, estos equipos deben tener al menos 4 participantes cada uno.</p>



<h3 class="wp-block-heading">¡Cuerpo a Tierra!</h3>



<p>Se hace una pequeña carrera donde sale el último participante de la fila, para iniciar se hace correr el pañolin del primero de la fila por entremedio de sus piernas hacia quien se encuentre detrás.</p>



<p>Pasa el pañolin por entremedio de sus piernas hacia atrás, al segundo de la fila, el segundo se lo pasa al tercero y así sucesivamente hasta que llega al último de la fila.</p>



<p>Un vez que el último tiene el pañolin grita ¡<a href="http://www.feanor.cl/recursos/actividades-scouts/cuerpo-tierra" target="_blank" rel="noreferrer noopener">cuerpo a tierra</a>!</p>



<p>Al grito de ¡Cuerpo a tierra! todos los que están delante se lanzan al piso con sus brazos juntos a su cuerpo, utilizando el menor espacio posible, pero con el cuerpo estirado en el suelo y el último debe pasar saltando por sobre los cuerpos de sus compañeros.</p>



<p>Hecho esto corre hacia el dirigente o guiadora que se encontrara a una distancia X de las filas, pasa por detrás de la guiadora o dirigente, y regresa a la fila poniéndose delante de la fila, para repetir el proceso y pasar el pañolin por entremedio de sus piernas hacia atrás.</p>



<p>Gana el equipo que primero pasan todos sus participantes o el número de veces que se determine.</p>', extracto = 'El cuerpo a tierra es un  juego  que consta de una carrera en equipo, donde existe un punto en el que participa todo el equipo, es un juego que se utiliza prin...', metadata = '{"areas": ["corporalidad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "06 participantes", "duracion": "15 minutos", "unidades": ["manada", "compa¿¿a", "tropa"], "objetivos": ["Desfogue de Energ¿as", "Trabajo en equipo"], "materiales": ["Pa¿olin"], "variaciones": "Las variaciones se pueden hacer en el momento que la o el participante llega al punto de referencia (guiadora o dirigente) en ese lugar puede responder una pregunta, o hacer borrachitos, sapitos, ranitas, etc. pueden correr en una forma determinada y regresar de otra, etc.", "recomendaciones": "Procure hacer la actividad en un terreno plano, e idealmente suave, haga ¿nfasis en la necesidad de una distancia segura entre una y otro participante que se encuentra en la fila para evitar que se pisen cuando pasen por encima.", "justificacion_areas": "Fomenta la coordinaci¿n f¿sica y la resistencia cardiovascular mediante desaf¿os corporales din¿micos. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_CuerpoATierra.png", "objetivos_educativos": [{"id": "36d989b6-30dd-434a-874a-70a993ed0bec", "area": "Corporalidad", "texto": "Conozco las principales enfermedades que me pueden dar y por qué.", "unidad": "Manada", "como_se_cumple": "Ejercitando la precisi¿n visomotora y el control de su cuerpo en los desaf¿os corporales de Cuerpo a Tierra."}, {"id": "6467298d-fe2b-4920-9b9a-e3524e4b2aef", "area": "Corporalidad", "texto": "S¿ en qué lugar de mi cuerpo est¿n ubicados los ¿rganos m¿s importantes.", "unidad": "Manada", "como_se_cumple": "Ejercitando la precisi¿n visomotora y el control de su cuerpo en los desaf¿os corporales de Cuerpo a Tierra."}, {"id": "705b686a-8374-467a-b871-f6470f0d58ae", "area": "Corporalidad", "texto": "Me doy cuenta de los cambios que se est¿n produciendo en mi cuerpo.", "unidad": "Compa¿¿a", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de Cuerpo a Tierra."}, {"id": "57887da4-c70e-45bc-bdfb-f79db513a89c", "area": "Corporalidad", "texto": "S¿ qué hacer frente a una enfermedad o accidente.", "unidad": "Compa¿¿a", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de Cuerpo a Tierra."}, {"id": "8cae916f-5e67-4697-b3cd-c59b5c7d1439", "area": "Corporalidad", "texto": "Trato de evitar situaciones que puedan da¿ar mi salud y la de mis compa¿eros.", "unidad": "Tropa", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de Cuerpo a Tierra."}, {"id": "68add558-4b03-4105-b00d-e7f2ead6ac23", "area": "Corporalidad", "texto": "S¿ qué hacer frente a una enfermedad o accidente.", "unidad": "Tropa", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de Cuerpo a Tierra."}, {"id": "b69188bf-2391-43c1-a885-abd1b13912be", "area": "Sociabilidad", "texto": "Acepto las reglas que se ponen en mi casa, en la escuela y en la Manada.", "unidad": "Manada", "como_se_cumple": "Respetando rigurosamente las reglas del juego de relevos y las instrucciones de seguridad en Cuerpo a Tierra."}, {"id": "2394dd5b-87b9-4f3d-9cdd-a42649139782", "area": "Sociabilidad", "texto": "Comprendo y respeto las normas que se han puesto en mi casa y en la escuela, aunque no siempre est¿ de acuerdo con ellas", "unidad": "Manada", "como_se_cumple": "Respetando rigurosamente las reglas del juego de relevos y las instrucciones de seguridad en Cuerpo a Tierra."}, {"id": "007e85ea-2b06-4