UPDATE public.articulos SET titulo = '¿Que animal me gustaría ser?', contenido = '<p>¿Qué animal me gustaría ser? Es una <a href="https://nuamana.com/nuanew/actividades/dinamicas/" target="_blank" rel="noreferrer noopener">dinámica</a> en forma de historia que se relata a los participantes y donde tienen que responder a la pregunta ¿Qué animal me gustaría ser? o ante la posibilidad de reencarnar en un animal, ¿Qué animal me gustaría ser?</p>







<h3 class="wp-block-heading">¿Cómo realizar la dinámica, ¿Qué animal me gustaría ser?</h3>







<p>Cada participante debe tener papel y lápiz en sus manos, cada respuesta la deben anotar en su hoja, deben estar sentados en un espacio calmo para esto puede antes haber realizado un <a href="https://www.psyciencia.com/6-ejercicios-de-respiracion-para-relajarse/" target="_blank" rel="noreferrer noopener">ejercicio de respiración</a>.</p>







<p>A los participantes se les puede relatar una historia sobre animales, cualquier historia que involucre de forma breve a muchos animales diferentes de forma de recordarles de antemano una variedad de animales, luego se deben realizan las preguntas:</p>







<ul class="wp-block-list">

<li>¿Que animal me gustaría ser?</li>







<li>¿Por qué?</li>

</ul>







<p>A continuación se le debe quitar el animal que eligieron indicandoles:</p>







<p>y si no pudieran ser ese animal, ¿Qué le gustaría ser y por qué?</p>







<p>y volvemos a repetir el ejercicio, y si no pudieran ser eso, ¿Qué le gustaría ser y por qué?</p>







<p>Posterior a la pregunta, se vuelve a realizar la misma pregunta, pero en esta ocasión, preguntando por el animal que NO les gustaría ser/reencarnar y un motivo de porqué no ser ese animal.</p>







<p>Tal como antes debemos quitar lo que eligieron pero ahora en negativo, y si no pudiera ser ese animal, ¿Qué no le gustaría ser y por qué?</p>







<p>Los jóvenes tendrán que anotar las respuestas y su motivo en una hoja que contenga su nombre. Posterior a aquello, la hoja con la respuesta se les será entregada a quien dirija la actividad.</p>







<p>El objetivo principal de la actividad es poder identificar fortalezas y debilidades en los jóvenes a través un escenario imaginario en donde adoptan características que puedan ser deseadas o despreciadas por los participantes, lo que permite generar un diagnóstico en cuanto a los deseos y preocupaciones que mantengan los jóvenes participantes.</p>







<p>Al mismo tiempo, podemos observar si existen coincidencias en las respuestas, ya se la elección o la defensa de esa elección.</p>







<p>Los resultados pueden ser interpretados por un psicólogo basándose en el <a href="https://www.psi.uba.ar/academica/carrerasdegrado/psicologia/sitios_catedras/obligatorias/042_ttedm2c2/material/fichas/cuestionario_desiderativo_maladesky_veccia.pdf" target="_blank" rel="noreferrer noopener">Test psicológico "Cuestionario Desiderativo"</a>, leer este documento de igual manera puede darle algunas orientaciones sobre lo que se busca.</p>







<div class="wp-block-boldblocks-grid-item-repeater wp-block-boldblocks-custom-parent is-grid">

<div class="wp-block-boldblocks-grid-item wp-block-boldblocks-custom is-grid-item has-parent">



</div>







<div class="wp-block-boldblocks-grid-item wp-block-boldblocks-custom is-grid-item has-parent">



</div>

</div>', extracto = '¿Qué animal me gustaría ser? Es una  dinámica  en forma de historia que se relata a los participantes y donde tienen que responder a la pregunta ¿Qué animal me...', metadata = '{"areas": ["afectividad", "car¿cter"], "lugares": ["Exterior", "Interior"], "cantidad": "individual", "duracion": "20 minutos", "unidades": ["avanzada", "clan"], "objetivos": ["Estimular la creatividad", "Identificar fortalezas y debilidades", "Introspecci¿n"], "materiales": ["L¿piz", "Papel"], "variaciones": "", "recomendaciones": "", "justificacion_areas": "Ayuda a consolidar los valores scouts de honestidad, lealtad y fair play en la competencia. Desarrolla el autoconocimiento, la confianza grupal y la empat¿a en las interacciones del juego.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_QueAnimalMeGustariaSer.png", "objetivos_educativos": [{"id": "6c2b5054-70e8-4529-957f-a8abea073918", "area": "Afectividad", "texto": "Expreso mis opiniones libremente, sin descalificar a los dem¿s.", "unidad": "Avanzada", "como_se_cumple": "Estableciendo relaciones afectivas basadas en el respeto mutuo, el autocontrol y el cuidado del otro en ¿Que animal me gustaría ser?."}, {"id": "d0ba748f-313b-4ffe-b2a3-fb21c1f8943f", "area": "Afectividad", "texto": "Practica una conducta asertiva y una actitud afectuosa hacia las dem¿s personas, sin inhibiciones ni agresividad.", "unidad": "Clan", "como_se_cumple": "Estableciendo relaciones afectivas basadas en el respeto mutuo, el autocontrol y el cuidado del otro en ¿Que animal me gustaría ser?."}, {"id": "1d9d6751-4ab1-45db-9999-3f18606b4909", "area": "Car¿cter", "texto": "Soy fiel a la palabra dada.", "unidad": "Avanzada", "como_se_cumple": "Actuando consecuentemente con sus principios y valores individuales en cada decisi¿n y rol de ¿Que animal me gustaría ser?."}, {"id": "770a8ff3-7bb8-45dd-b114-5ae1069eff62", "area": "Car¿cter", "texto": "Act¿a consecuentemente con los valores que lo inspiran.", "unidad": "Clan", "como_se_cumple": "Actuando consecuentemente con sus principios y valores individuales en cada decisi¿n y rol de ¿Que animal me gustaría ser?."}]}'::jsonb WHERE id = '82610966-74e3-40cc-a789-6ec6b32af1a2';

UPDATE public.articulos SET titulo = 'Carrera de submarinos', contenido = '<p>La carrera de submarinos, es un <a href="https://nuamana.com/nuanew/actividades/juegos" target="_blank" rel="noreferrer noopener">juego</a> que busca que los participantes aprendan a seguir instrucciones, estimular la confianza y reforzar el <a href="https://nuamana.com/nuanew/objetivos-actividad/trabajo-en-equipo/" target="_blank" rel="noreferrer noopener">trabajo en equipo</a>, para poder realizarla se necesitan al menos 8 participantes.</p>







<h2 class="wp-block-heading">¿Cómo se juega la Carrera de Submarinos?</h2>







<p>Para jugar a la <a href="http://juegoscout.blogspot.cl/" target="_blank" rel="noreferrer noopener">carrera de submarinos</a> se debe tener más de un equipo de mínimo 4 participantes cada uno.</p>







<p>Se ubica cada equipo en fila y con los ojos vendados menos el último que será el encargado de guiar al resto mediante pequeños toques en los hombros, espalda y cabeza, pero sin hablar.</p>







<p>Cada participante se afirmará de los hombros del jugador de adelante, el objetivo del juego es ir desde el punto A al punto B antes que el otro equipo.</p>







<h3 class="wp-block-heading">Reglas de la Carrera de Submarinos</h3>







<ul class="wp-block-list">

<li>No hablar.</li>







<li>Tocar el hombro izquierdo significa doblar a la izquierda.</li>







<li>Tocar el hombro derecho significa doblar a la derecha.</li>







<li>Tocar la espalda significa frenar.</li>







<li>Tocar la cabeza significa avanzar derecho.</li>







<li>Deben pasar hacia adelante la misma señal que recibieron de atrás.</li>

</ul>







<p>A la señal salen todos los submarinos de su punto inicial y gana el primer equipo que llega a la meta.</p>







', extracto = 'La carrera de submarinos, es un  juego  que busca que los participantes aprendan a seguir instrucciones, estimular la confianza y reforzar el  trabajo en equip...', metadata = '{"areas": ["corporalidad", "creatividad", "sociabilidad"], "lugares": ["Campo Abierto", "Exterior"], "cantidad": "08 participantes", "duracion": "20 minutos", "unidades": ["manada", "compa¿¿a", "tropa"], "objetivos": ["Aprender a seguir instrucciones", "Estimular la confianza", "Trabajo en equipo"], "materiales": ["Pa¿olin"], "variaciones": "Puede permitir que los submarinos se hundan entre s¿ para evitar que lleguen a sus metas, para destruir a otro submarino puede chocarlo por un costado o hacer que se separen, también puede hacer que el primer jugador de la fila se convierta en un torpedo que se lanza con una señal determinada y si choca al otro submarino lo hunde.\r\n\r\nPuede hacer que la meta no sea un punto fijo para dificultar la llegada y que se mueva cada cierto tiempo, también puede hacer que los puntos de origen y destino de cada submarino sean diferentes y obligue a que se crucen entre equipos en el camino.", "recomendaciones": "Procure usar un terreno homog¿neo y parejo para evitar accidentes por ca¿das.", "justificacion_areas": "Fomenta la coordinaci¿n f¿sica y la resistencia cardiovascular mediante desaf¿os corporales din¿micos. Promueve el ingenio pr¿ctico, la agilidad mental y la resoluci¿n de problemas t¿cnicos o enigmas. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_CarreraDeSubmarinos.png", "objetivos_educativos": [{"id": "36d989b6-30dd-434a-874a-70a993ed0bec", "area": "Corporalidad", "texto": "Conozco las principales enfermedades que me pueden dar y por qué.", "unidad": "Manada", "como_se_cumple": "Ejercitando la precisi¿n visomotora y el control de su cuerpo en los desaf¿os corporales de Carrer