UPDATE public.articulos SET titulo = 'Dos mentiras y una verdad', contenido = '<p>Dos mentiras y una verdad es una <a href="https://nuamana.com/nuanew/actividades/dinamicas/" target="_blank" rel="noreferrer noopener">dinámica</a> que permite a las y los participantes conocerse más en profundidad, No se necesita ningún equipo ni preparación especial, aunque es posible que quieras usar lápiz y papel para llevar la cuenta de las puntuaciones (si juegas como desafío).</p>



<h3 class="wp-block-heading">Cómo jugar a Dos mentiras y una verdad</h3>



<p>Dos mentiras y una verdad se suele jugar con un grupo pequeño de personas, pero también se puede jugar con sólo dos personas o con un grupo gigante de personas.</p>



<p>Para empezar, una persona debe hacer tres declaraciones sobre sí misma al resto del grupo. El truco está en que no todas las afirmaciones serán verdaderas: dos de las afirmaciones dadas deben ser una mentira; y una debe ser una verdad.</p>



<p>Una vez que hayas terminado, todos deben adivinar qué declaración creen que te has inventado. Luego de que todos hayan adivinado, revela qué afirmación era tu verdad.</p>



<h3 class="wp-block-heading">¿Cómo funciona?</h3>



<p>Esta sencilla y clásica <a href="https://klaxoon.com/es/contenido-comunitario/diez-actividades-de-team-building-digital-para-activar-la-eficiencia-de-su-equipo-a-distancia" target="_blank" rel="noreferrer noopener">actividad de creación de equipos</a> funciona bien con equipos pequeños o medianos. Puedes repetirla varias veces con el mismo grupo para que la gente se conozca.</p>



<p>2 pasos:</p>



<ol class="wp-block-list">
<li>Cada persona dispone de un máximo de 3 minutos para pensar en 2 verdades y 1 mentira sobre ella, ya sea profesional o personalmente. Hay que destacar que el objetivo es engañar al grupo, para que el ejercicio sea más divertido. Por ejemplo: Hablo 5 idiomas / Toco la trompeta / Una vez compartí un café con Samuel Etoo.</li>



<li>Por turnos, cada persona declara sus 3 hechos, en el orden que quiera. A continuación, el resto del grupo debe adivinar cuales son dos mentiras y una verdad.</li>
</ol>



<h3 class="wp-block-heading"><strong>Algunas estrategias más generales...</strong></h3>



<ol class="wp-block-list">
<li>Empieza con una simple mentira, luego una afirmación escandalosa, y después una simple mentira para que la segunda afirmación suene a mentira (Ejemplo nº 1).</li>



<li>Elige una mentira que pueda ser cierta.</li>



<li>Por supuesto, mezcla tus estrategias a medida que juegas más rondas, ¡o tus amigos se darán cuenta y empezarán a derrotarte!</li>



<li>No elijas una frase demasiado obvia. Esto hará que el juego sea demasiado fácil de adivinar para tus amigos.</li>



<li>Además, intenta que tus declaraciones no incluyan demasiado vocabulario técnico.</li>
</ol>



<p>Una vez establecida la estrategia, se puede proceder con las ideas de las mentiras</p>



<p>Ref.: <a href="https://klaxoon.com/es/insight/dos-verdades-y-mas-mentiras-ideas-para-jugar-en-equipo" target="_blank" data-type="link" data-id="https://klaxoon.com/es/insight/dos-verdades-y-mas-mentiras-ideas-para-jugar-en-equipo" rel="noreferrer noopener">Klaxoon.com</a></p>', extracto = 'Dos mentiras y una verdad es una  dinámica  que permite a las y los participantes conocerse más en profundidad, No se necesita ningún equipo ni preparación esp...', metadata = '{"areas": ["creatividad", "sociabilidad"], "lugares": ["Exterior", "Interior", "Sala"], "cantidad": "02 participantes", "duracion": "20 minutos", "unidades": ["compa¿¿a", "avanzada", "clan"], "objetivos": ["Estimular la participaci¿n", "Facilitar el conocimiento entre los pares"], "materiales": ["L¿piz", "Papel"], "variaciones": "", "recomendaciones": "", "justificacion_areas": "Promueve el ingenio pr¿ctico, la agilidad mental y la resoluci¿n de problemas t¿cnicos o enigmas. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_DosMentirasYUnaVerdad.png", "objetivos_educativos": [{"id": "e1b7276f-4fd2-4c39-a32a-bd7fadbee702", "area": "Creatividad", "texto": "Doy mi opini¿n sobre las cosas que me pasan.", "unidad": "Compa¿¿a", "como_se_cumple": "Analizando el escenario t¿ctico del juego de forma ¿gil para proponer alternativas mentales en Dos mentiras y una verdad."}, {"id": "9f30f035-9179-4ac4-acfb-bea0e169e97a", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Compa¿¿a", "como_se_cumple": "Analizando el escenario t¿ctico del juego de forma ¿gil para proponer alternativas mentales en Dos mentiras y una verdad."}, {"id": "3cdf4b56-b55f-4878-b3fa-da32a7200ca4", "area": "Creatividad", "texto": "Soy capaz de sintetizar, criticar, proponer y apreciar las opiniones de los dem¿s.", "unidad": "Avanzada", "como_se_cumple": "Demostrando agilidad mental y pensamiento cr¿tico inmediato para liderar la resoluci¿n estrat¿gica de Dos mentiras y una verdad."}, {"id": "ef75fbed-4a6d-49ea-bfab-f2952415e1a0", "area": "Creatividad", "texto": "Act¿a con agilidad mental ante las situaciones m¿s diversas, desarrollando su capacidad de pensar, innovar y aventurar.", "unidad": "Clan", "como_se_cumple": "Demostrando agilidad mental y pensamiento cr¿tico inmediato para liderar la resoluci¿n estrat¿gica de Dos mentiras y una verdad."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compa¿¿a", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante Dos mentiras y una verdad."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que act¿o, aunque no siempre est¿ de acuerdo con ellas.", "unidad": "Compa¿¿a", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante Dos mentiras y una verdad."}, {"id": "f1496221-0da5-4775-b3ba-29e65603cfee", "area": "Sociabilidad", "texto": "Acepto las normas de los diferentes ambientes en que act¿o, sin renunciar a mi derecho de tratar de cambiarlas cuando no me parecen correctas.", "unidad": "Avanzada", "como_se_cumple": "Velando por la seguridad f¿sica y el cumplimiento estricto del reglamento de competencia en Dos mentiras y una verdad."}, {"id": "b5954f1c-4d0d-4bdb-97d8-821583beb77e", "area": "Sociabilidad", "texto": "Cumple las normas que la sociedad se ha dado, evalu¿ndolas con responsabilidad y sin renunciar a cambiarlas.", "unidad": "Clan", "como_se_cumple": "Velando por la seguridad f¿sica y el cumplimiento estricto del reglamento de competencia en Dos mentiras y una verdad."}]}'::jsonb WHERE id = 'b8daf1ee-84cd-46e5-a871-f6371673db05';

UPDATE public.articulos SET titulo = 'Casa Inquilino o Terremoto', contenido = '<p>La actividad casa inquilino o terremoto, es una actividad para romper el hielo, y estimular la capacidad de reacción, al mismo tiempo que permite a niños, niñas y jóvenes sacar la voz y hablar en público sin frases muy complejas, es ideal para desarrollar en unidades menores e intermedias y en grupo más grandes.</p>



<h3 class="wp-block-heading">Casa Inquilino o Terremoto</h3>



<p>Para hacer la <a href="https://nuamana.com/nuanew/actividades/" target="_blank" rel="noreferrer noopener">actividad</a> casa inquilino o terremoto se armarán equipos de a 3, una de ellas será el inquilino y se ubicará al medio, mientras los otros 2 se toman de las manos para formar una casa con su manos en alto, idealmente, por sobre la cabeza del inquilino.</p>



<figure class="wp-block-image aligncenter is-resized"><img src="https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_CasaInquilinoYTerremoto1.png" alt="Casa Inquilino y Terremoto" class="wp-image-4526" style="object-fit:cover;width:360px;height:360px"/></figure>



<p>Además de los equipos de a 3 personas regados por todo el campo de juego entre las casa inquilino o terremoto existe un animador, que debe relatar una historia inventada y dentro de la misma debe decir las palabras claves, <a href="https://dinamicasojuegos.blogspot.com/2010/03/casa-inquilino-y-terremoto.html" target="_blank" rel="noreferrer noopener">Casa Inquilino o Terremoto</a>, cada una de esas palabras genera una acción de los participantes en el juego, el relator también es un participante.</p>



<p>Sin embargo, el relator es un inquilino que no tiene casa, por lo que su objetivo es entrar en una de las casa. su historia es importante para darle dramatismo al juego, la historia puede ser un cuento complejo o una frase sencilla, por ejemplo, "Iba el otro día caminando por mi plaza cuando me encontré con un amigo que es <em><strong>Inquilino</strong></em>" o "Mi mamá el otro día se compro una casona que se había caído en un <em><strong>Terremoto</strong></em>", etc.</p>



<h4 class="wp-block-heading">Acciones para cada palabra clave</h4>



<p><strong><em>Inquilino:</em></strong> Cuando el animador dice la palabra inquilino, las casas alzan sus manos para permitir a los inquilinos que salgan y las casas deben permanecer en el mismo lugar, todos lo inquilinos deben salir y buscar otra casa, ningún inquilino puede quedar en la misma casa que tenía antes.</p>



<p><strong><em>Casa:</em></strong> Cuando el animador dice la palabra casa, los inquilinos se deben quedan en su lugar y son las casas las que se mueven a buscar otro inquilino, ninguna casa debe quedar con el mismo inquilino que tenían antes.</p>



<p><strong><em>Terremoto:</em></strong> al mencionar la palabra terremoto dentro de la historia que relata el animador, todo se desarma y se vuelve a armar, es decir, cada participante puede quedar como casa si antes era inquilino, o como inquilino si antes era parte de una casa, es importante que no quede nadie en el mismo orden anterior para causar un verdadero terremoto.</p>', extracto = 'La actividad casa inquilino o terremoto, es una actividad para romper el hielo, y estimular la capacidad de reacción, al mismo tiempo que permite a niños, niña...', metadata = '{"areas": ["corporalidad", "sociabilidad"], "lugares": ["Campo Abierto", "Exterior"], "cantidad": "06 participantes", "duracion": "20 minutos", "unidades": ["manada", "compa¿¿a", "tropa"], "objetivos": ["Estimular la agilidad", "Estimular la agilidad mental", "Estimular la capacidad de reacci¿n", "Estimular la coordinaci¿n", "Facilitar el contacto inicial"], "materiales": ["Sin Materiales"], "variaciones": "Una versi¿n m¿s sencilla de la actividad es que simplemente haya un animador fijo que siempre va relatando la historia.", "recomendaciones": "Procure y estimule que se los participantes no se queden siempre con el mismo equipo, esta actividad busca que ni¿as, ni¿os y j¿venes se conozcan o se crucen con personas fuera de su ¿rea de confort.", "justificacion_areas": "Fomenta la coordinaci¿n f¿sica y la resistencia cardiovascular mediante desaf¿os corporales din¿micos. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_CasaInquilinoYTerremoto.png", "objetivos_educativos": [{"id": "36d989b6-30dd-434a-874a-70a993ed0bec", "area": "Corporalidad", "texto": "Conozco las principales enfermedades que me pueden dar y por qué.", "unidad": "Manada", "como_se_cumple": "Ejercitando la precisi¿n visomotora y el control de su cuerpo en los desaf¿os corporales de Casa Inquilino o Terremoto."}, {"id": "6467298d-fe2b-4920-9b9a-e3524e4b2aef", "area": "Corporalidad", "texto": "S¿ en qué lugar de mi cuerpo est¿n ubicados los ¿rganos m¿s importantes.", "unidad": "Manada", "como_se_cumple": "Ejercitando la precisi¿n visomotora y el control de su cuerpo en los desaf¿os corporales de Casa Inquilino o Terremoto."}, {"id": "705b686a-8374-467a-b871-f6470f0d58ae", "area": "Corporalidad", "texto": "Me doy cuenta de los cambios que se est¿n produciendo en mi cuerpo.", "unidad": "Compa¿¿a", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de Casa Inquilino o Terremoto."}, {"id": "57887da4-c70e-45bc-bdfb-f79db513a89c", "area": "Corporalidad", "texto": "S¿ qué hacer frente a una enfermedad o accidente.", "unidad": "Compa¿¿a", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de Casa Inquilino o Terremoto."}, {"id": "8cae916f-5e67-4697-b3cd-c59b5c7d1439", "area": "Corporalidad", "texto": "Trato de evitar situaciones que puedan da¿ar mi salud y la de mis compa¿eros.", "unidad": "Tropa", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de Casa Inquilino o Terremoto."}, {"id": "68add558-4b03-4105-b00d-e7f2ead6ac23", "area": "Corporalidad", "texto": "S¿ qué hacer frente a una enfermedad o accidente.", "unidad": "Tropa", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de Casa Inquilino o Terremoto."}, {"id": "b69188bf-2391-43c1-a885-abd1b13912be", "area": "Sociabilidad", "texto": "Acepto las reglas que se ponen en mi casa, en la escuela y en la Manada.", "unidad": "Manada", "como_se_cumple": "Respetando rigurosamente las reglas del juego de relevos y las instrucciones de seguridad en Casa Inquilino o Terremoto."}, {"id": "2394dd5b-87b9-4f3d-9cdd-a42649139782", "area": "Sociabilidad", "texto": "Comprendo y respeto las normas que se han puesto en mi casa y en la escuela, aunque no siempre est¿ de acuerdo con ellas", "unidad": "Manada", "como_se_cumple": "Respetando rigurosamente las reglas del juego de relevos y las instrucciones de seguridad en Casa Inquilino o Terremoto."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compa¿¿a", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante Casa Inquilino o Terremoto."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que act¿o, aunque no siempre est¿ de acuerdo con ellas.", "unidad": "Compa¿¿a", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante Casa Inquilino o Terremoto."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante Casa Inquilino o Terremoto."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que act¿o, aunque no siempre est¿ de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante Casa Inquilino o Terremoto."}]}'::jsonb WHERE id = 'c37832d6-9192-43e2-9886-4a7917e8e710';

UPDATE public.articulos SET titulo = 'Juego del Gato Scout', contenido = '<p>El Juego del Gato Scout, es una representación física del clásico <a href="https://www.google.com/search?q=juego+del+gato&amp;source=lmns&amp;bih=793&amp;biw=1600&amp;rlz=1C1ONGR_esCL1018CL1018&amp;hl=es&amp;sa=X&amp;ved=2ahUKEwiEqrOsu8-BAxUzNbkGHSg1Bh0Q0pQJKAB6BAgBEAI" target="_blank" rel="noreferrer noopener">juego gato o tres en línea</a>, que en este caso se hará con objetos y sobre el suelo en un tablero de tamaño gigante en comparación a cuando se juega con papel y lápiz. Es una actividad para desarrollar el trabajo en equipo, la estrategia y la planificación en un equipo.</p>



<h3 class="wp-block-heading">Juego del Gato Scout</h3>



<p>Para el Juego del Gato Scout se dividirán en 2 equipos de al menos 2 jugadores cada equipo, en un extremo del campo se ubicaran los jugadores y en el otro extremo del campo se ubicará el tablero.</p>



<p>El tablero puede ser dibujado en el suelo, considerando que cada casilla debe tener el tamaño suficiente para que caiga una persona, para dibujar el tablero se puede usar cualquier material, por ejemplo, tela, pañolines, ropa, tiza, ramas, hojas, tierra, etc, lo importante es el tamaño y adecuarnos a las condiciones del lugar.</p>



<p>El tablero del Juego del Gato Scout consta de un cuadro con 3 filas y 3 columnas, teniendo un total de 9 cuadros donde se pueden ubicar personas u objetos, gráficamente el tablero se verá más o menos así...</p>



<figure class="wp-block-image aligncenter is-resized"><img src="https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_JuegoDelGatoScoutTablero.png" alt="" class="wp-image-4526" style="object-fit:cover;width:360px;height:360px"/></figure>



<p>El objetivo del juego del gato Scout es hacer una línea o una diagonal, al igual que en el juego tradicional ganará la partida el equipo que logre hacer primero la diagonal o línea.</p>



<p>Debido a que las casillas son limitadas, los posicionamientos de las piezas también lo son y es probable que se generen empates cuando ninguno de los equipos logra hacer una línea o diagonal, por lo mismo la <a href="https://nuamana.cl/actividades/" target="_blank" data-type="link" data-id="https://nuamana.cl/actividades/" rel="noreferrer noopener">actividad</a> se determina como ganador al equipo que logre hacer primero X cantidad de líneas o diagonales.</p>



<p>Con respecto a las fichas, estas pueden ser algún objeto que sea igual o diferente o incluso pueden ser los mismos jugadores los que queden en el lugar como una ficha del juego.</p>



<p>Una vez ubicados los equipos en el extremo contrario al del tablero, se dará una señal para comenzar, a la señal las primeras o primeros jugadores de cada equipo corren al tablero para ubicar la ficha dentro de él, cuando la ubica puede salir el siguiente y así sucesivamente hasta que hagan una línea, una diagonal o se produzca el empate.</p>', extracto = 'El Juego del Gato Scout, es una representación física del clásico  juego gato o tres en línea , que en este caso se hará con objetos y sobre el suelo en un tab...', metadata = '{"areas": ["corporalidad", "creatividad", "sociabilidad"], "cantidad": "04 participantes", "duracion": "15 minutos", "unidades": ["manada", "compa¿¿a", "tropa", "avanzada", "clan"], "objetivos": ["Estrategia y planificaci¿n", "Trabajo en equipo"], "materiales": ["L¿piz", "Papel", "Pa¿olin", "Silbato"], "variaciones": "Las variaciones pueden ser debido al tipo de fichas que se utilicen, otra variaci¿n puede ser que cada partida que ganen tengan que hacer el sonido de un gato.", "recomendaciones": "Procure poner atenci¿n al momento de las llegadas al tablero para evitar roces por discusiones sobre quien se ubic¿ primero en que lugar.", "justificacion_areas": "Fomenta la coordinaci¿n f¿sica y la resistencia cardiovascular mediante desaf¿os corporales din¿micos. Promueve el ingenio pr¿ctico, la agilidad mental y la resoluci¿n de problemas t¿cnicos o enigmas. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_JuegoDelGatoScout.png", "objetivos_educativos": [{"id": "36d989b6-30dd-434a-874a-70a993ed0bec", "area": "Corporalidad", "texto": "Conozco las principales enfermedades que me pueden dar y por qué.", "unidad": "Manada", "como_se_cumple": "Ejercitando la precisi¿n visomotora y el control de su cuerpo en los desaf¿os corporales de Juego del Gato Scout."}, {"id": "6467298d-fe2b-4920-9b9a-e3524e4b2aef", "area": "Corporalidad", "texto": "S¿ en qué lugar de mi cuerpo est¿n ubicados los ¿rganos m¿s importantes.", "unidad": "Manada", "como_se_cumple": "Ejercitando la precisi¿n visomotora y el control de su cuerpo en los desaf¿os corporales de Juego del Gato Scout."}, {"id": "705b686a-8374-467a-b871-f6470f0d58ae", "area": "Corporalidad", "texto": "Me doy cuenta de los cambios que se est¿n produciendo en mi cuerpo.", "unidad": "Compa¿¿a", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de Juego del Gato Scout."}, {"id": "57887da4-c70e-45bc-bdfb-f79db513a89c", "area": "Corporalidad", "texto": "S¿ qué hacer frente a una enfermedad o accidente.", "unidad": "Compa¿¿a", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de Juego del Gato Scout."}, {"id": "8cae916f-5e67-4697-b3cd-c59b5c7d1439", "area": "Corporalidad", "texto": "Trato de evitar situaciones que puedan da¿ar mi salud y la de mis compa¿eros.", "unidad": "Tropa", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de Juego del Gato Scout."}, {"id": "68add558-4b03-4105-b00d-e7f2ead6ac23", "area": "Corporalidad", "texto": "S¿ qué hacer frente a una enfermedad o accidente.", "unidad": "Tropa", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de Juego del Gato Scout."}, {"id": "05f42879-f5f5-40c4-bed6-c577bf61340a", "area": "Corporalidad", "texto": "Cuido mi salud y mantengo h¿bitos que la protegen.", "unidad": "Avanzada", "como_se_cumple": "Aceptando sus capacidades f¿sicas y perfeccionando el control psicomotor durante el desarrollo de Juego del Gato Scout."}, {"id": "69fff91f-a493-483d-92d6-8319700236c2", "area": "Corporalidad", "texto": "Conoce los procesos biol¿gicos que regulan su organismo, protege su salud, acepta sus posibilidades f¿sicas y orienta sus impulsos y fuerzas.", "unidad": "Clan", "como_se_cumple": "Aceptando sus capacidades f¿sicas y perfeccionando el control psicomotor durante el desarrollo de Juego del Gato Scout."}, {"id": "ec280dd0-2d80-4b84-86ad-2d362da14886", "area": "Creatividad", "texto": "Me gusta participar en juegos de observaci¿n.", "unidad": "Manada", "como_se_cumple": "Proponiendo ideas originales y r¿pidas para resolver los acertijos o enigmas mentales de Juego del Gato Scout."}, {"id": "418f2b77-f15b-405a-95bd-8033c0b6a4c2", "area": "Creatividad", "texto": "Puedo contar con detalles las an¿cdotas y aventuras que hemos tenido en la Manada.", "unidad": "Manada", "como_se_cumple": "Proponiendo ideas originales y r¿pidas para resolver los acertijos o enigmas mentales de Juego del Gato Scout."}, {"id": "e1b7276f-4fd2-4c39-a32a-bd7fadbee702", "area": "Creatividad", "texto": "Doy mi opini¿n sobre las cosas que me pasan.", "unidad": "Compa¿¿a", "como_se_cumple": "Analizando el escenario t¿ctico del juego de forma ¿gil para proponer alternativas mentales en Juego del Gato Scout."}, {"id": "9f30f035-9179-4ac4-acfb-bea0e169e97a", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Compa¿¿a", "como_se_cumple": "Analizando el escenario t¿ctico del juego de forma ¿gil para proponer alternativas mentales en Juego del Gato Scout."}, {"id": "49ae6ac6-be8f-4f2c-8b3e-6711d041181f", "area": "Creatividad", "texto": "Doy mi opini¿n sobre las cosas que me pasan.", "unidad": "Tropa", "como_se_cumple": "Analizando el escenario t¿ctico del juego de forma ¿gil para proponer alternativas mentales en Juego del Gato Scout."}, {"id": "cf530cf9-73a6-4423-a075-79be433fe96c", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Analizando el escenario t¿ctico del juego de forma ¿gil para proponer alternativas mentales en Juego del Gato Scout."}, {"id": "3cdf4b56-b55f-4878-b3fa-da32a7200ca4", "area": "Creatividad", "texto": "Soy capaz de sintetizar, criticar, proponer y apreciar las opiniones de los dem¿s.", "unidad": "Avanzada", "como_se_cumple": "Demostrando agilidad mental y pensamiento cr¿tico inmediato para liderar la resoluci¿n estrat¿gica de Juego del Gato Scout."}, {"id": "ef75fbed-4a6d-49ea-bfab-f2952415e1a0", "area": "Creatividad", "texto": "Act¿a con agilidad mental ante las situaciones m¿s diversas, desarrollando su capacidad de pensar, innovar y aventurar.", "unidad": "Clan", "como_se_cumple": "Demostrando agilidad mental y pensamiento cr¿tico inmediato para liderar la resoluci¿n estrat¿gica de Juego del Gato Scout."}, {"id": "b69188bf-2391-43c1-a885-abd1b13912be", "area": "Sociabilidad", "texto": "Acepto las reglas que se ponen en mi casa, en la escuela y en la Manada.", "unidad": "Manada", "como_se_cumple": "Respetando rigurosamente las reglas del juego de relevos y las instrucciones de seguridad en Juego del Gato Scout."}, {"id": "2394dd5b-87b9-4f3d-9cdd-a42649139782", "area": "Sociabilidad", "texto": "Comprendo y respeto las normas que se han puesto en mi casa y en la escuela, aunque no siempre est¿ de acuerdo con ellas", "unidad": "Manada", "como_se_cumple": "Respetando rigurosamente las reglas del juego de relevos y las instrucciones de seguridad en Juego del Gato Scout."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compa¿¿a", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante Juego del Gato Scout."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que act¿o, aunque no siempre est¿ de acuerdo con ellas.", "unidad": "Compa¿¿a", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante Juego del Gato Scout."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante Juego del Gato Scout."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que act¿o, aunque no siempre est¿ de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante Juego del Gato Scout."}, {"id": "f1496221-0da5-4775-b3ba-29e65603cfee", "area": "Sociabilidad", "texto": "Acepto las normas de los diferentes ambientes en que act¿o, sin renunciar a mi derecho de tratar de cambiarlas cuando no me parecen correctas.", "unidad": "Avanzada", "como_se_cumple": "Velando por la seguridad f¿sica y el cumplimiento estricto del reglamento de competencia en Juego del Gato Scout."}, {"id": "b5954f1c-4d0d-4bdb-97d8-821583beb77e", "area": "Sociabilidad", "texto": "Cumple las normas que la sociedad se ha dado, evalu¿ndolas con responsabilidad y sin renunciar a cambiarlas.", "unidad": "Clan", "como_se_cumple": "Velando por la seguridad f¿sica y el cumplimiento estricto del reglamento de competencia en Juego del Gato Scout."}]}'::jsonb WHERE id = 'cf0fce88-68dd-40ab-9a65-d684c9c28edd';

UPDATE public.articulos SET titulo = 'Carrera del Saber', contenido = '<p>La Carrera del Saber consiste en ir respondiendo preguntas sobre un tema específico. Se necesitan dos equipos o más, el objetivo es que logren reforzar conocimientos y aprender de forma divertida respondiendo preguntas en una carrera de equipo, para esto es necesario primero hacer una <a href="https://es.wikipedia.org/wiki/Narraci%C3%B3n" target="_blank" rel="noreferrer noopener">narración</a> del tema que quiera reforzar.</p>



<h3 class="wp-block-heading">Carrera del Saber</h3>



<p>Completada la narración del tema comienza la Carrera del Saber, se ubicaran los equipos en una línea de inicio, el objetivo de cada equipo es cruzar la línea de meta antes que los equipos rivales, la carrera del saber incia en un <a href="https://nuamana.cl/actividades/juegos/cuerpo-a-tierra/" data-type="post" data-id="1301" target="_blank" rel="noreferrer noopener">Cuerpo a tierra</a><a href="#cuerpotierra" data-type="internal" data-id="#cuerpotierra">*</a> (ver más abajo) con el último de la fila en cada equipo, el participante que sale desde el final de la línea debe correr hasta donde está el dirigente o guiadora y responder la pregunta que le harán, si responde correctamente volverá con su equipo, se colocará al principio de la fila de su equipo y saltaran todos juntos.</p>



<p>Al <em>momento de saltar</em>, todo el equipo se toma de la cintura y a la cuenta de 3 saltan todos juntos, se realiza sólo un salto por respuesta correcta y no pueden avanzar más allá de donde los dejó el salto todos juntos.</p>



<p>Completado el salto en la carrera del saber, nuevamente el último de cada fila grita cuerpo tierra y sale para contestar otra pregunta, en caso de responder incorrectamente la pregunta, el participante sólo debe volver a su equipo, colocarse al principio de la fila y dejar que salga nuevamente el último de su fila, mientras espera su siguiente turno puede también consultar con su equipo la respuesta correcta a la pregunta que falló en responder antes.</p>



<h4 class="wp-block-heading" id="cuerpotierra">Cuerpo a tierra</h4>



<p>Para el desarrollo de esta actividad se formarán dos o más equipos y se alinearán, al silbato el último de la fila gritará cuerpo a tierra y los demás participantes deberán acostarse en el suelo para que el último de la fila pueda pasar dando saltos por los espacios que dejan los otros participantes, deberán correr hasta él lugar en que estarán las animadoras y/o animadores, al llegar deberá responder una pregunta y volver, cuando vuelva se debe ganar al principio de la fila para que se repita el proceso.</p>', extracto = 'La Carrera del Saber consiste en ir respondiendo preguntas sobre un tema específico. Se necesitan dos equipos o más, el objetivo es que logren reforzar conocim...', metadata = '{"areas": ["corporalidad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "06 participantes", "duracion": "20 minutos", "unidades": ["compa¿¿a", "tropa", "avanzada", "clan"], "objetivos": ["Aprendizaje por la acci¿n", "Reforzar el conocimiento"], "materiales": ["Preguntas", "Silbato"], "variaciones": "Puede hacer el juego sin saltos, s¿lo con el cuerpo a tierra correr y responder la pregunta, cambiando de esta manera el formato de quien es el que gana, siendo la medici¿n en este caso por quien respondi¿ m¿s preguntas correctas.", "recomendaciones": "<ul>\r\n \t<li>Al momento de realizar el cuerpo a tierra, tener ¿nfasis en el cuidado del cuerpo de los dem¿s para no pisarlos.</li>\r\n \t<li>Si la o el participante no puede tirarse al suelo, considerar opciones o variaciones para que puede agacharse o moverse de otra manera si a as¿ se requiere.</li>\r\n \t<li>Preguntas e historia estar¿n en archivos de descargas y se llevar¿n impresos para la actividad.</li>\r\n</ul>", "justificacion_areas": "Fomenta la coordinaci¿n f¿sica y la resistencia cardiovascular mediante desaf¿os corporales din¿micos. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_CarreraDelSaber.png", "objetivos_educativos": [{"id": "705b686a-8374-467a-b871-f6470f0d58ae", "area": "Corporalidad", "texto": "Me doy cuenta de los cambios que se est¿n produciendo en mi cuerpo.", "unidad": "Compa¿¿a", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de Carrera del Saber."}, {"id": "57887da4-c70e-45bc-bdfb-f79db513a89c", "area": "Corporalidad", "texto": "S¿ qué hacer frente a una enfermedad o accidente.", "unidad": "Compa¿¿a", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de Carrera del Saber."}, {"id": "8cae916f-5e67-4697-b3cd-c59b5c7d1439", "area": "Corporalidad", "texto": "Trato de evitar situaciones que puedan da¿ar mi salud y la de mis compa¿eros.", "unidad": "Tropa", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de Carrera del Saber."}, {"id": "68add558-4b03-4105-b00d-e7f2ead6ac23", "area": "Corporalidad", "texto": "S¿ qué hacer frente a una enfermedad o accidente.", "unidad": "Tropa", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de Carrera del Saber."}, {"id": "05f42879-f5f5-40c4-bed6-c577bf61340a", "area": "Corporalidad", "texto": "Cuido mi salud y mantengo h¿bitos que la protegen.", "unidad": "Avanzada", "como_se_cumple": "Aceptando sus capacidades f¿sicas y perfeccionando el control psicomotor durante el desarrollo de Carrera del Saber."}, {"id": "69fff91f-a493-483d-92d6-8319700236c2", "area": "Corporalidad", "texto": "Conoce los procesos biol¿gicos que regulan su organismo, protege su salud, acepta sus posibilidades f¿sicas y orienta sus impulsos y fuerzas.", "unidad": "Clan", "como_se_cumple": "Aceptando sus capacidades f¿sicas y perfeccionando el control psicomotor durante el desarrollo de Carrera del Saber."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compa¿¿a", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante Carrera del Saber."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que act¿o, aunque no siempre est¿ de acuerdo con ellas.", "unidad": "Compa¿¿a", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante Carrera del Saber."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante Carrera del Saber."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que act¿o, aunque no siempre est¿ de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante Carrera del Saber."}, {"id": "f1496221-0da5-4775-b3ba-29e65603cfee", "area": "Sociabilidad", "texto": "Acepto las normas de los diferentes ambientes en que act¿o, sin renunciar a mi derecho de tratar de cambiarlas cuando no me parecen correctas.", "unidad": "Avanzada", "como_se_cumple": "Velando por la seguridad f¿sica y el cumplimiento estricto del reglamento de competencia en Carrera del Saber."}, {"id": "b5954f1c-4d0d-4bdb-97d8-821583beb77e", "area": "Sociabilidad", "texto": "Cumple las normas que la sociedad se ha dado, evalu¿ndolas con responsabilidad y sin renunciar a cambiarlas.", "unidad": "Clan", "como_se_cumple": "Velando por la seguridad f¿sica y el cumplimiento estricto del reglamento de competencia en Carrera del Saber."}]}'::jsonb WHERE id = 'ee69fbc0-4bbe-4cbf-8aab-bea1e11b7e15';

UPDATE public.articulos SET titulo = 'La Isla Desierta', contenido = '<p>La dinámica la Isla Desierta está diseñada para la <a href="https://nuamana.cl/objetivos-actividad/construccion-de-equipos/" data-type="objetivos-actividad" data-id="252">construcción de equipos</a> y reforzamiento de los lazos al interior de los mismos, poniendo en términos objetivos las cualidades subjetivas que cada integrante ve en sus pares.</p>



<h3 class="wp-block-heading">¿Cómo se hace la dinámica La Isla Desierta?</h3>



<p>En la isla desierta, dinámica que toma su nombre de sólo una parte de la misma; es necesario aplicar un pequeño cuestionario a los participantes, pidiéndoles que respondan 3 preguntas simples:</p>



<ul style="margin-top:var(--wp--preset--spacing--20);margin-bottom:var(--wp--preset--spacing--20)" class="wp-block-list is-style-default">
<li>Suponiendo que estás perdido en una isla desierta, ¿con qué compañero te gustaría estar?</li>



<li>Suponiendo que ganaste un viaje con derecho a 3 compañeros, ¿a quién del grupo elegirías?</li>



<li>Suponiendo que necesitas organizar un evento, ¿con qué colega elegirías compartir esta tarea?</li>
</ul>



<p>Es importante guiar a las y los participantes para que las respuestas no contengan sólo los nombres de los colegas, sino también una justificación. Cada persona llenará su tarjeta sin identificarse.</p>



<p>Una vez completado, es necesario colocar los cuestionarios en un sobre. El coordinador de la dinámica pedirá que todos se sienten en un círculo y presenten sus justificaciones para las elecciones, sin mencionar los nombres de los colegas elegidos.</p>



<p>Las palabras clave presentadas en estas justificaciones se anotarán en una tabla y se convertirán en valores importantes de compañerismo, siendo las características necesarias para desarrollar y mejorar con el trabajo en equipo.</p>



', extracto = 'La dinámica la Isla Desierta está diseñada para la  construcción de equipos  y reforzamiento de los lazos al interior de los mismos, poniendo en términos objet...', metadata = '{"areas": ["afectividad", "creatividad", "sociabilidad"], "lugares": ["Exterior", "Interior"], "cantidad": "04 participantes", "duracion": "20 minutos", "unidades": ["avanzada", "clan"], "objetivos": ["Construcci¿n de Equipos", "Estimular la confianza", "Fomentar un entorno de confianza", "Trabajo en equipo"], "materiales": ["L¿piz", "Papel"], "variaciones": "", "recomendaciones": "", "justificacion_areas": "Promueve el ingenio pr¿ctico, la agilidad mental y la resoluci¿n de problemas t¿cnicos o enigmas. Desarrolla el autoconocimiento, la confianza grupal y la empat¿a en las interacciones del juego. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_LaIslaDesierta.png", "objetivos_educativos": [{"id": "81298790-d245-48c6-8b1b-266b218c69da", "area": "Afectividad", "texto": "Me esfuerzo por encontrar mi identidad personal.", "unidad": "Avanzada", "como_se_cumple": "Demostrando madurez emocional y templanza al desenvolverse en los escenarios oscuros o tensos de La Isla Desierta."}, {"id": "07d61bf7-36fc-40f6-8f8e-21fe97b169f0", "area": "Afectividad", "texto": "Logra y mantiene un estado interior de libertad, equilibrio y madurez emocional.", "unidad": "Clan", "como_se_cumple": "Demostrando madurez emocional y templanza al desenvolverse en los escenarios oscuros o tensos de La Isla Desierta."}, {"id": "3cdf4b56-b55f-4878-b3fa-da32a7200ca4", "area": "Creatividad", "texto": "Soy capaz de sintetizar, criticar, proponer y apreciar las opiniones de los dem¿s.", "unidad": "Avanzada", "como_se_cumple": "Demostrando agilidad mental y pensamiento cr¿tico inmediato para liderar la resoluci¿n estrat¿gica de La Isla Desierta."}, {"id": "ef75fbed-4a6d-49ea-bfab-f2952415e1a0", "area": "Creatividad", "texto": "Act¿a con agilidad mental ante las situaciones m¿s diversas, desarrollando su capacidad de pensar, innovar y aventurar.", "unidad": "Clan", "como_se_cumple": "Demostrando agilidad mental y pensamiento cr¿tico inmediato para liderar la resoluci¿n estrat¿gica de La Isla Desierta."}, {"id": "f1496221-0da5-4775-b3ba-29e65603cfee", "area": "Sociabilidad", "texto": "Acepto las normas de los diferentes ambientes en que act¿o, sin renunciar a mi derecho de tratar de cambiarlas cuando no me parecen correctas.", "unidad": "Avanzada", "como_se_cumple": "Velando por la seguridad f¿sica y el cumplimiento estricto del reglamento de competencia en La Isla Desierta."}, {"id": "b5954f1c-4d0d-4bdb-97d8-821583beb77e", "area": "Sociabilidad", "texto": "Cumple las normas que la sociedad se ha dado, evalu¿ndolas con responsabilidad y sin renunciar a cambiarlas.", "unidad": "Clan", "como_se_cumple": "Velando por la seguridad f¿sica y el cumplimiento estricto del reglamento de competencia en La Isla Desierta."}]}'::jsonb WHERE id = '4ac6da05-a5c8-43a7-921b-e2af3a956aa9';

UPDATE public.articulos SET titulo = 'Relevos de Botones', contenido = '<p>Los <a href="http://juegoscout.blogspot.com/" target="_blank" rel="noreferrer noopener">relevos de botones</a> es una actividad que pone énfasis en la motricidad fina y la atención al detalle en una competencia, para poder hacerla se necesitan al menos <a href="https://nuamana.com/nuanew/cantidad-participantes/4-participantes/" target="_blank" rel="noreferrer noopener">4 participantes</a>.</p>







<h3 class="wp-block-heading">¿Cómo se hace el Relevos de Botones?</h3>







<p>Para hacer la actividad Relevos de botones se debe colocar en un extremo del campo un plato con tantos botones como participantes hay en el equipo, en el otro extremo se ubican a los equipos y a cada equipo se le entrega un tramo de hilo o lana.</p>







<p>A la señal sale un concursante de cada equipo con el hilo en la mano, al llegar al plato pasa el hilo por el o los orificios de cualquiera de los botones.</p>







<p>Luego, con el hilo y el botón en su mano, vuelve al punto de partida, en donde entregará el hilo con el botón al siguiente de su equipo, que sale para agregar otro botón al hilo, y así sucesivamente.</p>







<p>Si a alguno de los participantes se le cae el botón, deberá buscarlo e introducirlo de nuevo en el hilo. Gana el equipo que primero introduce los botones en el hilo y regresa.</p>







', extracto = 'Los  relevos de botones  es una actividad que pone énfasis en la motricidad fina y la atención al detalle en una competencia, para poder hacerla se necesitan a...', metadata = '{"areas": ["corporalidad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "04 participantes", "duracion": "15 minutos", "unidades": ["manada", "compa¿¿a", "tropa"], "objetivos": ["Desarrollar la motricidad", "Estimular la atención a los detalles", "Trabajo en equipo"], "materiales": ["Botones", "Hilos", "Plato"], "variaciones": "Puede modificar la cantidad de botones que debe pasar por el hilo cada participante o la situaci¿n en la que se deben pasar el hilo con los botones enhebrados puede ser en movimiento para aumentar la dificultad.", "recomendaciones": "Procure destacar la necesidad de poner atención en el proceso de pasar el hilo por el botón y en el traspaso del hilo al siguiente jugador del equipo.", "justificacion_areas": "Fomenta la coordinaci¿n f¿sica y la resistencia cardiovascular mediante desaf¿os corporales din¿micos. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_RelevosDeBotones.png", "objetivos_educativos": [{"id": "36d989b6-30dd-434a-874a-70a993ed0bec", "area": "Corporalidad", "texto": "Conozco las principales enfermedades que me pueden dar y por qué.", "unidad": "Manada", "como_se_cumple": "Ejercitando la precisi¿n visomotora y el control de su cuerpo en los desaf¿os corporales de Relevos de Botones."}, {"id": "6467298d-fe2b-4920-9b9a-e3524e4b2aef", "area": "Corporalidad", "texto": "S¿ en qué lugar de mi cuerpo est¿n ubicados los ¿rganos m¿s importantes.", "unidad": "Manada", "como_se_cumple": "Ejercitando la precisi¿n visomotora y el control de su cuerpo en los desaf¿os corporales de Relevos de Botones."}, {"id": "705b686a-8374-467a-b871-f6470f0d58ae", "area": "Corporalidad", "texto": "Me doy cuenta de los cambios que se est¿n produciendo en mi cuerpo.", "unidad": "Compa¿¿a", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de Relevos de Botones."}, {"id": "57887da4-c70e-45bc-bdfb-f79db513a89c", "area": "Corporalidad", "texto": "S¿ qué hacer frente a una enfermedad o accidente.", "unidad": "Compa¿¿a", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de Relevos de Botones."}, {"id": "8cae916f-5e67-4697-b3cd-c59b5c7d1439", "area": "Corporalidad", "texto": "Trato de evitar situaciones que puedan da¿ar mi salud y la de mis compa¿eros.", "unidad": "Tropa", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de Relevos de Botones."}, {"id": "68add558-4b03-4105-b00d-e7f2ead6ac23", "area": "Corporalidad", "texto": "S¿ qué hacer frente a una enfermedad o accidente.", "unidad": "Tropa", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de Relevos de Botones."}, {"id": "b69188bf-2391-43c1-a885-abd1b13912be", "area": "Sociabilidad", "texto": "Acepto las reglas que se ponen en mi casa, en la escuela y en la Manada.", "unidad": "Manada", "como_se_cumple": "Respetando rigurosamente las reglas del juego de relevos y las instrucciones de seguridad en Relevos de Botones."}, {"id": "2394dd5b-87b9-4f3d-9cdd-a42649139782", "area": "Sociabilidad", "texto": "Comprendo y respeto las normas que se han puesto en mi casa y en la escuela, aunque no siempre est¿ de acuerdo con ellas", "unidad": "Manada", "como_se_cumple": "Respetando rigurosamente las reglas del juego de relevos y las instrucciones de seguridad en Relevos de Botones."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compa¿¿a", "como_se_cump