UPDATE public.articulos SET titulo = 'Carrera de Velas', contenido = '<p>La <a href="http://juegoscout.blogspot.com/" target="_blank" rel="noreferrer noopener">carrera de velas</a> es una actividad enfocada en estimular la creatividad y la atención a los detalles, puede ser realizada en grupos pequeños de personas.</p>







<p>Para realizar la carrera de velas deben ser considerados los riesgos asociados al uso de fuego en su planificación de actividad, y requiere el uso de velas y fuego y la atención de todos con respecto a lo que caiga de la vela.</p>







<h3 class="wp-block-heading">¿Cómo se hace la Carrera de Velas?</h3>







<p>Se dividen en dos o más <a href="https://nuamana.com/nuanew/?s=equipo" target="_blank" rel="noreferrer noopener">equipos</a> a los participantes, cada componente del equipo deberá ir con la vela encendida a un punto designado y volver para darle la vela al siguiente sin que se apague.</p>







<h4 class="wp-block-heading">Reglas de la actividad</h4>







<ul class="wp-block-list">

<li>Si se apaga se deberá volver al punto de inicio para encenderla.</li>







<li>Gana el equipo que primero hace pasar a todos sus integrantes por la carrera.</li>

</ul>







', extracto = 'La  carrera de velas  es una actividad enfocada en estimular la creatividad y la atención a los detalles, puede ser realizada en grupos pequeños de personas....', metadata = '{"areas": ["creatividad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "02 participantes", "duracion": "20 minutos", "unidades": ["compa¿¿a", "tropa", "avanzada", "clan"], "objetivos": ["Estimular la atención a los detalles", "Estimular la creatividad", "Estimular la observaci¿n"], "materiales": ["Fuego", "Velas"], "variaciones": "Puede hacer una sola carrera de ida y vuelta con todos los participantes al mismo tiempo, donde gana el primer equipo que hace cruzar a todos sus miembros por la l¿nea de meta o permitir que se intenten apagar la vela a los otros en el camino.", "recomendaciones": "Haga ¿nfasis en la creatividad para cuidar el fuego de la vela pero sin dejar de lado la seguridad que se debe tener cuando se manipulan cosas con fuego.", "justificacion_areas": "Promueve el ingenio pr¿ctico, la agilidad mental y la resoluci¿n de problemas t¿cnicos o enigmas. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_CarreraDeVelas.png", "objetivos_educativos": [{"id": "e1b7276f-4fd2-4c39-a32a-bd7fadbee702", "area": "Creatividad", "texto": "Doy mi opini¿n sobre las cosas que me pasan.", "unidad": "Compa¿¿a", "como_se_cumple": "Analizando el escenario t¿ctico del juego de forma ¿gil para proponer alternativas mentales en Carrera de Velas."}, {"id": "9f30f035-9179-4ac4-acfb-bea0e169e97a", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Compa¿¿a", "como_se_cumple": "Analizando el escenario t¿ctico del juego de forma ¿gil para proponer alternativas mentales en Carrera de Velas."}, {"id": "49ae6ac6-be8f-4f2c-8b3e-6711d041181f", "area": "Creatividad", "texto": "