UPDATE public.articulos SET titulo = 'Conejos y Guaridas', contenido = '<p>El juego Conejos y Guaridas es una actividad enfocada en el <a href="https://nuamana.com/nuanew/objetivos-actividad/desfogue-de-energias/" target="_blank" rel="noreferrer noopener">desfogue de energías</a> y la colaboración entre pares, para llevar a cabo se designarán dos tipos de participantes en una pareja, unos serán conejos y guaridas los otros, mientras que los <a href="https://www.mestizos.cl/actualidad-animal/2023/10/03/conejos-7-cosas-que-debes-saber-sobre-ellos.html" target="_blank" rel="noreferrer noopener">conejos</a> corren, los guaridas se quedaran en el lugar para marcar la posición de ingreso.</p>



<h3 class="wp-block-heading">¿Como jugar Conejos y Guaridas?</h3>



<p>Para jugar Conejos y Guaridas se reúne a los participantes en un área abierta o sala lo suficientemente espaciosa para correr y jugar sin obstáculos. Luego se forma un círculo (deben estar de pie) de modo que los jugadores estén uno al lado del otro. Cada jugador estará emparejado con el jugador adyacente para formar una dupla y se le asigna aleatoriamente a cada pareja un rol de "conejo" y "guarida". Seguidamente se indica a los "conejos" que deben posicionarse detrás de sus "guaridas". Y por último se coloca un pañolín o un objeto que simule ser una “zanahoria” en el centro del círculo.</p>



<p>Previamente se les explica a los participantes que cuando el encargado/coordinador de la actividad menciona la palabra –<strong>CONEJOS– </strong> los jugadores designados como "conejo" deberán correr alrededor del círculo, mientras que los jugadores designados como "guarida" permanecerán en su lugar con las piernas abiertas para que su pareja pueda pasar por debajo y logre capturar la "zanahoria" del centro antes que el resto de los otros conejos.</p>



<p>Después de cada ronda, las parejas pueden intercambiar los roles y llevar un registro de las cantidades de veces que logran capturar el pañolín/objeto. Al final del juego, la dupla que haya capturado más “zanahorias” será declarada ganadora.</p>', extracto = 'El juego Conejos y Guaridas es una actividad enfocada en el  desfogue de energías  y la colaboración entre pares, para llevar a cabo se designarán dos tipos de...', metadata = '{"areas": ["corporalidad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "04 participantes", "duracion": "15 minutos", "unidades": ["compa¿¿a", "tropa", "avanzada"], "objetivos": ["Desarrollar la motricidad", "Desfogue de Energ¿as", "Refuerzo de habilidades f¿sicas", "Trabajo en equipo"], "materiales": ["Pa¿olin"], "variaciones": "Esta actividad también se puede realizar reemplazando las \"Guaridas\" por alg¿n objeto que quede como marcador de posici¿n.", "recomendaciones": "Procure hacer ¿nfasis en el cuidado de los dem¿s al momento de correr y pasar por debajo para tomar la \"Zanahoria\", evite las situaciones de riesgo poniendo cuidado en el terreno que se realiza la actividad.", "justificacion_areas": "Fomenta la coordinaci¿n f¿sica y la resistencia cardiovascular mediante desaf¿os corporales din¿micos. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_ConejosYGuaridas.png", "objetivos_educativos": [{"id": "705b686a-8374-467a-b871-f6470f0d58ae", "area": "Corporalidad", "texto": "Me doy cuenta de los cambios que se est¿n produciendo en mi cuerpo.", "unidad": "Compa¿¿a", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de Conejos y Guaridas."}, {"id": "57887da4-c70e-45bc-bdfb-f79db513a89c", "area": "Corporalidad", "texto": "S¿ qué hacer frente a una enfermedad o accidente.", "unidad": "Compa¿¿a", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de Conejos y Guaridas."}, {"id": "8cae916f-5e67-4697-b3cd-c59b5c7d1439", "area": "Corporalidad", "texto": "Trato de evitar situaciones que puedan da¿ar mi salud y la de mis compa¿eros.", "unidad": "Tropa", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de Conejos y Guaridas."}, {"id": "68add558-4b03-4105-b00d-e7f2ead6ac23", "area": "Corporalidad", "texto": "S¿ qué hacer frente a una enfermedad o accidente.", "unidad": "Tropa", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de Conejos y Guaridas."}, {"id": "05f42879-f5f5-40c4-bed6-c577bf61340a", "area": "Corporalidad", "texto": "Cuido mi salud y mantengo h¿bitos que la protegen.", "unidad": "Avanzada", "como_se_cumple": "Aceptando sus capacidades f¿sicas y perfeccionando el control psicomotor durante el desarrollo de Conejos y Guaridas."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compa¿¿a", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante Conejos y Guaridas."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que act¿o, aunque no siempre est¿ de acuerdo con ellas.", "unidad": "Compa¿¿a", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante Conejos y Guaridas."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante Conejos y Guaridas."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que act¿o, aunque no siempre est¿ de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante Conejos y Guaridas."}, {"id": "f1496221-0da5-4775-b3ba-29e65603cfee", "area": "Sociabilidad", "texto": "Acepto las normas de los diferentes ambientes en que act¿o, sin renunciar a mi derecho de tratar de cambiarlas cuando no me parecen correctas.", "unidad": "Avanzada", "como_se_cumple": "Velando por la seguridad f¿sica y el cumplimiento estricto del reglamento de competencia en Conejos y Guaridas."}]}'::jsonb WHERE id = '7bc4e56d-8f9d-4dc7-8e2e-3eeeabb80124';

UPDATE public.articulos SET titulo = 'Juego democrático: Los Inversionistas', contenido = '<p>El juego democrático: Los inversionistas , es una actividad participativa que tiene por fin la elección de otras actividades, las que serán realizadas durante el ciclo de programa.</p>



<p>Los <a href="https://nuamana.com/nuanew/actividades/juegos-democraticos/" target="_blank" rel="noopener">juegos democráticos</a>, como Los inversionistas, son simulaciones en que los jóvenes representan un determinado papel y, actuando de acuerdo a las reglas del ambiente simulado, tratan de obtener el apoyo de la Unidad para su propuesta.</p>



<h3 class="wp-block-heading">¿Cómo se juega a Los Inversionistas?</h3>



<p>En el caso del juego democrático: Los Inversionistas los jóvenes toman el rol de “los inversionistas” y tienen la oportunidad de utilizar su "dinero" como votos para apoyar las actividades, juegos y proyectos que más les gusten.</p>



<p>El objetivo de este juego es fomentar la participación activa de los jóvenes en la toma de decisiones y promover el sentido de responsabilidad y compromiso con las actividades de la unidad.</p>



<p>Se despliega una lista de propuestas de actividades y juegos (previamente sugeridas por los propios jóvenes) en un lugar visible para ser revisadas.</p>



<p>A cada participante se le asigna una cantidad X de "dinero" ficticio que representará sus votos, todos tendrán la misma cantidad de "dinero" y se les explica que este "dinero" puede ser utilizado para invertir en las actividades que prefieren realizar durante el ciclo que viene.</p>



<figure class="wp-block-image aligncenter is-resized"><img src="https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_JuegoDemocraticoLosInversionistas_billete1.png" alt="Los Inversionistas Billete Ejemplo 1" class="wp-image-4754" style="width:540px"/></figure>



<figure class="wp-block-image aligncenter is-resized"><img src="https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_JuegoDemocraticoLosInversionistas_billete2.png" alt="Los Inversionistas Billete Ejemplo 2" class="wp-image-4755" style="width:540px"/></figure>



<figure class="wp-block-image aligncenter is-resized"><img src="https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_JuegoDemocraticoLosInversionistas_billete3.png" alt="Los Inversionistas Billete Ejemplo 3" class="wp-image-4756" style="width:540px"/></figure>



<figure class="wp-block-image aligncenter is-resized"><img src="https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_JuegoDemocraticoLosInversionistas_billete4.png" alt="Los Inversionistas Billete Ejemplo 4" class="wp-image-4757" style="width:540px"/></figure>



<p>Aquí algunos <a href="https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_JuegoDemocraticoLosInversionistas_DineroFalso.pdf" target="_blank" rel="noopener">ejemplos de Dineros</a>... Se fundamentan las reglas sobre cómo se realizará la inversión. Por ejemplo, se puede permitir a los participantes invertir su dinero en una sola actividad o distribuirlo entre varias propuestas. También se puede establecer un límite de inversión para evitar que un solo miembro domine el proceso de votación.</p>



<p>Una vez que todos los miembros de la unidad han invertido su dinero, se procede a contar los votos, la actividad con más dinero tendrá prioridad. Y por último se determina cuáles son las actividades y juegos más populares en función de la cantidad de dinero invertido en cada propuesta.</p>



<p>Este juego promueve la toma de decisiones colaborativa y la planificación de actividades. Además, les brinda la oportunidad de aprender sobre el valor del voto, el poder de la elección y el respeto por las preferencias individuales y colectivas.</p>



<p>En las <a href="#descargas">descargas</a> tenemos un archivo de sugerencia con un formato para imprimir el dinero falso.</p>', extracto = 'El juego democrático: Los inversionistas , es una actividad participativa que tiene por fin la elección de otras actividades, las que serán realizadas durante...', metadata = '{"areas": ["car¿cter", "sociabilidad"], "lugares": ["Exterior", "Interior"], "cantidad": "02 participantes", "duracion": "30 minutos", "unidades": ["manada", "compa¿¿a", "tropa", "avanzada", "clan"], "objetivos": ["Aprendizaje por la acci¿n", "Estimular la participaci¿n", "Reforzar el valor de la democracia", "Toma de Decisiones"], "materiales": ["Dinero Falso", "Listado de Actividades", "Papel", "Plum¿n"], "variaciones": "<ul>\r\n \t<li>Se puede permitir a los participantes invertir su dinero en una sola actividad o distribuirlo entre varias propuestas.</li>\r\n \t<li>Tambi¿n se puede establecer un l¿mite de inversi¿n para evitar que un solo miembro domine el proceso de votaci¿n.</li>\r\n \t<li>Otra variaci¿n es realizar una actividad previa donde puedan ganar y perder dinero mediante un juego simple para a¿adir una dificultad econ¿mica, aunque esto no es recomendable al hacerlo como un juego democr¿tico.</li>\r\n</ul>", "recomendaciones": "Se claro al momento de establecer las reglas de la din¿mica de esta manera se evitan conflictos en los equipos.", "justificacion_areas": "Ayuda a consolidar los valores scouts de honestidad, lealtad y fair play en la competencia. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_JuegoDemocraticoLosInversionistas.png", "objetivos_educativos": [{"id": "baa365a9-087c-4c25-b0ad-57893df5ff74", "area": "Car¿cter", "texto": "S¿ lo que significa decir la verdad.", "unidad": "Manada", "como_se_cumple": "Jugando de manera transparente y honesta en Juego democr¿tico: Los