UPDATE public.articulos SET titulo = 'Carrera de Elefantes', contenido = '<p>La carrera de elefantes es una actividad que busca estimular el <a href="https://nuamana.cl/objetivos-actividad/trabajo-en-equipo/" target="_blank" rel="noreferrer noopener" id="https://nuamana.cl/objetivos-actividad/trabajo-en-equipo/">trabajo en equipo</a>, necesita al menos 2 equipos de 3 integrantes cada uno para poder llevarse a cabo. Se llama carrera de elefantes porque simula el cómo se toman los elefantes de sus colas con las trompas al caminar en manada.</p><h2>¿Cómo se juega a la Carrera de elefantes?</h2><p>Para jugar a la <a href="http://juegoscout.blogspot.com/" target="_blank" rel="noreferrer noopener">carrera de elefantes</a> se debe tener más de un equipo de mínimo 3 participantes cada uno, se coloca cada equipo en fila uno detrás de otro.</p><p>El primero pasa una mano entre sus piernas para tomar una mano de su compañero o compañera de atrás. El segundo, de igual modo, pasa su mano por entre sus piernas, para tomar la mano de la compañera o compañero de atrás, y así sucesivamente hasta el último o última de la fila.</p><p>Cuando están todas y todos colocados en esta posición, se colocan detrás de la línea de partida y a la señal comienza la carrera. Gana el primer equipo que cruza completo la línea de meta.</p><h3>Reglas de la Carrera de Elefantes</h3><ul><li>No se deben soltar.</li><li>Si el equipo se suelta se debe rearmar antes de continuar.</li><li>Gana el primer equipo que cruza la meta.</li></ul><div></div>', extracto = 'La carrera de elefantes es una actividad que busca estimular el  trabajo en equipo , necesita al menos 2 equipos de 3 integrantes cada uno para poder llevarse...', metadata = '{"areas": ["corporalidad", "sociabilidad"], "lugares": ["Campo Abierto", "Exterior"], "cantidad": "06 participantes", "duracion": "15 minutos", "unidades": ["manada", "compa¿¿a", "tropa"], "objetivos": ["Aumentar el conocimiento de las limitantes f¿sicas", "Trabajo en equipo"], "materiales": ["Sin Materiales"], "variaciones": "Una variaci¿n puede ser que si un equipo se llega a desarmar debe volver al punto de partida.", "recomendaciones": "Puede indicar que los elefantes emiten sonido y por lo mismo cada equipo debe hacer sonidos de elefantes mientras avanza.", "justificacion_areas": "Fomenta la coordinaci¿n f¿sica y la resistencia cardiovascular mediante desaf¿os corporales din¿micos. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_CarreraDeElefantes.png", "objetivos_educativos": [{"id": "36d989b6-30dd-434a-874a-70a993ed0bec", "area": "Corporalidad", "texto": "Conozco las principales enfermedades que me pueden dar y por qué.", "unidad": "Manada", "como_se_cumple": "Ejercitando la precisi¿n visomotora y el control de su cuerpo en los desaf¿os corporales de Carrera de Elefantes."}, {"id": "6467298d-fe2b-4920-9b9a-e3524e4b2aef", "area": "Corporalidad", "texto": "S¿ en qué lugar de mi cuerpo están ubicados los ¿rganos más importantes.", "unidad": "Manada", "como_se_cumple": "Ejercitando la precisi¿n visomotora y el control de su cuerpo en los desaf¿os corporales de Carrera de Elefantes."}, {"id": "705b686a-8374-467a-b871-f6470f0d58ae", "area": "Corporalidad", "texto": "Me doy cuenta de los cambios que se están produciendo en mi cuerpo.", "unidad": "Compa¿¿a", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de Carrera de Elefantes."}, {"id": "57887da4-c70e-45bc-bdfb-f79db513a89c", "area": "Corporalidad", "texto": "S¿ qué hacer frente a una enfermedad o accidente.", "unidad": "Compa¿¿a", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de Carrera de Elefantes."}, {"id": "8cae916f-5e67-4697-b3cd-c59b5c7d1439", "area": "Corporalidad", "texto": "Trato de evitar situaciones que puedan da¿ar mi salud y la de mis compañeros.", "unidad": "Tropa", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de Carrera de Elefantes."}, {"id": "68add558-4b03-4105-b00d-e7f2ead6ac23", "area": "Corporalidad", "texto": "S¿ qué hacer frente a una enfermedad o accidente.", "unidad": "Tropa", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de Carrera de Elefantes."}, {"id": "b69188bf-2391-43c1-a885-abd1b13912be", "area": "Sociabilidad", "texto": "Acepto las reglas que se ponen en mi casa, en la escuela y en la Manada.", "unidad": "Manada", "como_se_cumple": "Respetando rigurosamente las reglas del juego de relevos y las instrucciones de seguridad en Carrera de Elefantes."}, {"id": "2394dd5b-87b9-4f3d-9cdd-a42649139782", "area": "Sociabilidad", "texto": "Comprendo y respeto las normas que se han puesto en mi casa y en la escuela, aunque no siempre est¿ de acuerdo con ellas", "unidad": "Manada", "como_se_cumple": "Respetando rigurosamente las reglas del juego de relevos y las instrucciones de seguridad en Carrera de Elefantes."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compa¿¿a", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante Carrera de Elefantes."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que act¿o, aunque no siempre est¿ de acuerdo con ellas.", "unidad": "Compa¿¿a", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante Carrera de Elefantes."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante Carrera de Elefantes."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que act¿o, aunque no siempre est¿ de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante Carrera de Elefantes."}]}'::jsonb WHERE id = '844d5d4b-743e-4ebc-a734-5e7210a3be75';

UPDATE public.articulos SET titulo = 'Carrera de Cuncunas', contenido = '<p>La <a href="http://juegoscout.blogspot.com/" target="_blank" rel="noreferrer noopener">carrera de cuncunas</a> es una competencia que requiere trabajo en equipo y estrategia es un poco dura pero sólo el hecho de intentarlo merece la pena, otra ventaja es que no requiere de materiales.</p>







<h3 class="wp-block-heading">¿Cómo se hace la Carrera de Cuncunas?</h3>







<p>Se hacen grupos de alrededor de <a href="https://nuamana.com/nuanew/cantidad-participantes/8-participantes/" target="_blank" rel="noreferrer noopener">4 a 8 personas</a> formando una fila sentados, el segundo de la fila debe abrazar con sus piernas al primero, tercero al segundo y así sucesivamente.</p>







<p>Apoyados sólo con sus glúteos y sus manos o brazos deben hacer avanzar la fila hacia la línea de meta. En caso de que se suelten, se desarmen o caigan de lado deben reposicionarse para continuar avanzando.</p>







<p>Gana el primer equipo que cruza completo la línea de meta.</p>







