UPDATE public.articulos SET titulo = 'Ley con clave morse', contenido = '<p>La ley con clave morse es una actividad enfocada en reforzar el <a href="https://www.questionpro.com/blog/es/trabajar-en-equipo/" target="_blank" rel="noreferrer noopener">trabajo en equipo</a> y el aprendizaje de la criptografía, al mismo tiempo que refuerza la confianza en los pares, para poder hacer la actividad son necesarios al menos 2 equipos con un mínimo de 2 personas cada uno.</p>







<h3 class="wp-block-heading">Ley con clave morse</h3>







<p>La primera parte es crear los equipos, estos equipos se colocaran en un extremo del campo de juego, mientras que en el otro extremo del campo se colocarán papeles con escritos en <a href="https://nuamana.cl/tecnicas/claves-y-pistas/codigo-morse/" data-type="post" data-id="1316">clave morse</a>, estos papeles tendrán articulos de la <a href="https://nuamana.com/nuanew/lo-que-hacemos/ley-y-promesa/">ley guía y scout</a> escritos en <a href="https://nuamana.cl/tecnicas/claves-y-pistas/codigo-morse/" data-type="post" data-id="1316">clave morse</a>.</p>







<p>El o la participante, antes de salir a buscar un papel escrito en código morse, deberá vendar sus ojos mientras que sus compañeros y/o compañeras de equipo le gritarán las instrucciones para llegar al papel u objeto que debe tomar.</p>







<p>Una vez que toma el objeto se puede quitar la venda de los ojos y regresar al lugar con el resto de su equipo, a su llegada saldrá la o el siguiente participante del equipo, y así sucesivamente hasta recuperar todos los papeles.</p>







<p>Cuando tengan todos los mensajes en poder del equipo tienen que empezar a traducir lo más rápidamente posible los mensajes donde descubrirán los artículos de la <a href="https://nuamana.com/nuanew/lo-que-hacemos/ley-y-promesa/">ley guía-scout</a> que estará escrita la ley con clave morse.</p>







<p>Si necesitas ayuda para escribir las pistas más abajo en las descargas de este artículo puedes descargar una fuente (font, letras) que convierte lo que escribas en un computador a código morse, y aquí te dejamos una actividad para que puedas hacer con tu unidad.</p>







<figure class="wp-block-image aligncenter"><img src="https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Articulo_CodigoMorse1.jpg" alt="Regla mnemot¿cnica morse"/></figure>







</div>', extracto = 'La ley con clave morse es una actividad enfocada en reforzar el  trabajo en equipo  y el aprendizaje de la criptografía, al mismo tiempo que refuerza la confia...', metadata = '{"areas": ["afectividad", "creatividad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "04 participantes", "duracion": "25 minutos", "unidades": ["compa¿¿a", "tropa"], "descargas": [{"url": "https://dl.dafont.com/dl/?f=morse", "nombre": "Fuente Morse (Dafont)"}], "objetivos": ["Aprender criptografía", "Aprendizaje por la acci¿n", "Estimular el pensamiento l¿gico", "Trabajo en equipo"], "materiales": ["L¿piz", "Papel", "Pa¿olin"], "variaciones": "En lugar de vendarse los ojos los participantes y ser guiados a viva voz hasta los mensajes, también se puede reemplazar esto por un <a href=\"https://nuamana.cl/actividades/juegos/cuerpo-a-tierra/\" target=\"_blank\" rel=\"noopener\">cuerpo a tierra</a>, u otra carrera que los lleve desde un extremo al otro del campo.\r\n\r\nDe la misma manera se puede reemplazar el código morse por otra clave, para aumentar o disminuir la dificultad.", "recomendaciones": "Procure hacer la actividad en un lugar plano y despejados, sin riesgos de ca¿das por tropiezos o golpes en la cabeza por algo en altura.", "justificacion_areas": "Promueve el ingenio pr¿ctico, la agilidad mental y la resoluci¿n de problemas t¿cnicos o enigmas. Desarrolla el autoconocimiento, la confianza grupal y la empat¿a en las interacciones del juego. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_LeyConClaveMorse.png", "objetivos_educativos": [{"id": "2f8359db-221e-4a64-b2df-2b3e7b74a2db", "area": "Afectividad", "texto": "Escucho las opiniones de las demás personas y si no estoy de acuerdo lo digo con respeto.", "unidad": "Compa¿¿a", "como_se_cumple": "Practicando la empat¿a y la asertividad en las relaciones interpersonales de patrulla en Ley con clave morse."}, {"id": "3621f4ae-1316-4b3e-8682-3e3c9ad381a7", "area": "Afectividad", "texto": "Mantengo mi opini¿n cuando estoy convencida que es correcta.", "unidad": "Compa¿¿a", "como_se_cumple": "Practicando la empat¿a y la asertividad en las relaciones interpersonales de patrulla en Ley con clave morse."}, {"id": "a4060c60-7ce9-425b-bf2a-76941a689937", "area": "Afectividad", "texto": "Escucho las opiniones de los demás personas y si no estoy de acuerdo lo digo con respeto.", "unidad": "Tropa", "como_se_cumple": "Practicando la empat¿a y la asertividad en las relaciones interpersonales de patrulla en Ley con clave morse."}, {"id": "4ade9c82-6b0d-4a44-8bc6-2eb47a011ffb", "area": "Afectividad", "texto": "Digo lo que pienso con respeto hacia los demás personas.", "unidad": "Tropa", "como_se_cumple": "Practicando la empat¿a y la asertividad en las relaciones interpersonales de patrulla en Ley con clave morse."}, {"id": "e1b7276f-4fd2-4c39-a32a-bd7fadbee702", "area": "Creatividad", "texto": "Doy mi opini¿n sobre las cosas que me pasan.", "unidad": "Compa¿¿a", "como_se_cumple": "Analizando el escenario t¿ctico del juego de forma ¿gil para proponer alternativas mentales en Ley con clave morse."}, {"id": "9f30f035-9179-4ac4-acfb-bea0e169e97a", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Compa¿¿a", "como_se_cumple": "Analizando el escenario t¿ctico del juego de forma ¿gil para proponer alternativas mentales en Ley con clave morse."}, {"id": "49ae6ac6-be8f-4f2c-8b3e-6711d041181f", "area": "Creatividad", "texto": "Doy mi opini¿n sobre las cosas que me pasan.", "unidad": "Tropa", "como_se_cumple": "Analizando el escenario t¿ctico del juego de forma ¿gil para proponer alternativas mentales en Ley con clave morse."}, {"id": "cf530cf9-73a6-4423-a075-79be433fe96c", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Analizando el escenario t¿ctico del juego de forma ¿gil para proponer alternativas mentales en Ley con clave morse."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compa¿¿a", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante Ley con clave morse."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que act¿o, aunque no siempre est¿ de acuerdo con ellas.", "unidad": "Compa¿¿a", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante Ley con clave morse."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante Ley con clave morse."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que act¿o, aunque no siempre est¿ de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante Ley con clave morse."}]}'::jsonb WHERE id = 'd87c3dc3-20b6-4400-9a8f-4dc1c9ee42cc';

UPDATE public.articulos SET titulo = 'Una torre alta firme y hermosa', contenido = '<p>La actividad <a href="https://odresnuevos.files.wordpress.com/2008/05/juegos-para-scouts.pdf" target="_blank" rel="noreferrer noopener">una torre alta firme y hermosa</a> es una dinámica que sirve de <a href="https://nuamana.com/nuanew/objetivos-actividad/trabajo-en-equipo/" target="_blank" rel="noreferrer noopener">integración para equipos</a> recién formados.</p>







<p>Se entregarán materiales por equipo, un pegamento, diarios o periódicos, palos de maqueta u otro similar, y papel para adornar por cada equipo.</p>







<h3 class="wp-block-heading">¿Cómo hacer una torre alta firme y hermosa?</h3>







<p>El responsable de la actividad pide a cada equipo que construya "una torre alta, firme y hermosa". No especifica nada más y se le entregan los materiales a cada equipo.</p>







<p>Después de ¿30 minutos se juntan los equipos y por votación se elige la que mejor cumple con las características solicitadas. Después el responsable de la actividad pide a los participantes que piensen que su equipo se construye igual que la torre que han presentado.</p>







', extracto = 'La actividad  una torre alta firme y hermosa  es una dinámica que sirve de  integración para equipos  recién formados. 



 Se entregarán materiales por equipo...', metadata = '{"areas": ["creatividad", "sociabilidad"], "lugares": ["Exterior", "Interior"], "cantidad": "04 participantes", "duracion": "35 minutos", "unidades": ["compa¿¿a", "tropa", "avanzada", "clan"], "objetivos": ["Aprendizaje por la acci¿n", "Desarrollar la motricidad", "Estimular la creatividad", "Favorecer la comunicaci¿n en el grupo", "Trabajo en equipo"], "materiales": ["Diarios o Peri¿dicos", "Objetos Varios", "Palos de Maqueta", "Papel", "Pegamento"], "variaciones": "Puede variar los materiales entregados para la construcci¿n de la torre, por ejemplo, se pueden utilizar también espaguettis, cart¿n, etc.", "recomendaciones": "Procure hacer ¿nfasis en la evaluaci¿n posterior a la construcci¿n de la torre, de forma de realzar que las características individuales ayudan a mejorar el todo del equipo.", "justificacion_areas": "Promueve el ingenio pr¿ctico, la agilidad mental y la resoluci¿n de problemas t¿cnicos o enigmas. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_UnaTorreAltaFirmeYHermosa.png", "objetivos_educativos": [{"id": "e1b7276f-4fd2-4c39-a32a-bd7fadbee702", "area": "Creatividad", "texto": "Doy mi opini¿n sobre las cosas que me pasan.", "unidad": "Compa¿¿a", "como_se_cumple": "Analizando el escenario t¿ctico del juego de forma ¿gil para proponer alternativas mentales en Una torre alta firme y hermosa."}, {"id": "9f30f035-9179-4ac4-acfb-bea0e169e97a", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Compa¿¿a", "como_se_cumple": "Analizando el escenario t¿ctico del juego de forma ¿gil para proponer alternativas mentales en Una torre alta firme y hermosa."}, {"id": "49ae6ac6-be8f-4f2c-8b3e-6711d041181f", "area": "Creatividad", "texto": "Doy mi opini¿n sobre las cosas que me pasan.", "unidad": "Tropa", "como_