UPDATE public.articulos SET titulo = 'Relevos del Jinete', contenido = '<p>Relevos del jinete es un juego enfocado al desfogue de energías, el <a href="https://nuamana.com/nuanew/objetivos-actividad/refuerzo-de-habilidades-fisicas/" target="_blank" rel="noreferrer noopener">refuerzo de habilidades físicas</a> y el conocimiento de las limitantes físicas personales.</p>



<h3 class="wp-block-heading">¿Cómo se juegan los Relevos del jinete?</h3>



<p>Se divide cada equipo en dos grupos, los grupos de cada equipo se ubicaran en lugares opuestos del campo de juego.</p>



<p>A la señal el primer participante del equipo se convierte en el "caballo" mientras que el o la participante que está detrás sera el "jinete".</p>



<p>El "jinete" se sube sobre la espalda del "caballo" y salen en dirección a donde se ubica el otro grupo de su equipo.</p>



<p>Al llegar el "caballo" se ubica al final de fila del segundo grupo, y el que era "jinete" se convierte ahora en "caballo" del primer participante del segundo grupo en su equipo.</p>



<p>Los nuevos "caballo" y "jinete" salen en dirección ahora del primer grupo y repiten el cambio cuando llegan al otro lado, así sucesivamente hasta que todos pasan como jinete y caballos.</p>



<p>En otras palabras....</p>



<ol class="wp-block-list">
<li>Se dividen los equipos en dos grupos.</li>



<li>De un lado sale una pareja, uno haciendo de caballo y el otro de jinete.</li>



<li>Al llegar al otro lado el jinete hace el <a href="http://juegoscout.blogspot.cl/" target="_blank" rel="noreferrer noopener">Relevos del jinete</a> y se convierte en caballo y trae a uno de los que están esperando.</li>



<li>Al llegar al lado contrario de nuevo el jinete se convierte en caballo y así sucesivamente...</li>
</ol>', extracto = 'Relevos del jinete es un juego enfocado al desfogue de energías, el  refuerzo de habilidades físicas  y el conocimiento de las limitantes físicas personales....', metadata = '{"areas": ["corporalidad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "06 participantes", "duracion": "15 minutos", "unidades": ["avanzada", "clan", "compa¿¿a", "tropa"], "objetivos": ["Aumentar el conocimiento de las limitantes f¿sicas", "Desfogue de Energ¿as", "Refuerzo de habilidades f¿sicas"], "materiales": ["Sin Materiales"], "variaciones": "Puede variar el juego manteniendo al equipo en unido, en este caso \"jinete\" y \"caballo\" llegar¿an hasta el extremo del campo y volver¿an, para hacer el relevo con la o el compa¿ero que sigue.", "recomendaciones": "Procure que haya un equilibrio de fuerzas f¿sicas entre los equipos y tenga criterio en los Relevos bas¿ndose en el peso de cada participante, evite accidentes por sobreesfuerzo f¿sico.", "justificacion_areas": "Fomenta la coordinaci¿n f¿sica y la resistencia cardiovascular mediante desaf¿os corporales din¿micos. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_RelevosDelJinete.png", "objetivos_educativos": [{"id": "7200435f-b020-46fc-b323-8249048b1d18", "area": "Corporalidad", "texto": "Participo en la organizaci¿n de juegos y actividades recreativas para los dem¿s.", "unidad": "Avanzada", "como_se_cumple": "Desplegando su m¿ximo rendimiento aer¿bico, agilidad y coordinaci¿n t¿ctica en la carrera de Relevos del Jinete."}, {"id": "106e27af-ec7a-45fa-9295-fcef88fbef3d", "area": "Corporalidad", "texto": "Convive constantemente en la naturaleza y participa en actividades deportivas y recreativas.", "unidad": "Clan", "como_se_cumple": "Desplegando su m¿ximo rendimiento aer¿bico, agilidad y coordinaci¿n t¿ctica en la carrera de Relevos del Jinete."}, {"id": "d5b111f1-5f6f-4716-8a02-e1826d653c59", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Compa¿¿a", "como_se_cumple": "Corriendo velozmente y dosificando su energ¿a y esfuerzo aer¿bico para superar las fases f¿sicas de Relevos del Jinete."}, {"id": "b12da732-d736-480c-82b8-95b312316390", "area": "Corporalidad", "texto": "Me esfuerzo por mejorar mi rendimiento en el deporte que practico y s¿ ganar y perder.", "unidad": "Compa¿¿a", "como_se_cumple": "Corriendo velozmente y dosificando su energ¿a y esfuerzo aer¿bico para superar las fases f¿sicas de Relevos del Jinete."}, {"id": "58b4936a-816e-4d17-8d0a-c92d0606009d", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Corriendo velozmente y dosificando su energ¿a y esfuerzo aer¿bico para superar las fases f¿sicas de Relevos del Jinete."}, {"id": "6768d60a-187e-4bbf-97b9-cdc25a316030", "area": "Corporalidad", "texto": "Ayudo a preparar los juegos, excursiones y campamentos de mi patrulla y mi Tropa.", "unidad": "Tropa", "como_se_cumple": "Corriendo velozmente y dosificando su energ¿a y esfuerzo aer¿bico para superar las fases f¿sicas de Relevos del Jinete."}, {"id": "f1496221-0da5-4775-b3ba-29e65603cfee", "area": "Sociabilidad", "texto": "Acepto las normas de los diferentes ambientes en que act¿o, sin renunciar a mi derecho de tratar de cambiarlas cuando no me parecen correctas.", "unidad": "Avanzada", "como_se_cumple": "Velando por la seguridad f¿sica y el cumplimiento estricto del reglamento de competencia en Relevos del Jinete."}, {"id": "b5954f1c-4d0d-4bdb-97d8-821583beb77e", "area": "Sociabilidad", "texto": "Cumple las normas que la sociedad se ha dado, evalu¿ndolas con responsabilidad y sin renunciar a cambiarlas.", "unidad": "Clan", "como_se_cumple": "Velando por la seguridad f¿sica y el cumplimiento estricto del regla