UPDATE public.articulos SET titulo = 'Carrera de Globos', contenido = '<p>La carrera de globos es una actividad que busca que los participantes reconozcan sus limitaciones físicas, estimulen su coordinación corporal y la <a href="https://nuamana.com/nuanew/objetivos-actividad/desarrollar-la-motricidad/" target="_blank" rel="noreferrer noopener">motricidad</a>, además de fomentar la sana competencia entre pares.</p>







<p>Se puede realizar en equipos o <a href="https://nuamana.com/nuanew/cantidad-participantes/individual/" target="_blank" rel="noreferrer noopener">individualmente</a>, si se realiza como una competencia entre equipos el primer paso es dividir a los participantes en equipos.</p>







<h3 class="wp-block-heading">¿Cómo se realiza la Carrera de Globos?</h3>







<p>Se determina el área de competencia estableciendo un punto de partida y una meta, la distancia de la meta dependerá de la edad de los participantes, para niñas y niños más pequeños la distancia será poca y aumentará en la medida que aumente la edad de los participantes.</p>







<p>La Carrera de Globos es una actividad que pondrá a prueba la capacidad pulmonar de los participantes, por lo que si hay participantes que tengan algún problema con sus pulmones debe ser puesto en consideración.</p>







<p>Una vez divididos los equipos, se ubica a los participantes en el punto de inicio, a la señal, los participantes colocarán los <a href="https://es.wikipedia.org/wiki/Globo_(juguete)" target="_blank" rel="noreferrer noopener">globos</a> en el aire y lo soplaran haciéndolo llegar a la meta sin tocarlos con ninguna parte del cuerpo o que los globos caigan al suelo.</p>







<p>Si alguien toca al globo con cualquier parte del cuerpo o lo deja caer al suelo debe volver al punto de partida y comenzar de nuevo.</p>







', extracto = 'La carrera de globos es una actividad que busca que los participantes reconozcan sus limitaciones físicas, estimulen su coordinación corporal y la  motricidad...', metadata = '{"areas": ["corporalidad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior", "Interior"], "cantidad": "individual", "duracion": "15 minutos", "unidades": ["manada"], "objetivos": ["Aumentar el conocimiento de las limitantes físicas", "Conocer las capacidades corporales", "Desarrollar la motricidad", "Fomentar la sana competencia"], "materiales": ["Globos"], "variaciones": "Tambi¿n se puede realizar usando papeles y sostenerlos en el aire con el soplido.", "recomendaciones": "Procure que el trayecto que deben recorrer los participantes no tenga obst¿culos de ning¿n tipo para evitar accidentes.", "justificacion_areas": "Fomenta la coordinación f¿sica y la resistencia cardiovascular mediante desaf¿os corporales din¿micos. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_CarreraDeGlobos.png", "objetivos_educativos": [{"id": "4bf1e3dd-7f21-4c24-962d-9d6d64e32f25", "area": "Corporalidad", "texto": "Me gusta hacer actividades al aire libre.", "unidad": "Manada", "como_se_cumple": "Corriendo a paso r¿pido y coordinando sus movimientos con sus compa¿eros durante la din¿mica de Carrera de Globos."}, {"id": "5d2d48ed-c461-4a8e-9048-cceecd3de2e2", "area": "Corporalidad", "texto": "Me gusta jugar con otros niños y niñas y respeto las reglas de los juegos.", "unidad": "Manada", "como_se_cumple": "Corriendo a paso r¿pido y coordinando sus movimientos con sus compa¿eros durante la din¿mica de Carrera de Globos."}, {"id": "b69188bf-2391-43c1-a885-abd1b13912be", "area": "Sociabilidad", "texto": "Acepto las reglas que se ponen en mi casa, en la escuela y en la Manada.", "unidad": "Manada", "como_se_cumple": "Respetando rigurosamente las reglas del juego de relevos y las instrucciones de seguridad en Carrera de Globos."}, {"id": "2394dd5b-87b9-4f3d-9cdd-a42649139782", "area": "Sociabilidad", "texto": "Comprendo y respeto las normas que se han puesto en mi casa y en la escuela, aunque no siempre est¿ de acuerdo con ellas", "unidad": "Manada", "como_se_cumple": "Respetando rigurosamente las reglas del juego de relevos y las instrucciones de seguridad en Carrera de Globos."}]}'::jsonb WHERE id = '67f165b7-09dc-4d94-b862-5afcbc31f742';

UPDATE public.articulos SET titulo = 'Carrera con Vaso de Agua', contenido = '<p>La carrera con vaso de agua es una actividad ideal para los días de más calor, es una actividad que busca estimular la motricidad fina y el cuidado en los detalles, al mismo tiempo que ayuda a con una sana competencia que demuestra que la velocidad no siempre es lo más importante en un juego.</p>



<p>La carrera con vaso de agua se puede realizar en equipos con relevos o de forma <a href="https://nuamana.com/nuanew/cantidad-participantes/individual/" target="_blank" rel="noreferrer noopener">individual</a> todos al mismo tiempo.</p>



<p>Se necesita un área de juego delimitada con un punto de partida y una meta, la distancia entre ambos debe ser relativamente corta, además de <a href="https://es.wikipedia.org/wiki/Vaso_desechable" target="_blank" rel="noreferrer noopener">vasos plásticos</a> y agua.</p>



<h3 class="wp-block-heading">¿Cómo se realiza la carrera con vaso de agua?</h3>



<p>Se divide a los participantes en equipos en caso de ser necesario, a la señal salen los participantes desde el punto de partida con el vaso de agua sobre sus cabezas.</p>



<p>Cada participante o cada equipo tendrá un vaso con agua, el nivel del agua en el vaso también significará una variación en la dificultad, mientras más agua más difícil será tener el equilibrio del vaso.</p>



<p>Hay que ir avanzando manteniendo la cabeza en perfecto equilibrio para que el vaso de agua no se caiga encima. No se pueden utilizar las manos y si el vaso se cae el participante debe volver al punto de inicio y llenar el vaso de agua nuevamente.</p>', extracto = 'La carrera con vaso de agua es una actividad ideal para los días de más calor, es una actividad que busca estimular la motricidad fina y el cuidado en los deta...', metadata = '{"areas": ["corporalidad", "creatividad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "individual", "duracion": "15 minutos", "unidades": ["avanzada", "compa¿¿a", "manada", "tropa"], "objetivos": ["Aumentar el conocimiento de las limitantes f¿sicas", "Conocer las capacidades corporales", "Crear un ambiente de distensi¿n", "Desarrollar la motricidad", "Estimular la creatividad"], "materiales": ["Agua", "Vasos pl¿sticos o de papel"], "variaciones": "Una variaci¿n puede ser obligar a mantener las manos en una parte determinada.", "recomendaciones": "Procure un ¿rea de juego que sea despejada y plana para evitar accidentes. Al mismo tiempo considere que haya buen clima para hacer la actividad.", "justificacion_areas": "Fomenta la coordinaci¿n f¿sica y la resistencia cardiovascular mediante desaf¿os corporales din¿micos. Promueve el ingenio pr¿ctico, la agilidad mental y la resoluci¿n de problemas t¿cnicos o enigmas. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_carreraConVasoDeAgua.png", "objetivos_educativos": [{"id": "7200435f-b020-46fc-b323-8249048b1d18", "area": "Corporalidad", "texto": "Participo en la organizaci¿n de juegos y actividades recreativas para los dem¿s.", "unidad": "Avanzada", "como_se_cumple": "Desplegando su m¿ximo rendimiento aer¿bico, agilidad y coordinaci¿n t¿ctica en la carrera de Carrera con Vaso de Agua."}, {"id": "d5