UPDATE public.articulos SET titulo = 'Carrera de Objetos', contenido = '<p>La carrera de objetos es una <a href="https://nuamana.com/nuanew/actividades/" target="_blank" rel="noreferrer noopener">actividad</a> que busca estimular la capacidad de observación y la atención a los detalles, se divide a los participantes en equipos.</p>



<h3 class="wp-block-heading">¿Cómo se juega la Carrera de Objetos?</h3>



<p>Para hacer la Carrera de Objetos, en una esquina de la pista se colocan diversos objetos encima de una <a href="https://es.wikipedia.org/wiki/Mesa" target="_blank" rel="noreferrer noopener">mesa</a>. En el otro extremo, en el punto de partida, se coloca otra mesa con papel y lápiz para cada equipo.</p>



<p>Cada participante, correrá hacia el final de la pista para observar los objetos colocados en la mesa al llegar se le dará un tiempo razonable y deberá volver al punto de inicio donde anotará a su llegada los objetos que recuerde.</p>



<p>El siguiente hace lo mismo y así hasta que pase todo el equipo. Gana el equipo que más objetos tenga anotados cuando termine el tiempo, o el primero que tenga todos los objetos anotados.</p>', extracto = 'La carrera de objetos es una  actividad  que busca estimular la capacidad de observación y la atención a los detalles, se divide a los participantes en equipos...', metadata = '{"areas": ["corporalidad", "creatividad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "04 participantes", "duracion": "15 minutos", "unidades": ["avanzada", "compa¿¿a", "tropa"], "objetivos": ["Estimular la atenci¿n a los detalles", "Estimular la creatividad", "Estimular la observaci¿n"], "materiales": ["L¿piz", "Objetos Varios", "Papel"], "variaciones": "Una variaci¿n puede ser limitar la cantidad de observaciones de los objetos, por ejemplo, cada participante s¿lo podr¿ correr a la meta de objetos 2 veces o 1 vez, etc.", "recomendaciones": "Procure que los objetos colocados en la mesa no se visualicen a la distancia del inicio.\r\n\r\nTenga precauci¿n con el nivel del terreno para evitar ca¿das durante la carrera.", "justificacion_areas": "Fomenta la coordinaci¿n f¿sica y la resistencia cardiovascular mediante desaf¿os corporales din¿micos. Promueve el ingenio pr¿ctico, la agilidad mental y la resoluci¿n de problemas t¿cnicos o enigmas.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_CarreraDeObjetos.png", "objetivos_educativos": [{"id": "05f42879-f5f5-40c4-bed6-c577bf61340a", "area": "Corporalidad", "texto": "Cuido mi salud y mantengo h¿bitos que la protegen.", "unidad": "Avanzada", "como_se_cumple": "Aceptando sus capacidades f¿sicas y perfeccionando el control psicomotor durante el desarrollo de Carrera de Objetos."}, {"id": "705b686a-8374-467a-b871-f6470f0d58ae", "area": "Corporalidad", "texto": "Me doy cuenta de los cambios que se est¿n produciendo en mi cuerpo.", "unidad": "Compa¿¿a", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de Carrera de Objetos."}, {"id": "57887da4-c70e-45bc-bdfb-f79db513a89c", "area": "Corporalidad", "texto": "S¿ qué hacer frente a una enfermedad o accidente.", "unidad": "Compa¿¿a", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de Carrera de Objetos."}, {"id": "8cae916f-5e67-4697-b3cd-c59b5c7d1439", "area": "Corporalidad", "texto": "Trato de evitar situaciones que puedan da¿ar mi salud y la de mis compa¿eros.", "unidad": "Tropa", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de Carrera de Objetos."}, {"id": "68add558-4b03-4105-b00d-e7f2ead6ac23", "area": "Corporalidad", "texto": "S¿ qué hacer frente a una enfermedad o accidente.", "unidad": "Tropa", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de Carrera de Objetos."}, {"id": "3cdf4b56-b55f-4878-b3fa-da32a7200ca4", "area": "Creatividad", "texto": "Soy capaz de sintetizar, criticar, proponer y apreciar las opiniones de los dem¿s.", "unidad": "Avanzada", "como_se_cumple": "Demostrando agilidad mental y pensamiento cr¿tico inmediato para liderar la resoluci¿n estrat¿gica de Carrera de Objetos."}, {"id": "e1b7276f-4fd2-4c39-a32a-bd7fadbee702", "area": "Creatividad", "texto": "Doy mi opini¿n sobre las cosas que me pasan.", "unidad": "Compa¿¿a", "como_se_cumple": "Analizando el escenario t¿ctico del juego de forma ¿gil para proponer alternativas mentales en Carrera de Objetos."}, {"id": "9f30f035-9179-4ac4-acfb-bea0e169e97a", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Compa¿¿a", "como_se_cumple": "Analizando el escenario t¿ctico del juego de forma ¿gil para proponer alternativas mentales en Carrera de Objetos."}, {"id": "49ae6ac6-be8f-4f2c-8b3e-6711d041181f", "area": "Creatividad", "texto": "Doy mi opini¿n sobre las cosas que me pasan.", "unidad": "Tropa", "como_se_cumple": "Analizando el escenario t¿ctico del juego de forma ¿gil para proponer alternativas mentales en Carrera de Objetos."}, {"id": "cf530cf9-73a6-4423-a075-79be433fe96c", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Analizando el escenario t¿ctico del juego de forma ¿gil para proponer alternativas mentales en Carrera de Objetos."}]}'::jsonb WHERE id = '70755489-cdb1-4228-adaf-0e800ac81f0c';

UPDATE public.articulos SET titulo = 'Relevos de la botella', contenido = '<p>Los Relevos de la botella es una actividad enfocada en reforzar el trabajo en equipo y la sana competencia entre equipos.</p>



<p>Para los Relevos de la botella son necesarios <a href="https://nuamana.com/nuanew/cantidad-participantes/4-participantes/" target="_blank" rel="noreferrer noopener">al menos dos participantes por equipo,</a> una botella o recipiente por equipo, agua y un área de juego amplia.</p>



<h3 class="wp-block-heading">¿Cómo se hacen los relevos de la botella?</h3>



<p>Se ubican las botellas de cada equipo en el extremo contrario al punto de inicio de los equipos, al menos unos 10 metros de distancia, las botella o recipientes se encontrarán vacías y deben tener el mismo tamaño o capacidad.</p>



<p>Los equipos deben tener donde abastecerse de agua en el punto de inicio, puede ser otro par de botella de agua, una <a href="https://es.wikipedia.org/wiki/Olla" target="_blank" rel="noreferrer noopener">olla</a> u otro elemento donde puedan tener agua a su alcance de forma fácil y rápida.</p>



<p>A la señal la o el participante se llena la boca con agua y sale corriendo hacia la botella de su equipo, al llegar donde se encuentra la botella del equipo y vierte en ella el agua que tiene en la boca y regresa al punto de inicio. Así sucesivamente hasta que el equipo llene su botella.</p>', extracto = 'Los Relevos de la botella es una actividad enfocada en reforzar el trabajo en equipo y la sana competencia entre equipos. 



 Para los Relevos de la botella s...', metadata = '{"areas": ["corporalidad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "04 participantes", "duracion": "20 minutos", "unidades": ["compa¿¿a", "manada", "tropa"], "objetivos": ["Crear un ambiente de distensi¿n", "Trabajo en equipo"], "materiales": ["Agua", "Botella"], "variaciones": "Puede cambiar el medio de traslado del agua por transportarla en las manos u otro elemento en el que se pueda perder agua por el camino.", "recomendaciones": "Escoja un terreno de juego donde se pueda caer agua sin generar accidentes posteriores.", "justificacion_areas": "Fomenta la coordinaci¿n f¿sica y la resistencia cardiovascular mediante desaf¿os corporales din¿micos. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_relevosDeLaBotella.png", "objetivos_educativos": [{"id": "d5b111f1-5f6f-4716-8a02-e1826d653c59", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Compa¿¿a", "como_se_cumple": "Corriendo velozmente y dosificando su energ¿a y esfuerzo aer¿bico para superar las fases f¿sicas de Relevos de la botella."}, {"id": "b12da732-d736-480c-82b8-95b312316390", "area": "Corporalidad", "texto": "Me esfuerzo por mejorar mi rendimiento en el deporte que practico y s¿ ganar y perder.", "unidad": "Compa¿¿a", "como_se_cumple": "Corriendo velozmente y dosificando su energ¿a y esfuerzo aer¿bico para superar las fases f¿sicas de Relevos de la botella."}, {"id": "4bf1e3dd-7f21-4c24-962d-9d6d64e32f25", "area": "Corporalidad", "texto": "Me gusta hacer actividades al aire libre.", "unidad": "Manada", "como_se_cumple": "Corriendo a paso r¿pido y coordinando sus movimientos con sus compa¿eros durante la din¿mica de Relevos de la botella."}, {"id": "5d2d48ed-c461-4a8e-9048-cceecd3de2e2", "area": "Corporalidad", "texto": "Me gusta jugar con otros ni¿os y ni¿as y respeto las reglas de los juegos.", "unidad": "Manada", "como_se_cumple": "Corriendo a paso r¿pido y coordinando sus movimientos con sus compa¿eros durante la din¿mica de Relevos de la botella."}, {"id": "58b4936a-816e-4d17-8d0a-c92d0606009d", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Corriendo velozmente y dosificando su energ¿a y esfuerzo aer¿bico para superar las fases f¿sicas de Relevos de la botella."}, {"id": "6768d60a-187e-4bbf-97b9-cdc25a316030", "area": "Corporalidad", "texto": "Ayudo a preparar los juegos, excursiones y campamentos de mi patrulla y mi Tropa.", "unidad": "Tropa", "como_se_cumple": "Corriendo velozmente y dosificando su energ¿a y esfuerzo aer¿bico para superar las fases f¿sicas de Relevos de la botella."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compa¿¿a", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante Relevos de la botella."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que act¿o, aunque no siempre est¿ de acuerdo con ellas.", "unidad": "Compa¿¿a", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante Relevos de la botella."}, {"id": "b69188bf-2391-43c1-a885-abd1b13912be", "area": "Sociabilidad", "texto": "Acepto las reglas que se ponen en mi casa, en la escuela y en la Manada.", "unidad": "Manada", "como_se_cumple": "Respetando rigurosamente las reglas del juego de relevos y las instrucciones de seguridad en Relevos de la botella."}, {"id": "2394dd5b-87b9-4f3d-9cdd-a42649139782", "area": "Sociabilidad", "texto": "Comprendo y respeto las normas que se han puesto en mi casa y en la escuela, aunque no siempre est¿ de acuerdo con ellas", "unidad": "Manada", "como_se_cumple": "Respetando rigurosamente las reglas del juego de relevos y las instrucciones de seguridad en Relevos de la botella."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante Relevos de la botella."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que act¿o, aunque no siempre est¿ de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante Relevos de la botella."}]}'::jsonb WHERE id = 'b4c00c19-1082-4974-be52-a55c4598f5bf';

UPDATE public.articulos SET titulo = 'El viejo tarugo', contenido = '<p>El viejo tarugo es una actividad que busca promover el trabajo en equipo y la elaboración colaborativa de estrategias para el equipo, también es una actividad con un alto componente físico por lo que puede ser utilizada para desfogue de energías.</p>



<p>Para poder realizar el viejo tarugo es necesario al menos <a href="https://nuamana.com/nuanew/cantidad-participantes/6-participantes/" target="_blank" rel="noreferrer noopener">2 equipos de 3 participantes cada uno</a>, un área de juego pequeña que pueda contener dos círculos y una pelota, la pelota se puede hacer amarrando pañolines unos con otros hasta tener algo parecido a una pelota.</p>



<h3 class="wp-block-heading">¿Cómo se hace el viejo tarugo?</h3>



<p>Para hacer el viejo tarugo, se divide a las y los participantes en dos equipos, estos equipos se encontrarán en <a href="https://es.wikipedia.org/wiki/Conc%C3%A9ntrico" target="_blank" rel="noreferrer noopener">círculos concéntricos</a> y en el centro de ambos círculos se colocara un participante del equipo que se encuentra en el círculo exterior.</p>



<p>Los y las jugadoras que se encuentran en el círculo exterior deben hacer circular la pelota entre ellos con el objetivo de buscar una apertura en el círculo interior y entregarle la pelota al compañero o compañera que está en el centro del círculo interior.</p>



<p>Las y los participantes que se encuentran en el círculo interior deben bloquear cualquier intento de que la pelota llegue al jugador (a) que está en el centro de los círculos.</p>



<p>Cuando los y las participantes del círculo exterior le logran pasar la pelota a la jugadora (o) en el centro se hace el intercambio de equipos, los que estaban en el círculo interior pasan al exterior y viceversa.</p>



<p>Gana el equipo que demora menos tiempo en pasar la pelota, la o el participante en el interior del círculo debe cambiar en cada traspaso de pelota, siendo la idea que todos los y las jugadores pasen por el centro de los círculos.</p>', extracto = 'El viejo tarugo es una actividad que busca promover el trabajo en equipo y la elaboración colaborativa de estrategias para el equipo, también es una actividad...', metadata = '{"areas": ["corporalidad", "creatividad", "sociabilidad"], "lugares": ["Campo Abierto", "Exterior"], "cantidad": "06 participantes", "duracion": "20 minutos", "unidades": ["avanzada", "compa¿¿a", "tropa"], "objetivos": ["Promover la elaboraci¿n de estrategias", "Trabajo en equipo"], "materiales": ["Pelota"], "variaciones": "Puede variar el juego indicando que la pelota s¿lo se puede pasar en mano o que s¿lo puede ser lanzada, o dando ambas opciones.", "recomendaciones": "Procure tener las precauciones con el terreno, pero también haciendo ¿nfasis en la seguridad y en el cuidado con aquellos que sean m¿s peque¿os o tengan menos fuerza.", "justificacion_areas": "Fomenta la coordinaci¿n f¿sica y la resistencia cardiovascular mediante desaf¿os corporales din¿micos. Promueve el ingenio pr¿ctico, la agilidad mental y la resoluci¿n de problemas t¿cnicos o enigmas. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_elViejoTarugo.png", "objetivos_educativos": [{"id": "05f42879-f5f5-40c4-bed6-c577bf61340a", "area": "Corporalidad", "texto": "Cuido mi salud y mantengo h¿bitos que la protegen.", "unidad": "Avanzada", "como_se_cumple": "Aceptando sus capacidades f¿sicas y perfeccionando el control psicomotor durante el desarrollo de El viejo tarugo."}, {"id": "705b686a-8374-467a-b871-f6470f0d58ae", "area": "Corporalidad", "texto": "Me doy cuenta de los cambios que se est¿n produciendo en mi cuerpo.", "unidad": "Compa¿¿a", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de El viejo tarugo."}, {"id": "57887da4-c70e-45bc-bdfb-f79db513a89c", "area": "Corporalidad", "texto": "S¿ qué hacer frente a una enfermedad o accidente.", "unidad": "Compa¿¿a", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de El viejo tarugo."}, {"id": "8cae916f-5e67-4697-b3cd-c59b5c7d1439", "area": "Corporalidad", "texto": "Trato de evitar situaciones que puedan da¿ar mi salud y la de mis compa¿eros.", "unidad": "Tropa", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de El viejo tarugo."}, {"id": "68add558-4b03-4105-b00d-e7f2ead6ac23", "area": "Corporalidad", "texto": "S¿ qué hacer frente a una enfermedad o accidente.", "unidad": "Tropa", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de El viejo tarugo."}, {"id": "843fda9c-6c4a-4516-b30c-23c92ef755a8", "area": "Creatividad", "texto": "Puedo resolver la mayor¿a de los problemas t¿cnicos dom¿sticos simples.", "unidad": "Avanzada", "como_se_cumple": "Combinando conocimientos pr¿cticos e inventiva t¿cnica para resolver los retos de pionerismo y dise¿o en El viejo tarugo."}, {"id": "103661fc-3396-4eac-9182-58b7e54d5115", "area": "Creatividad", "texto": "Perfecciono mis habilidades manuales.", "unidad": "Compa¿¿a", "como_se_cumple": "Aplicando ingenio pr¿ctico y destrezas manuales para optimizar los recursos construidos en El viejo tarugo."}, {"id": "0f60be94-6de3-4c34-a6ff-5b5018f0b156", "area": "Creatividad", "texto": "Coopero en la mantenci¿n y renovaci¿n del local y materiales de mi patrulla.", "unidad": "Compa¿¿a", "como_se_cumple": "Aplicando ingenio pr¿ctico y destrezas manuales para optimizar los recursos construidos en El viejo tarugo."}, {"id": "11320fb6-98de-4725-825d-db858e3bffa2", "area": "Creatividad", "texto": "Perfecciono mis habilidades manuales.", "unidad": "Tropa", "como_se_cumple": "Aplicando ingenio pr¿ctico y destrezas manuales para optimizar los recursos construidos en El viejo tarugo."}, {"id": "fd3d3e14-e92b-4ab5-8298-9018c6e70b20", "area": "Creatividad", "texto": "Coopero en la mantenci¿n y renovaci¿n del local y materiales de mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Aplicando ingenio pr¿ctico y destrezas manuales para optimizar los recursos construidos en El viejo tarugo."}, {"id": "f1496221-0da5-4775-b3ba-29e65603cfee", "area": "Sociabilidad", "texto": "Acepto las normas de los diferentes ambientes en que act¿o, sin renunciar a mi derecho de tratar de cambiarlas cuando no me parecen correctas.", "unidad": "Avanzada", "como_se_cumple": "Velando por la seguridad f¿sica y el cumplimiento estricto del reglamento de competencia en El viejo tarugo."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compa¿¿a", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante El viejo tarugo."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que act¿o, aunque no siempre est¿ de acuerdo con ellas.", "unidad": "Compa¿¿a", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante El viejo tarugo."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante El viejo tarugo."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que act¿o, aunque no siempre est¿ de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante El viejo tarugo."}]}'::jsonb WHERE id = 'c126a443-2ad1-4805-ac4b-ce7b2ba02aa2';

UPDATE public.articulos SET titulo = 'Regalos y Guantes', contenido = '<p>Los Regalos y guantes es una actividad de <a href="https://nuamana.cl/etiqueta/navidad-scout/" data-type="post_tag" data-id="155">Navidad</a> que busca estimular a el o la participante desde la rapidez mental, y la agilidad de reacción, al mismo tiempo que busca desarrollar la capacidad cognitiva de las y los jugadores.</p>







<p>Para poder efectuar los regalos y guantes se necesita tener previamente envueltos como regalos diferentes paquetes, de diversos tamaños y no es necesario un área de juego específica.</p>







<h3 class="wp-block-heading">¿Cómo se hacen los regalos y guantes?</h3>







<p>La actividad consiste en abrir regalos envueltos usando <a href="https://es.wikipedia.org/wiki/Manopla" target="_blank" rel="noreferrer noopener">guantes de cocina</a>. Se divide a los y las participantes en equipos, cada equipo tendrá un par de guantes y 2 dados.</p>







<p>El equipo se coloca en un círculo y tanto los dados como, el regalo y los guantes irán pasando de mano en mano en el sentido del reloj.</p>







<p>El o la primera participante del equipo lanza los dados hasta que le salga par en el resultado de los dados, cuando le sale un número par en los dados rápidamente se coloca los guantes de cocina y comienza a tratar de abrir el regalo.</p>







<p>Mientras lo anterior sucede, en el mismo momento que la o el primer participante soltó los dados, la o el siguiente jugador puede comenzar a tirar los dados en cuanto le salga número par en los dados, le puede quitar los guantes y el regalo al jugador anterior para comenzar a abrirlo en cuanto tenga los guantes puestos.</p>







<p>En cuanto el o la jugadora suelta los dados comienza el turno del siguiente hasta que saca número par para quitarle los guantes y el regalo al anterior, así sucesivamente hasta que se abra el regalo.</p>







<p>Mira un pequeño ejemplo en este video.</p>







