UPDATE public.articulos SET titulo = 'Lucha con una pierna y una mano', contenido = '<p>La lucha con una pierna y una mano es una actividad de desfogue de energías que busca permitir a los y las participantes conocer sus limitaciones físicas y desarrollar un poco de equilibrio.</p>



<p>Es una actividad con un alto componente físico, pero que no necesariamente requiere de fuerza para poder ganar, la agilidad y el equilibrio son factores mucho más importantes.</p>



<p>La lucha con una pierna y una mano es una actividad que se puede desarrollar perfectamente como una competencia <a href="https://nuamana.com/nuanew/cantidad-participantes/individual/" target="_blank" rel="noreferrer noopener">individual</a> o entre equipos.</p>



<h3 class="wp-block-heading">¿Cómo se hace la Lucha con una pierna y una mano?</h3>



<p>Cada competidor sostiene su pierna izquierda o derecha tras de sí tomada con la misma mano de la pierna que sostiene, es decir, si sostiene su pierna izquierda la tendrá con su mano izquierda y/o viceversa, mientras que con la mano que le queda libre toma la mano del compañero o compañera.</p>



<p>A la señal <a href="https://es.wiktionary.org/wiki/tiran" target="_blank" rel="noreferrer noopener">tiran</a> o empujan a su pareja de forma tal de forzar que baje su pierna y toque el suelo con ella.</p>



<p>Gana quien no baje su pierna y toque el suelo con su pie o el que caiga al suelo.</p>', extracto = 'La lucha con una pierna y una mano es una actividad de desfogue de energías que busca permitir a los y las participantes conocer sus limitaciones físicas y des...', metadata = '{"areas": ["corporalidad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "individual", "duracion": "15 minutos", "unidades": ["compa¿¿a", "tropa"], "objetivos": ["Conocer las capacidades corporales", "Desfogue de Energ¿as"], "materiales": ["Sin Materiales"], "variaciones": "Puede hacer lo mismo sin que se tomen con su mano libre, esto promover¿ mucho m¿s la agilidad y equilibrio por sobre la fuerza.", "recomendaciones": "Procure hacer ¿nfasis en el cuidado del oponente para que no se generen accidentes innecesarios. Trate de hacerlo sobre un terreno que no sea cemento para evitar golpes demasiado fuertes.", "justificacion_areas": "Fomenta la coordinaci¿n f¿sica y la resistencia cardiovascular mediante desaf¿os corporales din¿micos. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_LuchaUnaPiernaUnaMano.png", "objetivos_educativos": [{"id": "d5b111f1-5f6f-4716-8a02-e1826d653c59", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Compa¿¿a", "como_se_cumple": "Corriendo velozmente y dosificando su energ¿a y esfuerzo aer¿bico para superar las fases f¿sicas de Lucha con una pierna y una mano."}, {"id": "b12da732-d736-480c-82b8-95b312316390", "area": "Corporalidad", "texto": "Me esfuerzo por mejorar mi rendimiento en el deporte que practico y s¿ ganar y perder.", "unidad": "Compa¿¿a", "como_se_cumple": "Corriendo velozmente y dosificando su energ¿a y esfuerzo aer¿bico para superar las fases f¿sicas de Lucha con una pierna y una mano."}, {"id": "58b4936a-816e-4d17-8d0a-c92d0606009d", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Corriendo velozmente y dosificando su energ¿a y esfuerzo aer¿bico para superar las fases f¿sicas de Lucha con una pierna y una mano."}, {"id": "6768d60a-187e-4bbf-97b9-cdc25a316030", "area": "Corporalidad", "texto": "Ayudo a preparar los juegos, excursiones y campamentos de mi patrulla y mi Tropa.", "unidad": "Tropa", "como_se_cumple": "Corriendo velozmente y dosificando su energ¿a y esfuerzo aer¿bico para superar las fases f¿sicas de Lucha con una pierna y una mano."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compa¿¿a", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante Lucha con una pierna y una mano."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que act¿o, aunque no siempre est¿ de acuerdo con ellas.", "unidad": "Compa¿¿a", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante Lucha con una pierna y una mano."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante Lucha con una pierna y una mano."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que act¿o, aunque no siempre est¿ de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante Lucha con una pierna y una mano."}]}'::jsonb WHERE id = 'f36e1535-6aef-4cb5-bc4c-7da6dee08eaf';

UPDATE public.articulos SET titulo = 'Esquiva el tiro', contenido = '<p>Esquiva el tiro es una actividad enfocada en el desfogue de energías, y el refuerzo de la motricidad, permite al mismo tiempo generar un ambiente de sana competencia y distensión.</p>



<p>Para realizar esquiva el tiro se requiere como mínimo <a href="https://nuamana.com/nuanew/cantidad-participantes/4-participantes/" target="_blank" rel="noreferrer noopener">4 participantes</a> considerando que al menos uno debe estar sosteniendo la cuerda.</p>



<h3 class="wp-block-heading">¿Cómo se hace Esquiva el tiro?</h3>



<p>Se utilizará una cuerda con un par de metros con un pequeño peso en el extremo, idealmente que no supere los 500 gramos de peso. Las y los jugadores forman un círculo alrededor del <a href="https://es.wikipedia.org/wiki/Director_de_juego" target="_blank" rel="noreferrer noopener">director del juego</a>.</p>



<p>El director del juego sostiene la cuerda con el peso ya puesto en el centro del círculo. Deberá mover la cuerda a fin de describir con ella un círculo que vaya a una altura por debajo del nivel de las rodillas de las y los jugadores que integran el círculo.</p>



<p>Los y las jugadoras deben saltar a medida que la cuerda va tratando de pasar al otro lado. Las y los participantes que tengan menos fallos o puntos en contra al final del juego, serán los ganadores.</p>', extracto = 'Esquiva el tiro es una actividad enfocada en el desfogue de energías, y el refuerzo de la motricidad, permite al mismo tiempo generar un ambiente de sana compe...', metadata = '{"areas": ["corporalidad"], "lugares": ["Campo Abierto", "Exterior", "Interior"], "cantidad": "04 participantes", "duracion": "15 minutos", "unidades": ["avanzada", "compa¿¿a", "manada", "tropa"], "objetivos": ["Desarrollar la motricidad", "Desfogue de Energ¿as"], "materiales": ["Bolsa", "Cuerda"], "variaciones": "Una variaci¿n m¿s sencilla puede ser sin un peso y simplemente formar el c¿rculo con la cuerda a la misma altura del piso.", "recomendaciones": "Ponga especial atenci¿n a posibles ca¿das que se pueden producir por golpes con el peso en la cuerda, o con la misma cuerda que se amarre en los pies de las y los jugadores al momento de saltar.", "justificacion_areas": "Fomenta la coordinaci¿n f¿sica y la resistencia cardiovascular mediante desaf¿os corporales din¿micos.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_esquivaElTiro.png", "objetivos_educativos": [{"id": "7200435f-b020-46fc-b323-8249048b1d18", "area": "Corporalidad", "texto": "Participo en la organizaci¿n de juegos y actividades recreativas para los dem¿s.", "unidad": "Avanzada", "como_se_cumple": "Desplegando su m¿ximo rendimiento aer¿bico, agilidad y coordinaci¿n t¿ctica en la carrera de Esquiva el tiro."}, {"id": "d5b111f1-5f6f-4716-8a02-e1826d653c59", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Compa¿¿a", "como_se_cumple": "Corriendo velozmente y dosificando su energ¿a y esfuerzo aer¿bico para superar las fases f¿sicas de Esquiva el tiro."}, {"id": "b12da732-d736-480c-82b8-95b312316390", "area": "Corporalidad", "texto": "Me esfuerzo por mejorar mi rendimiento en el deporte que practico y s¿ ganar y perder.", "unidad": "Compa¿¿a", "como_se_cumple": "Corriendo velozmente y dosificando su energ¿a y esfuerzo aer¿bico para superar las fases f¿sicas de Esquiva el tiro."}, {"id": "4bf1e3dd-7f21-4c24-962d-9d6d64e32f25", "area": "Corporalidad", "texto": "Me gusta hacer actividades al aire libre.", "unidad": "Manada", "como_se_cumple": "Corriendo a paso r¿pido y coordinando sus movimientos con sus compa¿eros durante la din¿mica de Esquiva el tiro."}, {"id": "5d2d48ed-c461-4a8e-9048-cceecd3de2e2", "area": "Corporalidad", "texto": "Me gusta jugar con otros ni¿os y ni¿as y respeto las reglas de los juegos.", "unidad": "Manada", "como_se_cumple": "Corriendo a paso r¿pido y coordinando sus movimientos con sus compa¿eros durante la din¿mica de Esquiva el tiro."}, {"id": "58b4936a-816e-4d17-8d0a-c92d0606009d", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Corriendo velozmente y dosificando su energ¿a y esfuerzo aer¿bico para superar las fases f¿sicas de Esquiva el tiro."}, {"id": "6768d60a-187e-4bbf-97b9-cdc25a316030", "area": "Corporalidad", "texto": "Ayudo a preparar los juegos, excursiones y campamentos de mi patrulla y mi Tropa.", "unidad": "Tropa", "como_se_cumple": "Corriendo velozmente y dosificando su energ¿a y esfuerzo aer¿bico para superar las fases f¿sicas de Esquiva el tiro."}]}'::jsonb WHERE id = 'f4373764-4b71-4f03-b768-1e16316c9b13';

UPDATE public.articulos SET titulo = 'Relevos del pañuelo', contenido = '<p>Relevos del pañuelo es una actividad enfocada en el desarrollo de la motricidad, el trabajo en equipo y el desfogue de energías, requiere un par de sillas y un par de pañuelos o pañolines para poder efectuarla.</p>







<p>Es una actividad por equipos, por lo que al menos se requieren dos personas <a href="https://nuamana.com/nuanew/etiqueta/en-equipo/" target="_blank" rel="noreferrer noopener">por equipo</a>.</p>







<p>El enfoque en la motricidad fina de los Relevos del pañuelo la hace una actividad ideal para unidades menores e intermedias que permitirá a las y los participantes enfocarse inicialmente en la carrera pero será el pañuelo lo que va a generar un cambio rápido de enfoque.</p>







<h3 class="wp-block-heading">¿Cómo se hacen los Relevos del pañuelo?</h3>







<p>Se divide a los equipos y se les ubica en el punto de inicio del <a href="https://es.wikipedia.org/wiki/Pista_de_juego" target="_blank" rel="noreferrer noopener">área de juego</a>, en el extremo opuesto del área de juego se ubicara una silla, u otro objeto similar para los efectos de la actividad, y un pañuelo.</p>







<p>A la señal, sale el o la primera participante de cada equipo corriendo hacia donde se encuentra la silla, en la ubicación de la silla también se encontrará el pañuelo.</p>







<p>Al llegar a la silla la o el corredor anuda fuertemente el pañuelo en una pata de la silla y regresa al punto de partida, acto seguido a la llegada del primer participante sale corriendo el o la siguiente jugadora que llega a la silla y desata el pañuelo, así sucesivamente hasta que pasan todas y todos los participantes.</p>







