UPDATE public.articulos SET titulo = 'Adivina la palabra', contenido = '<p>Adivina la palabra es una actividad enfocada en el trabajo de equipo y el desarrollo de estrategias, para poder efectuar la actividad es necesario tener una cartulina por equipo y aguja o algo con punta para poder perforar la carpeta, de un grosor no tan pequeño.</p>



<p>El juego Adivina la palabra se desarrolla en equipos que deberán descifrar una palabra que no es visible, sin embargo, como variable se puede agregar que tengan los ojos vendados.</p>



<h3 class="wp-block-heading">¿Cómo se hace Adivina la palabra?</h3>



<p>Primero, en caso de que no se así desde antes, se dividen los equipos, los equipos se colocan en filas (un participante detrás de otro) detrás de la línea de inicio.</p>



<p>A la señal el último de la fila gritara <a href="https://nuamana.com/nuanew/actividades/juegos/cuerpo-a-tierra/" target="_blank" rel="noreferrer noopener">¡Cuerpo a Tierra!</a> y saldrá corriendo por sobre sus compañeras y/o compañeros hasta el punto de meta en el final del área de juego.</p>



<p>Al llegar el o la participante encontrará una cartulina con relieves perforados, parecida a como se escribe en <a href="https://es.wikipedia.org/wiki/Braille_(lectura)" target="_blank" rel="noreferrer noopener">Braille</a>, la idea es que estos relieves en la cartulina formen una palabra o frase, en caso de ir con los ojos desvendados las perforaciones deben ser pequeñas.</p>



<p>La cartulina se debe perforar desde atrás hacia adelante formando la letra, la idea es que descubran la letra a través del tacto y no de la vista; En la cartulina se escribirá mediante perforaciones una frase o una palabra, dependiendo de la dificultad que se quiera dar.</p>



<p>Al llegar la o el participante a la cartulina mediante el tacto tratara de descifrar la primera letra (en caso de ser una palabra) o palabra (en caso de ser una frase, cuando crea que ya sabe que dice, vuelve con su equipo se coloca al principio de la fila y sale nuevamente el último de la fila después de gritar <a href="https://nuamana.com/nuanew/actividades/juegos/cuerpo-a-tierra/" target="_blank" rel="noreferrer noopener">¡Cuerpo a Tierra!</a> y así sucesivamente hasta que el equipo se logre Adivina la palabra.</p>



<p>Ganará el equipo que primero diga la palabra o frase en su cartulina.</p>', extracto = 'Adivina la palabra es una actividad enfocada en el trabajo de equipo y el desarrollo de estrategias, para poder efectuar la actividad es necesario tener una ca...', metadata = '{"areas": ["creatividad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "04 participantes", "duracion": "30 minutos", "unidades": ["avanzada", "compa¿¿a", "tropa"], "objetivos": ["Promover la elaboraci¿n de estrategias", "Trabajo en equipo"], "materiales": ["Aguja", "Cartulina"], "variaciones": "La actividad se puede hacer con los ojos vendados, donde para llegar a la cartulina su equipo lo debe guiar con gritos y lo mismo al regresar, en este caso las perforaciones deben ser m¿s grandes.", "recomendaciones": "A los dos grupos, es recomendable que tengan un cuaderno y l¿piz donde puedan escribir lo que hayan descifrado con el tacto.\r\n\r\nProcure que el terreno de juego sea parejo para evitar accidentes de ca¿das.", "justificacion_areas": "Promueve el ingenio pr¿ctico, la agilidad mental y la resoluci¿n de problemas t¿cnicos o enigmas. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_adivinaLaPalabra.png", "objetivos_educativos": [{"id": "3cdf4b56-b55f-4878-b3fa-da32a7200ca4", "area": "Creatividad", "texto": "Soy capaz de sintetizar, criticar, proponer y apreciar las opiniones de los dem¿s.", "unidad": "Avanzada", "como_se_cumple": "Demostrando agilidad mental y pensamiento cr¿tico inmediato para liderar la resoluci¿n estrat¿gica de Adivina la palabra."}, {"id": "e1b7276f-4fd2-4c39-a32a-bd7fadbee702", "area": "Creatividad", "texto": "Doy mi opini¿n sobre las cosas que me pasan.", "unidad": "Compa¿¿a", "como_se_cumple": "Analizando el escenario t¿ctico del juego de forma ¿gil para proponer alternativas mentales en Adivina la palabra."}, {"id": "9f30f035-9179-4ac4-acfb-bea0e169e97a", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Compa¿¿a", "como_se_cumple": "Analizando el escenario t¿ctico del juego de forma ¿gil para proponer alternativas mentales en Adivina la palabra."}, {"id": "49ae6ac6-be8f-4f2c-8b3e-6711d041181f", "area": "Creatividad", "texto": "Doy mi opini¿n sobre las cosas que me pasan.", "unidad": "Tropa", "como_se_cumple": "Analizando el escenario t¿ctico del juego de forma ¿gil para proponer alternativas mentales en Adivina la palabra."}, {"id": "cf530cf9-73a6-4423-a075-79be433fe96c", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Analizando el escenario t¿ctico del juego de forma ¿gil para proponer alternativas mentales en Adivina la palabra."}, {"id": "f1496221-0da5-4775-b3ba-29e65603cfee", "area": "Sociabilidad", "texto": "Acepto las normas de los diferentes ambientes en que act¿o, sin renunciar a mi derecho de tratar de cambiarlas cuando no me parecen correctas.", "unidad": "Avanzada", "como_se_cumple": "Velando por la seguridad f¿sica y el cumplimiento estricto del reglamento de competencia en Adivina la palabra."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compa¿¿a", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante Adivina la palabra."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que act¿o, aunque no siempre est¿ de acuerdo con ellas.", "unidad": "Compa¿¿a", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante Adivina la palabra."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante Adivina la palabra."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que act¿o, aunque no siempre est¿ de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante Adivina la palabra."}]}'::jsonb WHERE id = '7bf6a7d3-21a1-40c7-83dd-53178bfdc23f';

UPDATE public.articulos SET titulo = 'El guardia y los prisioneros', contenido = '<p>El guardia y los prisioneros es un <a href="https://nuamana.com/nuanew/etiqueta/juegos-nocturnos/" target="_blank" rel="noreferrer noopener">juego nocturno</a> que busca estimular el desarrollo de estrategias, promover la motricidad y el desarrollo de la observación en los participantes.</p>



<p>Para poder llevar a cabo la actividad de el guardia y los prisioneros son necesarios al menos 4 participantes, que deben <a href="https://blogs.20minutos.es/yaestaellistoquetodolosabe/tag/sigilo/" target="_blank" rel="noreferrer noopener">moverse con sigilo y cautela</a> durante la noche.</p>



<h3 class="wp-block-heading">¿Cómo se hace el guardia y los prisioneros?</h3>



<p>Para jugar El guardia y los prisioneros, primero se marcaran las líneas de inicio (cárcel) y de meta (seguridad) en los extremos del área de juego.</p>



<p>Después se elegirá a un <strong>GUARDIA</strong> dentro de los y las participantes, al guardia se le proveerá de una linterna para que pueda vigilar a los prisioneros durante la noche.</p>



<p>Los y las demás jugadoras serán <strong>PRISIONEROS</strong> que tratan de ir ocultos desde la línea de partida hasta una línea de seguridad simulando escaparse de una cárcel.</p>



<p>A la señal del <strong>GUARDIA</strong> los <strong>PRISIONEROS</strong> comienzan su intento de fuga, Si el <strong>GUARDIA</strong> escucha un ruido, enfocará su linterna apagada hacia el lugar donde él piensa que se halla un prisionero y gritará Alto! Todos los <strong>PRISIONEROS</strong> deberán permanecer inmóviles (Congelados).</p>



<p>Tras lo anterior el <strong>GUARDIA</strong> encenderá su linterna solamente hacia el lugar donde estaba apuntando y si atrapó a un Prisionero, éste deberá retroceder X cantidad de metros.</p>



<p>Luego de ello el <strong>GUARDIA</strong> apagará la linterna para señalar que el juego continúa. Si el <strong>GUARDIA</strong> realiza más de 3 desafíos en falso, pierde el juego y será ganador aquel Prisionero que se encuentre más cerca de la línea de seguridad.</p>



<p>El primer Prisionero en llegar a la línea de seguridad será quien gane convirtiéndose en <strong>GUARDIA</strong> para el próximo juego.</p>', extracto = 'El guardia y los prisioneros es un  juego nocturno  que busca estimular el desarrollo de estrategias, promover la motricidad y el desarrollo de la observación...', metadata = '{"areas": ["corporalidad", "creatividad"], "lugares": ["Bosque", "Campo delimitado", "Exterior"], "cantidad": "04 participantes", "duracion": "45 minutos", "unidades": ["avanzada", "clan", "compa¿¿a", "tropa"], "objetivos": ["Desarrollar la motricidad", "Estimular la observaci¿n", "Promover la elaboraci¿n de estrategias"], "materiales": ["Linterna"], "variaciones": "Una variaci¿n puede ser eliminar a las y los participantes cuando son descubiertos al avanzar.", "recomendaciones": "Tenga en consideraci¿n la iluminaci¿n en el lugar a la hora de jugar, prefiera un ¿rea boscosa para facilitar la huida de los prisioneros o un claro para dificultarla.\r\n\r\nHaga las recomendaciones de seguridad necesarias para que caminen con cuidado en un terreno sin iluminaci¿n.", "justificacion_areas": "Fomenta la coordinaci¿n f¿sica y la resistencia cardiovascular mediante desaf¿os corporales din¿micos. Promueve el ingenio pr¿ctico, la agilidad mental y la resoluci¿n de problemas t¿cnicos o enigmas.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_ElGuardiaYLosPrisioneros.png", "objetivos_educativos": [{"id": "05f42879-f5f5-40c4-bed6-c577bf61340a", "area": "Corporalidad", "texto": "Cuido mi salud y mantengo h¿bitos que la protegen.", "unidad": "Avanzada", "como_se_cumple": "Aceptando sus capacidades f¿sicas y perfeccionando el control psicomotor durante el desarrollo de El guardia y los prisioneros."}, {"id": "69fff91f-a493-483d-92d6-8319700236c2", "area": "Corporalidad", "texto": "Conoce los procesos biol¿gicos que regulan su organismo, protege su salud, acepta sus posibilidades f¿sicas y orienta sus impulsos y fuerzas.", "unidad": "Clan", "como_se_cumple": "Aceptando sus capacidades f¿sicas y perfeccionando el control psicomotor durante el desarrollo de El guardia y los prisioneros."}, {"id": "705b686a-8374-467a-b871-f6470f0d58ae", "area": "Corporalidad", "texto": "Me doy cuenta de los cambios que se est¿n produciendo en mi cuerpo.", "unidad": "Compa¿¿a", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de El guardia y los prisioneros."}, {"id": "57887da4-c70e-45bc-bdfb-f79db513a89c", "area": "Corporalidad", "texto": "S¿ qué hacer frente a una enfermedad o accidente.", "unidad": "Compa¿¿a", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de El guardia y los prisioneros."}, {"id": "8cae916f-5e67-4697-b3cd-c59b5c7d1439", "area": "Corporalidad", "texto": "Trato de evitar situaciones que puedan da¿ar mi salud y la de mis compa¿eros.", "unidad": "Tropa", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de El guardia y los prisioneros."}, {"id": "68add558-4b03-4105-b00d-e7f2ead6ac23", "area": "Corporalidad", "texto": "S¿ qué hacer frente a una enfermedad o accidente.", "unidad": "Tropa", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de El guardia y los prisioneros."}, {"id": "3cdf4b56-b55f-4878-b3fa-da32a7200ca4", "area": "Creatividad", "texto": "Soy capaz de sintetizar, criticar, proponer y apreciar las opiniones de los dem¿s.", "unidad": "Avanzada", "como_se_cumple": "Demostrando agilidad mental y pensamiento cr¿tico inmediato para liderar la resoluci¿n estrat¿gica de El guardia y los prisioneros."}, {"id": "ef75fbed-4a6d-49ea-bfab-f2952415e1a0", "area": "Creatividad", "texto": "Act¿a con agilidad mental ante las situaciones m¿s diversas, desarrollando su capacidad de pensar, innovar y aventurar.", "unidad": "Clan", "como_se_cumple": "Demostrando agilidad mental y pensamiento cr¿tico inmediato para liderar la resoluci¿n estrat¿gica de El guardia y los prisioneros."}, {"id": "e1b7276f-4fd2-4c39-a32a-bd7fadbee702", "area": "Creatividad", "texto": "Doy mi opini¿n sobre las cosas que me pasan.", "unidad": "Compa¿¿a", "como_se_cumple": "Analizando el escenario t¿ctico del juego de forma ¿gil para proponer alternativas mentales en El guardia y los prisioneros."}, {"id": "9f30f035-9179-4ac4-acfb-bea0e169e97a", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Compa¿¿a", "como_se_cumple": "Analizando el escenario t¿ctico del juego de forma ¿gil para proponer alternativas mentales en El guardia y los prisioneros."}, {"id": "49ae6ac6-be8f-4f2c-8b3e-6711d041181f", "area": "Creatividad", "texto": "Doy mi opini¿n sobre las cosas que me pasan.", "unidad": "Tropa", "como_se_cumple": "Analizando el escenario t¿ctico del juego de forma ¿gil para proponer alternativas mentales en El guardia y los prisioneros."}, {"id": "cf530cf9-73a6-4423-a075-79be433fe96c", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Analizando el escenario t¿ctico del juego de forma ¿gil para proponer alternativas mentales en El guardia y los prisioneros."}]}'::jsonb WHERE id = '8a6d8a79-f3dd-402c-9d2e-10d91c8f86d9';

UPDATE public.articulos SET titulo = 'Señales nocturnas', contenido = '<p>Señales nocturnas es una actividad que permite practicar el <a href="https://nuamana.com/nuanew/tecnicas/claves-y-pistas/codigo-morse/" target="_blank" rel="noreferrer noopener">código morse</a> al mismo tiempo que refuerza el <a href="https://nuamana.com/nuanew/objetivos-actividad/trabajo-en-equipo/" target="_blank" rel="noreferrer noopener">trabajo en equipo</a>, y la cohesión dentro del mismo.</p>



<p>Para poder realizar las señales nocturnas es necesario disponer de una <a href="https://es.wikipedia.org/wiki/Linterna" target="_blank" rel="noreferrer noopener">linterna</a> o un elemento lumínico que permita prender y apagar y ser visible a una distancia mayor a 50 mts.</p>



<h3 class="wp-block-heading">¿Cómo se hacen las Señales Nocturnas?</h3>



<p>Primero se divide al grupo en equipos, debe haber al menos 2 participantes por cada equipo para que exista una comunicación, ambos equipos escribirán un mensaje de diez palabras en morse para el equipo contrario.</p>



<p>Cuando ambos equipos tengan diseñado su mensaje se elegirá un representante de cada equipo para que se ubiquen en un lugar específico con una linterna y el mensaje del otro equipo.</p>



<p>Las y los demás participantes de cada equipo estarán a unos 50 metros (aprox.) de sus integrantes (no necesariamente en la misma dirección para no confundir las señales de la linterna del otro equipo) y deberán resolver el mensaje con las señales dadas por la linterna.</p>



<p>El encargado del juego indicará el inicio de la traducción del mensaje para ambos equipos, el primer equipo en resolver el mensaje será el ganador.</p>', extracto = 'Señales nocturnas es una actividad que permite practicar el  código morse  al mismo tiempo que refuerza el  trabajo en equipo , y la cohesión dentro del mismo....', metadata = '{"areas": ["car¿cter", "creatividad", "sociabilidad"], "lugares": ["Campo Abierto", "Exterior"], "cantidad": "04 participantes", "duracion": "45 minutos", "unidades": ["avanzada", "clan", "compa¿¿a", "tropa"], "objetivos": ["Crear un ambiente de distensi¿n", "Favorecer la comunicaci¿n en el grupo", "Fomentar la comunicaci¿n e interpretaci¿n", "Trabajo en equipo"], "materiales": ["Linterna", "L¿piz", "Papel"], "variaciones": "Puede existir un puntaje inicial de ambos equipo, digamos 100 puntos. Si quieren que el mensaje se repita por la linterna, se bajar¿ 5 puntos por realizar tal petici¿n, entonces el equipo ganador ser¿ el que conserve la mayor cantidad de puntos.", "recomendaciones": "Procure tener el espacio adecuado para la transmisi¿n de se¿ales", "justificacion_areas": "Promueve el ingenio pr¿ctico, la agilidad mental y la resoluci¿n de problemas t¿cnicos o enigmas. Ayuda a consolidar los valores scouts de honestidad, lealtad y fair play en la competencia. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_senalesNocturnas.png", "objetivos_educativos": [{"id": "1d9d6751-4ab1-45db-9999-3f18606b4909", "area": "Car¿cter", "texto": "Soy fiel a la palabra dada.", "unidad": "Avanzada", "como_se_cumple": "Actuando consecuentemente con sus principios y valores individuales en cada decisi¿n y rol de Se¿ales nocturnas."}, {"id": "770a8ff3-7bb8-45dd-b114-5ae1069eff62", "area": "Car¿cter", "texto": "Act¿a consecuentemente con los valores que lo inspiran.", "unidad": "Clan", "