UPDATE public.articulos SET titulo = 'Escultores', contenido = '<p>Escultores es una dinámica enfocada en el <a href="https://nuamana.com/nuanew/objetivos-actividad/fomentar-un-entorno-de-confianza/" target="_blank" rel="noreferrer noopener">desarrollo de la confianza entre pares</a>, al mismo tiempo que busca estimular y desarrollar la creatividad de las y los participantes, pero que también puede tener un enfoque en el <a href="https://www.educ.ar/recursos/157438/cuidamos-nuestro-cuerpo" target="_blank" rel="noreferrer noopener">cuidado y respeto del cuerpo</a>.</p>



<p>Las y los escultores se encontraran ante indicaciones que deberán resolver con su propia creatividad, mientras que las parejas tendrán que confiar en el criterio de sus pares. Idealmente puede hacer un énfasis en la importancia de la empatía.</p>



<h3 class="wp-block-heading">¿Cómo se hace Escultores?</h3>



<p>Primero se dividirá a los y las participantes en parejas, se recomienda que en este paso inicialmente las parejas sean elegidas libremente por un tema de confianzas entre las parejas, aunque se puede hacer una segunda fase de forma más aleatoria de ser necesaria.</p>



<p>El juego consiste en que, una o uno de los participantes, será la escultura, y otro el escultor, se les indica una consigna, que puede ser "Un ninja", "Un superhéroe", un "animal", etc. y el escultor moldea a la escultura para adoptar la pose que él o ella cree que mejor se adapta a lo indicado, lo ideal sería que existan distintas parejas para comparar y elegir el ganador que mejor se adapte a la consigna dada.</p>', extracto = 'Escultores es una dinámica enfocada en el  desarrollo de la confianza entre pares , al mismo tiempo que busca estimular y desarrollar la creatividad de las y l...', metadata = '{"areas": ["corporalidad", "creatividad", "sociabilidad"], "lugares": ["Exterior", "Interior"], "cantidad": "04 participantes", "duracion": "20 minutos", "unidades": ["avanzada", "compa¿¿a", "manada", "tropa"], "objetivos": ["Conocer las capacidades corporales", "Crear un ambiente de distensi¿n", "Estimular la confianza", "Estimular la creatividad", "Fomentar un entorno de confianza"], "materiales": ["Sin Materiales"], "variaciones": "Tambi¿n se puede realizar con el escultor con los ojos vendados, para agregar dificultad.", "recomendaciones": "Procure dar indicaciones sobre el cuidado y el respeto del cuerpo de los dem¿s.", "justificacion_areas": "Fomenta la coordinaci¿n f¿sica y la resistencia cardiovascular mediante desaf¿os corporales din¿micos. Promueve el ingenio pr¿ctico, la agilidad mental y la resoluci¿n de problemas t¿cnicos o enigmas. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_escultores.png", "objetivos_educativos": [{"id": "05f42879-f5f5-40c4-bed6-c577bf61340a", "area": "Corporalidad", "texto": "Cuido mi salud y mantengo h¿bitos que la protegen.", "unidad": "Avanzada", "como_se_cumple": "Aceptando sus capacidades f¿sicas y perfeccionando el control psicomotor durante el desarrollo de Escultores."}, {"id": "705b686a-8374-467a-b871-f6470f0d58ae", "area": "Corporalidad", "texto": "Me doy cuenta de los cambios que se est¿n produciendo en mi cuerpo.", "unidad": "Compa¿¿a", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de Escultores."}, {"id": "57887da4-c70e-45bc-bdfb-f79db513a89c", "area": "Corporalidad", "texto": "S¿ qué hacer frente a una enfermedad o accidente.", "unidad": "Compa¿¿a", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de Escultores."}, {"id": "36d989b6-30dd-434a-874a-70a993ed0bec", "area": "Corporalidad", "texto": "Conozco las principales enfermedades que me pueden dar y por qué.", "unidad": "Manada", "como_se_cumple": "Ejercitando la precisi¿n visomotora y el control de su cuerpo en los desaf¿os corporales de Escultores."}, {"id": "6467298d-fe2b-4920-9b9a-e3524e4b2aef", "area": "Corporalidad", "texto": "S¿ en qué lugar de mi cuerpo est¿n ubicados los ¿rganos m¿s importantes.", "unidad": "Manada", "como_se_cumple": "Ejercitando la precisi¿n visomotora y el control de su cuerpo en los desaf¿os corporales de Escultores."}, {"id": "8cae916f-5e67-4697-b3cd-c59b5c7d1439", "area": "Corporalidad", "texto": "Trato de evitar situaciones que puedan da¿ar mi salud y la de mis compa¿eros.", "unidad": "Tropa", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de Escultores."}, {"id": "68add558-4b03-4105-b00d-e7f2ead6ac23", "area": "Corporalidad", "texto": "S¿ qué hacer frente a una enfermedad o accidente.", "unidad": "Tropa", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de Escultores."}, {"id": "843fda9c-6c4a-4516-b30c-23c92ef755a8", "area": "Creatividad", "texto": "Puedo resolver la mayor¿a de los problemas t¿cnicos dom¿sticos simples.", "unidad": "Avanzada", "como_se_cumple": "Combinando conocimientos pr¿cticos e inventiva t¿cnica para resolver los retos de pionerismo y dise¿o en Escultores."}, {"id": "103661fc-3396-4eac-9182-58b7e54d5115", "area": "Creatividad", "texto": "Perfecciono mis habilidades manuales.", "unidad": "Compa¿¿a", "como_se_cumple": "Aplicando ingenio pr¿ctico y destrezas manuales para optimizar los recursos construidos en Escultores."}, {"id": "0f60be94-6de3-4c34-a6ff-5b5018f0b156", "area": "Creatividad", "texto": "Coopero en la mantenci¿n y renovaci¿n del local y materiales de mi patrulla.", "unidad": "Compa¿¿a", "como_se_cumple": "Aplicando ingenio pr¿ctico y destrezas manuales para optimizar los recursos construidos en Escultores."}, {"id": "8985ff05-ee84-4fba-af46-146c5374df89", "area": "Creatividad", "texto": "Participo en los talleres de manualidades que se hacen en la Manada.", "unidad": "Manada", "como_se_cumple": "Manipulando de forma segura y creativa los materiales de la actividad para modelar o construir en Escultores."}, {"id": "d4232b99-5655-49c6-9d24-099cfe9c8180", "area": "Creatividad", "texto": "Practico continuamente mis habilidades manuales.", "unidad": "Manada", "como_se_cumple": "Manipulando de forma segura y creativa los materiales de la actividad para modelar o construir en Escultores."}, {"id": "11320fb6-98de-4725-825d-db858e3bffa2", "area": "Creatividad", "texto": "Perfecciono mis habilidades manuales.", "unidad": "Tropa", "como_se_cumple": "Aplicando ingenio pr¿ctico y destrezas manuales para optimizar los recursos construidos en Escultores."}, {"id": "fd3d3e14-e92b-4ab5-8298-9018c6e70b20", "area": "Creatividad", "texto": "Coopero en la mantenci¿n y renovaci¿n del local y materiales de mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Aplicando ingenio pr¿ctico y destrezas manuales para optimizar los recursos construidos en Escultores."}, {"id": "f1496221-0da5-4775-b3ba-29e65603cfee", "area": "Sociabilidad", "texto": "Acepto las normas de los diferentes ambientes en que act¿o, sin renunciar a mi de