UPDATE public.articulos SET titulo = 'El Trineo del Viejito Pascuero', contenido = '<p>El Trineo del Viejito Pascuero es una carrera de Trineos ficticia como actividades de navidad y <a href="https://nuamana.com/nuanew/actividades/juegos/">juegos</a> para niñas, niños y/o jóvenes.</p>



<p>Esta actividad solamente se puede hacer en un lugar que tenga el suelo deslizante.</p>



<p>Además también se necesita un trozo de tela o felpudo (trocito de alfombra) por equipo para ayudar al deslizamiento.</p>



<h3 class="wp-block-heading">¿Como se Juega el Trineo del Viejito Pascuero?</h3>



<figure class="wp-block-image aligncenter"><img src="https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_ElTrineodelViejitoPascuero_1.jpg" alt="El Trineo del Viejito Pascuero graficado" class="wp-image-1392"/></figure>



<p></p>



<p>Es una <a href="https://juegosdetiempolibre.org/juegos/00744-carros/" target="_blank" rel="noopener">carrera de trineos</a>, en este caso cada trineo es el pedazo de tela donde se sentara el Jinete o Viejito Pascuero (Santa, Papa Noel, etc).</p>



<p>El grupo se distribuye por equipos de un peso o constitución similar. O en su defecto el Jinete debe ser el más liviano del equipo. Se establece un punto de partida y una meta para la carrera.</p>



<p>Los equipos deben tener un "viejo pascuero" (Jinete) y varios "renos" que tiran del trineo.</p>



<p>Para que los renos puedan tirar del trineo necesitan tener riendas las que se construirán amarrando sus pañolines como un gran lazo y cada extremo de este lazo será sostenido por el "viejo pascuero".</p>



<p>A la señal comienza la carrera y gana el equipo que primero cruce la meta.</p>', extracto = 'El Trineo del Viejito Pascuero es una carrera de Trineos ficticia como actividades de navidad y  juegos  para niñas, niños y/o jóvenes. 



 Esta actividad sol...', metadata = '{"areas": ["corporalidad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "06 participantes", "duracion": "20 minutos", "unidades": ["manada", "compa¿¿a", "tropa", "avanzada"], "objetivos": ["Refuerzo de habilidades f¿sicas", "Trabajo en equipo"], "materiales": ["Pa¿olin", "Tela"], "variaciones": "La carrera puede ser efectuada en parejas y haciendo relevos, de manera que cuando una pareja llega a un tramo, hay otra pareja esperando en ese punto para iniciar otro tramo y as¿ sucesivamente hasta llegar a la meta.", "recomendaciones": "Ponga especial ¿nfasis en que los jinetes deben ser llevados sobre la tela y en caso de que la fuerza de los \"Renos\" de su equipo haga que se levante sobre sus pies deben detenerse y esperar a que tome asiento el jinete y luego continuar desde el punto donde el jinete fue levantado.", "justificacion_areas": "Fomenta la coordinaci¿n f¿sica y la resistencia cardiovascular mediante desaf¿os corporales din¿micos. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_ElTrineodelViejitoPascuero.png", "objetivos_educativos": [{"id": "36d989b6-30dd-434a-874a-70a993ed0bec", "area": "Corporalidad", "texto": "Conozco las principales enfermedades que me pueden dar y por qué.", "unidad": "Manada", "como_se_cumple": "Ejercitando la precisi¿n visomotora y el control de su cuerpo en los desaf¿os corporales de El Trineo del Viejito Pascuero."}, {"id": "6467298d-fe2b-4920-9b9a-e3524e4b2aef", "area": "Corporalidad", "texto": "S¿ en qué lugar de mi cuerpo est¿n ubicados los ¿rganos m¿s importantes.", "unidad": "Manada", "como_se_cumple": "Ejercitando la precisi¿n visomotora y el control de su cuerpo en los desaf¿os corporales de El Trineo del Viejito Pascuero."}, {"id": "705b686a-8374-467a-b871-f6470f0d58ae", "area": "Corporalidad", "text