UPDATE public.articulos SET titulo = 'Carrera de porotos', contenido = '<p>La carrera de porotos es una actividad destinada a promover el uso de la creatividad, por lo que es importante hacer el enfasís y permitir el uso de la imaginación de los participantes.</p>



<h3 class="wp-block-heading">Carrera de Porotos</h3>



<p>El <a href="https://nuamana.com/nuanew/actividades/juegos/">juego</a> consiste, como su nombre lo dice en una <a href="http://juegoscout.blogspot.com/" target="_blank" rel="noreferrer noopener">carrera</a>, donde se hace que corran porotos u otro elemento pequeño empujados por los participantes con un pequeño palito. A falta de porotos se pueden usar piedras chicas. Se puede variar según el terreno, hacerlo individual o por equipos...</p>', extracto = 'La carrera de porotos es una actividad destinada a promover el uso de la creatividad, por lo que es importante hacer el enfasís y permitir el uso de la imagina...', metadata = '{"areas": ["corporalidad", "creatividad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "individual", "duracion": "15 minutos", "unidades": ["manada"], "objetivos": ["Aumentar el conocimiento de las limitantes f¿sicas", "Estimular la creatividad"], "materiales": ["Palo", "Porotos"], "variaciones": "Se puede variar seg¿n el terreno, hacerlo individual o por equipos.", "recomendaciones": "Permita a los participantes utilizar la imaginaci¿n en el desplazamiento del poroto.", "justificacion_areas": "Fomenta la coordinaci¿n f¿sica y la resistencia cardiovascular mediante desaf¿os corporales din¿micos. Promueve el ingenio pr¿ctico, la agilidad mental y la resoluci¿n de problemas t¿cnicos o enigmas. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_CarreraDePorotos.png", "objetivos_educativos": [{"id": "36d989b6-30dd-434a-874a-70a993ed0bec", "area": "Corporalidad", "texto": "Conozco las principales enfermedades que me pueden dar y por qué.", "unidad": "Manada", "como_se_cumple": "Ejercitando la precisi¿n visomotora y el control de su cuerpo en los desaf¿os corporales de Carrera de porotos."}, {"id": "6467298d-fe2b-4920-9b9a-e3524e4b2aef", "area": "Corporalidad", "texto": "S¿ en qué lugar de mi cuerpo est¿n ubicados los ¿rganos m¿s importantes.", "unidad": "Manada", "como_se_cumple": "Ejercitando la precisi¿n visomotora y el control de su cuerpo en los desaf¿os corporales de Carrera de porotos."}, {"id": "ec280dd0-2d80-4b84-86ad-2d362da14886", "area": "Creatividad", "texto": "Me gusta participar en juegos de observaci¿n.", "unidad": "Manada", "como_se_cumple": "Proponiendo ideas originales y r¿pidas para resolver los acertijos o enigmas mentales de Carrera de porotos."}, {"id": "418f2b77-f15b-405a-95bd-8033c0b6a4c2", "area": "Creatividad", "texto": "Puedo contar con detalles las an¿cdotas y aventuras que hemos tenido en la Manada.", "unidad": "Manada", "como_se_cumple": "Proponiendo ideas originales y r¿pidas para resolver los acertijos o enigmas mentales de Carrera de porotos."}, {"id": "b69188bf-2391-43c1-a885-abd1b13912be", "area": "Sociabilidad", "texto": "Acepto las reglas que se ponen en mi casa, en la escuela y en la Manada.", "unidad": "Manada", "como_se_cumple": "Respetando rigurosamente las reglas del juego de relevos y las instrucciones de seguridad en Carrera de porotos."}, {"id": "2394dd5b-87b9-4f3d-9cdd-a42649139782", "area": "Sociabilidad", "texto": "Comprendo y respeto las normas que se han puesto en mi casa y en la escuela, aunque no siempre est¿ de acuerdo con ellas", "unidad": "Manada", "como_se_cumple": "Respetando rigurosamente las reglas del juego de relevos y las instrucciones de seguridad en Carrera de porotos."}]}'::jsonb WHERE id = '73044568-1f54-4fa8-a79d-fe47fcd839a1';

UPDATE public.articulos SET titulo = 'Carrera de camillas', contenido = '<p>La carrera de camillas consiste en una competencia de traslado de pacientes, para ello se organizarán dos o más <a href="https://nuamana.com/nuanew/etiqueta/en-equipo/" target="_blank" rel="noreferrer noopener">equipos</a>, antes de inciar la misma carrera se les debe explicar algunos de los elementos más importantes a considerar para trasladar un paciente, por ejemplo:</p>



<h3 class="wp-block-heading">Consideraciones</h3>



<ul class="wp-block-list">
<li>Se debe considerar la inmovilización que debe tener la persona que será trasladada.</li>



<li>Se debe considerar que la persona trasladada debe saltar o moverse lo menos posible en el traslado.</li>



<li>Se debe considerar el terreno por el que será trasladado, la pendiente y lo accidentado que sea.</li>
</ul>



<p>Adicionalmente, se debe explicar de forma breve algunos ejemplos de <a href="https://www.tafadycursos.com/load/socorrismo/temario/traslado_accidentados_camilla/145-1-0-857" target="_blank" rel="noreferrer noopener">camillas improvisadas</a>, deben tener en consideración en primera instancia los materiales que tienen disponibles para poder construir la camilla. En caso de no tener materiales los scouts siempre pueden contar con su pañolin y sus manos.</p>



<h3 class="wp-block-heading">Tipos de Camillas</h3>



<p>Un tipo de camilla para esta carrera de camillas puede ser entre dos personas entrelazando los brazos.</p>



<p>Para hacer esta camilla, la mano derecha debe tomar la muñeca izquierda de su compañero enfrente de el o ella, y la mano izquierda tomar la muñeca derecha propia. Este puede ser un buen soporte cuando se cuenta con pocas personas, el paciente entonces se sentara sobre las manos, como el ejemplo a continuación...</p>



<figure class="wp-block-image aligncenter is-resized"><img src="https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_CarreraDeCamillas1.png" alt="Carrera de Camillas ejemplo gráfico de camilla improvisada con las manos" class="wp-image-4375" style="object-fit:cover;width:360px;height:360px"/></figure>



<p>Otro tipo de camilla cuando se cuenta con más personas, al menos 6, es pasar los pañolines, estando enrollados por debajo del paciente, tomando cada persona dos puntas de un pañolin, en este tipo de camilla se debe considerar que el mayor peso se encontrara a la altura de la cintura del paciente, y que se debe dar adecuado soporte a la cabeza y hombros del paciente.</p>



<h3 class="wp-block-heading">Carrera de Camillas</h3>



<p>Teniendo estos factores en consideración, se iniciara la carrera de camillas y se colocarán las camillas en una línea, donde a la señal deben cruzar desde el punto A al punto B, en este caso, la carrera de camillas no la ganara necesariamente la camilla que primero cruce la línea de meta, sino la que consiga llevar de la mejor manera al paciente.</p>', extracto = 'La carrera de camillas consiste en una competencia de traslado de pacientes, para ello se organizarán dos o más  equipos , antes de inciar la misma carrera se...', metadata = '{"areas": ["corporalidad", "creatividad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "12 participantes", "duracion": "20 minutos", "unidades": ["compa¿¿a", "tropa", "avanzada"], "objetivos": ["Aprender elementos B¿sicos de Primeros Auxilios", "Aprendizaje por la acci¿n", "Trabajo en equipo"], "materiales": ["Pa¿olin"], "variaciones": "En lugar de utilizar una persona como \"paciente\" en el traslado puede utilizar otro elemento que requiera mantener cierto equilibrio para que no se caiga.", "recomendaciones": "Procure hacer ¿nfasis en que la actividad no es sobre llegar primero a la meta, sino sobre que \"paciente\" llega en mejor condici¿n a la meta.\r\n\r\nMuestre el estado y condici¿n del terreno para hacer ¿nfasis de la misma manera en la importancia de la seguridad en la actividad.", "justificacion_areas": "Fomenta la coordinaci¿n f¿sica y la resistencia cardiovascular mediante desaf¿os corporales din¿micos. Promueve el ingenio pr¿ctico, la agilidad mental y la resoluci¿n de problemas t¿cnicos o enigmas.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_CarreraDeCamillas.png", "objetivos_educativos": [{"id": "705b686a-8374-467a-b871-f6470f0d58ae", "area": "Corporalidad", "texto": "Me doy cuenta de los cambios que se est¿n produciendo en mi cuerpo.", "unidad": "Compa¿¿a", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de Carrera de camillas."}, {"id": "57887da4-c70e-45bc-bdfb-f79db513a89c", "area": "Corporalidad", "texto": "S¿ qué hacer frente a una enfermedad o accidente.", "unidad": "Compa¿¿a", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de Carrera de camillas."}, {"id": "8cae916f-5e67-4697-b3cd-c59b5c7d1439", "area": "Corporalidad", "texto": "Trato de evitar situaciones que puedan da¿ar mi salud y la de mis compa¿eros.", "unidad": "Tropa", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de Carrera de camillas."}, {"id": "68add558-4b03-4105-b00d-e7f2ead6ac23", "area": "Corporalidad", "texto": "S¿ qué hacer frente a una enfermedad o accidente.", "unidad": "Tropa", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiraci¿n ante la tensi¿n visomotora de Carrera de camillas."}, {"id": "05f42879-f5f5-40c4-bed6-c577bf61340a", "area": "Corporalidad", "texto": "Cuido mi salud y mantengo h¿bitos que la protegen.", "unidad": "Avanzada", "como_se_cumple": "Aceptando sus capacidades f¿sicas y perfeccionando el control psicomotor durante el desarrollo de Carrera de camillas."}, {"id": "e1b7276f-4fd2-4c39-a32a-bd7fadbee702", "area": "Creatividad", "texto": "Doy mi opini¿n sobre las cosas que me pasan.", "unidad": "Compa¿¿a", "como_se_cumple": "Analizando el escenario t¿ctico del juego de forma ¿gil para proponer alternativas mentales en Carrera de camillas."}, {"id": "9f30f035-9179-4ac4-acfb-bea0e169e97a", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Compa¿¿a", "como_se_cumple": "Analizando el escenario t¿ctico del juego de forma ¿gil para proponer alternativas mentales en Carrera de camillas."}, {"id": "49ae6ac6-be8f-4f2c-8b3e-6711d041181f", "area": "Creatividad", "texto": "Doy mi opini¿n sobre las cosas que me pasan.", "unidad": "Tropa", "como_se_cumple": "Analizando el escenario t¿ctico del juego de forma ¿gil para proponer alternativas mentales en Carrera de camillas."}, {"id": "cf530cf9-73a6-4423-a075-79be433fe96c", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Analizando el escenario t¿ctico del juego de forma ¿gil para proponer alternativas mentales en Carrera de camillas."}, {"id": "3cdf4b56-b55f-4878-b3fa-da32a7200ca4", "area": "Creatividad", "texto": "Soy capaz de sintetizar, criticar, proponer y apreciar las opiniones de los dem¿s.", "unidad": "Avanzada", "como_se_cumple": "Demostrando agilidad mental y pensamiento cr¿tico inmediato para liderar la resoluci¿n estrat¿gica de Carrera de camillas."}]}'::jsonb WHERE id = 'fa3fe65c-fb44-46a6-9a27-6ea8bf72e246';

UPDATE public.articulos SET titulo = 'Relevos Ciegos', contenido = '<p>Los <a href="http://juegoscout.blogspot.cl/" target="_blank" rel="noreferrer noopener">Relevos Ciegos</a> es un <a href="https://nuamana.com/nuanew/actividades/juegos/" target="_blank" rel="noreferrer noopener">juego</a> que busca reforzar el <a href="https://nuamana.com/nuanew/objetivos-actividad/trabajo-en-equipo/" target="_blank" rel="noreferrer noopener">trabajo en equipo</a> y reconocer las limitaciones físicas propias, se realizará en grupos de al menos 6 participantes, donde mediante la voz deberán encontrar el lugar de intercambio.</p>







<h3 class="wp-block-heading">¿Cómo realizar los Relevos Ciegos?</h3>







<p>Se necesitan al menos dos equipos, en un campo delimitado a una distancia razonable para que se puedan escuchar las instrucciones de sus compañeras y/o compañeros de equipo.</p>







<p>Los equipos estarán divididos en dos grupos cada uno, y se pondrán enfrente uno de otro en los dos extremos de un campo.</p>







<p>A la señal salen los o las corredores de un lado, que llevarán los ojos vendados e irán al otro extremo del campo dirigidos por los gritos de sus compañeras y/o compañeros.</p>







<figure class="wp-block-image aligncenter is-resized"><img src="https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_RelevosCiegos_2.png" alt="Gr¿fico sobre los relevos ciegos" class="wp-image-4700" style="width:360px"/></figure>







<p>Al llegar, entregarán el testigo a otro compañero o compañera que también estará con los ojos vendados y que ha de recorrer el camino de vuelta al punto de origen, y así sucesivamente hasta que hayan corrido todos los del grupo.</p>







<p>Ganará el primer equipo en completar con todos sus participantes el campo de juego vendados completando los <a href="http://juegoscout.blogspot.cl/" target="_blank" rel="noreferrer noopener">relevos ciegos</a>, en caso de ser números impares los equipos con menos jugadores pueden hacer que alguno se repita.</p>







', extracto = 'Los  Relevos Ciegos  es un  juego  que busca reforzar el  trabajo en equipo  y reconocer las limitaciones físicas propias, se realizará en grupos de al menos 6...', metadata = '{"areas": ["corporalidad", "creatividad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "06 participantes", "duracion": "15 minutos", "unidades": ["manada", "compa¿¿a", "tropa", "avanzada"], "objetivos": ["Aprender a seguir instrucciones", "Aumentar el conocimiento de las limitantes físicas", "Trabajo en equipo"], "materiales": ["Pa¿olin"], "variaciones": "Una variaci¿n es que en lugar de gritar desde el otro lado del campo las instrucciones puede ir una compañera o compañero de equipo al lado del participante que est¿ vendada o vendado para darle las indicaciones.", "recomendaciones": "<ul>\r\n \t<li>Ponga ¿nfasis en el cuidado de la jugadora o jugador cuando le den instrucciones para evitar accidentes.</li>\r\n \t<li>Procure que el terreno sea un terreno parejo para evitar que las y los participantes tropiecen y se caigan.</li>\r\n \t<li>Indique que no es necesario correr y que se debe primero saber que se esta dando un paso seguro.</li>\r\n</ul>", "justificacion_areas": "Fomenta la coordinaci¿n f¿sica y la resistencia cardiovascular mediante desaf¿os corporales din¿micos. Promueve el ingenio pr¿ctico, la agilidad mental y la resoluci¿n de problemas t¿cnicos o enigmas. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_RelevosCiegos.png", "objetivos_educativos": [{"id": "36d989b6-30dd-434a-874a-70a993ed0bec", "area": "Corporalidad", "texto": "Conozco las principales enfermedades que me pueden dar y por qué.", "unidad": "Manada", "como_se_cumple": "Ejercitando la precisi¿n visomotora y el control de su cuerpo en los desaf¿os corporales de Relevos Ciegos."}, {"id": "6467298d-fe2b-4920-9b9a-e352