UPDATE public.articulos SET titulo = 'Carrera de ciempiés', contenido = '<p>La carrera de ciempiés es una actividad para el <a href="https://nuamana.com/nuanew/objetivos-actividad/desarrollar-la-motricidad/" target="_blank" rel="noreferrer noopener">desarrollo de la motricidad</a>, el <a href="https://nuamana.com/nuanew/objetivos-actividad/desfogue-de-energias/" target="_blank" rel="noreferrer noopener">desfogue de energías</a> y el <a href="https://nuamana.com/nuanew/objetivos-actividad/trabajo-en-equipo/" target="_blank" rel="noreferrer noopener">trabajo en equipo</a>, se desarrolla en filas o hileras, estas simularán ser cienpies unidos con las manos y los tobillos.</p>







<h3 class="wp-block-heading">¿Cómo se juega la Carrera de ciempiés?</h3>







<p>Se divide el grupo en equipos y se ubican en filas detrás de la línea de partida.</p>







<p>Cada equipo debe ubicarse de la siguiente manera: en hileras el primero de coloca sus manos sobre sus rodillas, y los que se ubican detrás tomarán con las manos los tobillos de la persona que tienen delante, mientras que la cabeza irá entre las piernas.</p>







<p>Ubicados en esta posición a la señal comienza la <a href="http://juegoscout.blogspot.cl/" target="_blank" rel="noreferrer noopener">carrera de ciempiés</a> y ganará el primer equipo que cruce la línea de meta por completo.</p>







', extracto = 'La carrera de ciempiés es una actividad para el  desarrollo de la motricidad , el  desfogue de energías  y el  trabajo en equipo , se desarrolla en filas o hil...', metadata = '{"areas": ["corporalidad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "06 participantes", "duracion": "15 minutos", "unidades": ["compa¿¿a", "manada", "tropa"], "objetivos": ["Desarrollar la motricidad", "Desfogue de Energ¿as", "Trabajo en equipo"], "materiales": ["Sin Materiales"], "variaciones": "Una variaci¿n de la actividad puede ser tomando las rodillas del que se encuentra delante, en lugar de los tobillos.", "recomendaciones": "Procure poner ¿nfasis en la seguridad del equipo, que tengan cuidado con sus manos a la hora de avanzar, si visualiza que uno o todos los equipos tienen inconvenientes para avanzar haga recomendaciones para que avancen coordinadamente.", "justificacion_areas": "Fomenta la coordinaci¿n f¿sica y la resistencia cardiovascular mediante desaf¿os corporales din¿micos. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_CarreraDeCiempies.png", "objetivos_educativos": [{"id": "d5b111f1-5f6f-4716-8a02-e1826d653c59", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Compa¿¿a", "como_se_cumple": "Corriendo velozmente y dosificando su energ¿a y esfuerzo aer¿bico para superar las fases f¿sicas de Carrera de ciempiés."}, {"id": "b12da732-d736-480c-82b8-95b312316390", "area": "Corporalidad", "texto": "Me esfuerzo por mejorar mi rendimiento en el deporte que practico y s¿ ganar y perder.", "unidad": "Compa¿¿a", "como_se_cumple": "Corriendo velozmente y dosificando su energ¿a y esfuerzo aer¿bico para superar las fases f¿sicas de Carrera de ciempiés."}, {"id": "4bf1e3dd-7f21-4c24-962d-9d6d64e32f25", "area":