</div>



<div class="wp-block-boldblocks-carousel-item wp-block-boldblocks-custom is-carousel-item has-parent carousel-item">
<figure class="wp-block-image size-large"><img src="https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/cabuyeria_NudoEstacha_paso2.png" alt=""/></figure>



<p class="has-text-align-center has-large-font-size"><strong>Nudo de Estacha Paso 2</strong></p>
</div>



<div class="wp-block-boldblocks-carousel-item wp-block-boldblocks-custom is-carousel-item has-parent carousel-item">
<figure class="wp-block-image size-large"><img src="https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/cabuyeria_NudoEstacha_paso3.png" alt=""/></figure>



<p class="has-text-align-center has-large-font-size"><strong>Nudo de Estacha Paso 3</strong></p>
</div>
