UPDATE public.articulos SET titulo = 'Asalto a la Fortaleza', contenido = '<p>Asalto a la Fortaleza es una actividad que busca promover el <a href="https://es.wikipedia.org/wiki/Trabajo_en_equipo" target="_blank" data-type="link" data-id="https://es.wikipedia.org/wiki/Trabajo_en_equipo" rel="noreferrer noopener">trabajo en equipo</a>, el desarrollo de estrategias y la creatividad, así mismo puede ayudar a estimular el liderazgo.</p>



<h3 class="wp-block-heading">¿Cómo se hace el Asalto a la Fortaleza?</h3>



<p>Primero haz que cada pañolin se convierta en una pelota pequeña de genero, para hacer esto de forma rápida te recomiendo que con el pañolin armado simplemente hagas <a href="https://nuamana.cl/tecnicas/cabuyeria/nudos/nudo-simple/" data-type="post" data-id="154">nudos simples</a> sobre <a href="https://nuamana.cl/tecnicas/cabuyeria/nudos/nudo-simple/" data-type="post" data-id="154">nudos simples</a>, es decir, haz un nudo simple en la parte que se posa en tu cuello, luego lo giras en 180° y haz otro nudo simple que apriete el anterior, así sucesivamente hasta que ya no quede ninguna punta.</p>



<p>Luego de esto divide los equipos, en dos grupos, un grupo defiende y otro grupo ataca, a ambos grupos dales 3 minutos para que organicen una estrategia, el que defiende puede, por ejemplo, hacer una pequeña fortaleza para resistir mejor, o puedes decirles a todos que armen primero la fortaleza que ambos van a tener que defender.</p>



<p>El juego consiste en que el equipo que ataca debe tomar por asalto a la fortaleza ingresando sus miembros dentro de la fortaleza, mientras que el equipo que defiende debe evitar que ingresen o tomen por asalto a la fortaleza. Cada pelota es una bala, obviamente todas las balas se pueden reutilizar, si te llega una bala quedas fuera.</p>



<p>Gana el equipo que "mata" a todos los jugadores del equipo contrario o si el equipo asaltante ingresa a la fortaleza sin ser herido, o si el equipo defensor sobrevive un tiempo establecido. Básicamente es agarrarse a pelotazos con un fin, o simular una batalla de forma simple.</p>', extracto = 'Asalto a la Fortaleza es una actividad que busca promover el  trabajo en equipo , el desarrollo de estrategias y la creatividad, así mismo puede ayudar a estim...', metadata = '{"areas": ["creatividad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior", "Interior"], "cantidad": "04 participantes", "duracion": "30 minutos", "unidades": ["avanzada", "compa¿¿a", "tropa"], "objetivos": ["Estimular el liderazgo", "Estimular la creatividad", "Promover la elaboraci¿n de estrategias", "Trabajo en equipo"], "materiales": ["Pa¿olin"], "variaciones": "Puede dejar al Gu¿a de Patrulla a cargo 100% de la estrategia y dar instrucciones a las y/o los participantes de su patrulla como si fuera un capit¿n en una batalla.", "recomendaciones": "Elija un terreno donde sea dif¿cil que se pierdan las pelotas, idealmente plano o con muchos lugares donde se puedan perder las pelotas como con hiervas altas o similares.", "justificacion_areas": "Promueve el ingenio pr¿ctico, la agilidad mental y la resoluci¿n de problemas t¿cnicos o enigmas. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_AsaltoALaFortaleza.png", "objetivos_educativos": [{"id": "3cdf4b56-b55f-4878-b3fa-da32a7200ca4", "area": "Creatividad", "texto": "Soy capaz de sintetizar, criticar, proponer y apreciar las opiniones de los dem¿s.", "unidad": "Avanzada", "como_se_cumple": "Demostrando agilidad mental y pensamiento cr¿tico inmediato para liderar la resoluci¿n estrat¿gica de Asalto a la Fortaleza."}, {"id": "e1b7276f-4fd2-4c39-a32a-bd7fadbee702", "area": "Creatividad", "texto": "Doy mi opini¿n sobre las cosas que me pasan.", "unidad": "Compa¿¿a", "como_se_cumple": "Analizando el escenario t¿ctico del juego de forma ¿gil para proponer alternativas mentales en Asalto a la Fortaleza."}, {"id": "9f30f035-9179-4ac4-acfb-bea0e169e97a", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Compa¿¿a", "como_se_cumple": "Analizando el escenario t¿ctico del juego de forma ¿gil para proponer alternativas mentales en Asalto a la Fortaleza."}, {"id": "49ae6ac6-be8f-4f2c-8b3e-6711d041181f", "area": "Creatividad", "texto": "Doy mi opini¿n sobre las cosas que me pasan.", "unidad": "Tropa", "como_se_cumple": "Analizando el escenario t¿ctico del juego de forma ¿gil para proponer alternativas mentales en Asalto a la Fortaleza."}, {"id": "cf530cf9-73a6-4423-a075-79be433fe96c", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Analizando el escenario t¿ctico del juego de forma ¿gil para proponer alternativas mentales en Asalto a la Fortaleza."}, {"id": "f1496221-0da5-4775-b3ba-29e65603cfee", "area": "Sociabilidad", "texto": "Acepto las normas de los diferentes ambientes en que act¿o, sin renunciar a mi derecho de tratar de cambiarlas cuando no me parecen correctas.", "unidad": "Avanzada", "como_se_cumple": "Velando por la seguridad f¿sica y el cumplimiento estricto del reglamento de competencia en Asalto a la Fortaleza."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compa¿¿a", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante Asalto a la Fortaleza."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que act¿o, aunque no siempre est¿ de acuerdo con ellas.", "unidad": "Compa¿¿a", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante Asalto a la Fortaleza."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante Asalto a la Fortaleza."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que act¿o, aunque no siempre est¿ de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante Asalto a la Fortaleza."}]}'::jsonb WHERE id = '43be9855-17d1-4ac1-b344-8fa575676129';

UPDATE public.articulos SET titulo = 'Carrera de Liderazgo', contenido = '<p>La carrera de liderazgo es una actividad que permite ver a las y los participantes como lo visualizan otros con respecto a la impresión que tiene de si mismo, al mismo tiempo que permite saber cuales son las <a href="https://www.lhh.com/es-es/insights/20-cualidades-de-liderazgo-que-hacen-a-un-gran-lider" id="https://www.lhh.com/es-es/insights/20-cualidades-de-liderazgo-que-hacen-a-un-gran-lider">cualidades </a>que consideran positivas en un líder.</p><p>Este juego revela quién tiene el temple necesario para enfrentarse a los retos del <a href="https://nuamana.cl/objetivos-actividad/estimular-el-liderazgo/" id="253">liderazgo</a>.</p><h3>¿Cómo se hace la Carrera de Liderazgo?</h3><p><strong>En fila:</strong> Los jugadores se colocan hombro con hombro, listos para mostrar sus estilos en esta carrera de liderazgo y su potencial.</p><p><strong>Caracterización:</strong> Una persona no participante señala un rasgo de liderazgo correcto, como la innovación, la comunicación, la fiabilidad, la resistencia, la ética, la inteligencia emocional, la proactividad y la inspiración, basándose en los <a href="https://nuamana.cl/lo-que-hacemos/ley-y-promesa/" id="838">criterios de liderazgo de la organización</a>.</p><p><strong>Explicar y convencer:</strong> Los jugadores que creen que el rasgo se aplica a ellos dan un paso al frente y explican por qué piensan así<br><strong>Juzgar y repetir:</strong> Un jurado juzga las explicaciones y, si las considera válidas, el jugador permanece en la alineación; si no, da un paso atrás. El juego continúa con nuevos rasgos.</p><p><strong>El ganador:</strong> El jugador con más explicaciones válidas y que permanece en la alineación gana.</p><p>Este juego consiste en pensar con rapidez, comunicarse con claridad y demostrar tus habilidades y cualidades esenciales de liderazgo. Aunque no ganes, perfeccionarás tus habilidades, ¡y todos saldremos ganando!</p>', extracto = 'La carrera de liderazgo es una actividad que permite ver a las y los participantes como lo visualizan otros con respecto a la impresión que tiene de si mismo,...', metadata = '{"areas": ["car¿cter"], "lugares": ["Campo delimitado", "Exterior", "Interior", "Sala"], "cantidad": "02 participantes", "duracion": "15 minutos", "unidades": ["manada", "compa¿¿a", "tropa", "avanzada"], "objetivos": ["Conocer a los dem¿s", "Estimular el liderazgo"], "materiales": ["Sin Materiales"], "variaciones": "", "recomendaciones": "Al momento de evaluar la justificaci¿n eval¿e a cada participante en su justo merito y no permita que hayan agresiones emocionales hacia las y los participantes, idealmente base la evaluaci¿n en la calidad de la justificaci¿n y sea suave en como lo dice.", "justificacion_areas": "Ayuda a consolidar los valores scouts de honestidad, lealtad y fair play en la competencia.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_CarreraDeLiderazgo.png", "objetivos_educativos": [{"id": "baa365a9-087c-4c25-b0ad-57893df5ff74", "area": "Car¿cter", "texto": "S¿ lo que significa decir la verdad.", "unidad": "Manada", "como_se_cumple": "Jugando de manera transparente y honesta en Carrera de Liderazgo, aceptando con alegr¿a la victoria o la derrota."}, {"id": "506b7596-cac4-48e0-88c7-942d575172db", "area": "Car¿cter", "texto": "Digo la verdad, aunque a veces no me gusten las consecuencias.", "unidad": "Manada", "como_se_cumple": "Jugando de manera transparente y honesta en Carrera de Liderazgo, aceptando con alegr¿a la victoria o la derrota."}, {"id": "075c93b1-81d2-4370-8e47-f0a4d086b20e", "area": "Car¿cter", "texto": "S¿ lo que significa ser leal.", "unidad": "Compa¿¿a", "como_se_cumple": "Demostrando lealtad con sus compa¿eros y respeto por la palabra empe¿ada en el transcurso de Carrera de Liderazgo."}, {"id": "7a9e143e-c837-473b-a014-e41ef5fc2ec2", "area": "Car¿cter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Compa¿¿a", "como_se_cumple": "Demostrando lealtad con sus compa¿eros y respeto por la palabra empe¿ada en el transcurso de Carrera de Liderazgo."}, {"id": "38f4863e-12a6-4a4b-9767-8cdf55020734", "area": "Car¿cter", "texto": "S¿ lo que significa ser leal.", "unidad": "Tropa", "como_se_cumple": "Demostrando lealtad con sus compa¿eros y respeto por la palabra empe¿ada en el transcurso de Carrera de Liderazgo."}, {"id": "5311be36-87be-40c4-ab4a-e6ce6e662183", "area": "Car¿cter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Tropa", "como_se_cumple": "Demostrando lealtad con sus compa¿eros y respeto por la palabra empe¿ada en el transcurso de Carrera de Liderazgo."}, {"id": "1d9d6751-4ab1-45db-9999-3f18606b4909", "area": "Car¿cter", "texto": "Soy fiel a la palabra dada.", "unidad": "Avanzada", "como_se_cumple": "Actuando consecuentemente con sus principios y valores individuales en cada decisi¿n y rol de Carrera de Liderazgo."}]}'::jsonb WHERE id = '6615c3d3-f10f-4a21-96a4-ec618483a588';

UPDATE public.articulos SET titulo = 'El Lazarillo en Patrulla', contenido = '<p>El lazarillo en patrulla es una actividad que busca estimular la confianza en el liderazgo dentro del equipo, además de facilitar la comunicación en el equipo, es una variación de la actividad el lazarillo que se hace entre dos personas.</p>



<p>La actividad se trata de que el equipo se desplace desde un punto A a un punto B todos con los ojos cerrados salvo una persona, la o él líder del equipo deberá ser quien asuma el rol de <a href="https://www.rae.es/dhle/lazarillo#:~:text=fig.,otra%20necesitada%20de%20alguna%20ayuda." data-type="link" data-id="https://www.rae.es/dhle/lazarillo#:~:text=fig.,otra%20necesitada%20de%20alguna%20ayuda.">lazarillo </a>para ver cuanto confía su equipo en su liderazgo. Es una excelente actividad de diagnostico para <a href="https://es.wikipedia.org/wiki/Liderazgo" data-type="link" data-id="https://es.wikipedia.org/wiki/Liderazgo">liderazgos</a> de equipos.</p>



<h3 class="wp-block-heading">¿Cómo se hace El Lazarillo en Patrulla?</h3>



<p>El primer paso es indicarles a todos que es una actividad de confianza, todas y/o todos las y los integrantes de la <a href="https://nuamana.cl/lo-que-hacemos/sistema-de-equipos/" data-type="page" data-id="855">patrulla </a>se vendaran los ojos, con excepción del Guía que será el lazarillo en Patrulla, una vez que estén con los ojos cubiertos el dirigente le indicara la meta a la que debe llegar el guía de patrulla con su patrulla completa.</p>



<p>Hecho esto, el o la guía debe establecer una estrategia, este paso es clave para evaluar el liderazgo, ya que puede establecer o no una estrategia entre toda la patrulla, o simplemente decidirla sola o sólo, esto dirá mucho de su tipo de liderazgo en el equipo. Otro factor clave es como guía a la patrulla, ya que puede ir relatando todo el espacio o tomándoles de la mano, indicando los peligros o simplemente obviándolos.</p>



<p>A la señal la patrullas intentaran llegar al punto señalado como meta, gana la patrulla que llega con su patrulla completa al lugar y guiada por el lazarillo en patrulla, es importante destacar la calidad del traslado.</p>', extracto = 'El lazarillo en patrulla es una actividad que busca estimular la confianza en el liderazgo dentro del equipo, además de facilitar la comunicación en el equipo,...', metadata = '{"areas": ["afectividad", "car¿cter", "sociabilidad"], "lugares": ["Campo Abierto", "Exterior"], "cantidad": "04 participantes", "duracion": "15 minutos", "unidades": ["compa¿¿a", "tropa"], "objetivos": ["Crear un ambiente de distensi¿n", "Estimular el liderazgo", "Fomentar un entorno de confianza", "Trabajo en equipo"], "materiales": ["Pa¿olin"], "variaciones": "Existe una versi¿n en parejas, donde se turnan en el trayecto de ida y de vuelta, esta versi¿n esta m¿s enfocada en generar lazos o relaciones entre las y los participantes m¿s que en reforzar un liderazgo.", "recomendaciones": "Procure que el terreno no este muy accidentado para evitar ca¿das y observe meticulosamente el proceso para evaluar el liderazgo del gu¿a de patrulla.", "justificacion_areas": "Ayuda a consolidar los valores scouts de honestidad, lealtad y fair play en la competencia. Desarrolla el autoconocimiento, la confianza grupal y la empat¿a en las interacciones del juego. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_ElLazarilloEnPatrulla.png", "objetivos_educativos": [{"id": "818d8a25-549b-4e01-a830-e50d73e39025", "area": "Afectividad", "texto": "Me doy cuenta y puedo hablar de las cosas que me atemorizan.", "unidad": "Compa¿¿a", "como_se_cumple": "Canalizando emociones dif¿ciles de incertidumbre o temor al andar a ciegas en El Lazarillo en Patrulla."}, {"id": "67a2f0fa-9b1e-4b7b-bda2-e25696c87898", "area": "Afectividad", "texto": "Trato de dominar mis reacciones, a¿n en situaciones dif¿ciles o inesperadas.", "unidad": "Compa¿¿a", "como_se_cumple": "Canalizando emociones dif¿ciles de incertidumbre o temor al andar a ciegas en El Lazarillo en Patrulla."}, {"id": "03ccaf4c-03c4-42a8-b311-47fef60f204c", "area": "Afectividad", "texto": "Me doy cuenta y puedo hablar de las cosas que me atemorizan.", "unidad": "Tropa", "como_se_cumple": "Canalizando emociones dif¿ciles de incertidumbre o temor al andar a ciegas en El Lazarillo en Patrulla."}, {"id": "74e6c7e0-f9f6-47d3-acdb-d6df315ef123", "area": "Afectividad", "texto": "Trato de dominar mis reacciones, a¿n en situaciones dif¿ciles o inesperadas.", "unidad": "Tropa", "como_se_cumple": "Canalizando emociones dif¿ciles de incertidumbre o temor al andar a ciegas en El Lazarillo en Patrulla."}, {"id": "075c93b1-81d2-4370-8e47-f0a4d086b20e", "area": "Car¿cter", "texto": "S¿ lo que significa ser leal.", "unidad": "Compa¿¿a", "como_se_cumple": "Demostrando lealtad con sus compa¿eros y respeto por la palabra empe¿ada en el transcurso de El Lazarillo en Patrulla."}, {"id": "7a9e143e-c837-473b-a014-e41ef5fc2ec2", "area": "Car¿cter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Compa¿¿a", "como_se_cumple": "Demostrando lealtad con sus compa¿eros y respeto por la palabra empe¿ada en el transcurso de El Lazarillo en Patrulla."}, {"id": "38f4863e-12a6-4a4b-9767-8cdf55020734", "area": "Car¿cter", "texto": "S¿ lo que significa ser leal.", "unidad": "Tropa", "como_se_cumple": "Demostrando lealtad con sus compa¿eros y respeto por la palabra empe¿ada en el transcurso de El Lazarillo en Patrulla."}, {"id": "5311be36-87be-40c4-ab4a-e6ce6e662183", "area": "Car¿cter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Tropa", "como_se_cumple": "Demostrando lealtad con sus compa¿eros y respeto por la palabra empe¿ada en el transcurso de El Lazarillo en Patrulla."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compa¿¿a", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante El Lazarillo en Patrulla."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que act¿o, aunque no siempre est¿ de acuerdo con ellas.", "unidad": "Compa¿¿a", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante El Lazarillo en Patrulla."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante El Lazarillo en Patrulla."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que act¿o, aunque no siempre est¿ de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantenci¿n del orden colectivo durante El Lazarillo en Patrulla."}]}'::jsonb WHERE id = '785b5274-af71-4f1d-aa4b-385c0be761b2';

UPDATE public.articulos SET titulo = 'Tú Ley Scout', contenido = '<p>Tú Ley Scout es una actividad que permite reforzar el liderazgo, el trabajo en equipo y reforzar los valores del movimiento Scout, es esencialmente una conversación entre pares sobre la priorización de sus valores en un entorno Scout</p>



<p>Para esto necesitaremos que haya un ambiente de concentración por lo que es recomendable dejar esta actividad después de otras que tengan más movimiento físico y así puedan correctamente elegir Tú <a href="https://nuamana.cl/lo-que-hacemos/ley-y-promesa/" data-type="page" data-id="838">Ley Scout</a>.</p>



<h3 class="wp-block-heading">¿Cómo se hace Tú Ley Scout?</h3>



<p>Lo primero es entregar a las y los participantes los <a href="https://es.wikipedia.org/wiki/Ley_scout" target="_blank" data-type="link" data-id="https://es.wikipedia.org/wiki/Ley_scout" rel="noreferrer noopener">artículos de la ley scout</a> sin numeración, esto se puede hacer con un doble reforzamiento si se dispone de tiempo, en este caso daremos a los y las participantes papelógrafo y plumón o papel y lápiz y les diremos que anoten los artículos que más les gusten, o que menos cumplen o que más cumples, etc. y que los anoten en letra grande. Si elige esta opción, considere no dictar los artículos en el orden que aparecen en los documentos.</p>



<p>La otra opción es entregarles los artículos ya impresos y proceder con el siguiente paso.</p>



<p>Agrupe a las y los participantes en equipos más pequeños de su mismo equipo o con sus respectivas patrullas, e indíqueles que deben elegir los mejores 3 artículos de la ley, esa será "Tú Ley Scout", deles un tiempo prudente para deliberación y observe como actúan sus liderazgos sin intervenir, si le hacen una pregunta simplemente limítese a repetir la instrucción "Elija los mejores 3 artículos de la ley".</p>



<p>Una vez completado el tiempo permita que los equipos se organicen para presentar y justificar su elección.</p>', extracto = 'Tú Ley Scout es una actividad que permite reforzar el liderazgo, el trabajo en equipo y reforzar los valores del movimiento Scout, es esencialmente una convers...', metadata = '{"areas": ["car¿cter", "creatividad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior", "Interior", "Sala"], "cantidad": "02 participantes", "duracion": "20 minutos", "unidades": ["avanzada", "clan", "compa¿¿a", "tropa"], "objetivos": ["Aprendizaje por la acci¿n", "Estimular el liderazgo", "Estimular la participaci¿n", "Estimular la reflexi¿n", "Trabajo en equipo"], "materiales": "", "variaciones": "", "recomendaciones": "", "justificacion_areas": "Promueve el ingenio pr¿ctico, la agilidad mental y la resoluci¿n de problemas t¿cnicos o enigmas. Ayuda a consolidar los valores scouts de honestidad, lealtad y fair play en la competencia. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_TuLeyScout.png", "objetivos_educativos": [{"id": "51210a26-62f2-4e33-8ca4-09b4b364a143", "area": "Car¿cter", "texto": "Comprendo el significado de la Ley y la Promesa en esta etapa de mi vida.", "unidad": "Avanzada", "como_se_cumple": "Reflexionando de manera madura sobre cómo los valores fundamentales de la Ley Scout modelan su vida en T¿ Ley Scout."}, {"id": "0bdf2252-6db5-41f9-8bc7-87e4da3ee602", "area": "Car¿cter", "texto": "Construye su proyecto de vida en base a los valores de la Ley y la Promesa Gu¿a y Scout.", "unidad": "Clan", "como_se_cumple": "Reflexionando de manera madura sobre cómo los valores fundamentales de la Ley Scout modelan su vida en T¿ Ley Scout."}, {"id": "a8667e56-d5f7-4f7b-b666-06c0b0d0d430", "area": "Car¿cter", "texto": "Conozco y comprendo la Ley y la Promesa Gu¿a.", "unidad": "Compa¿¿a", "co